(40, 'string', 'Lower_content', NULL, NULL, NULL, '', NULL, '2022-09-30 09:02:21'),
(41, 'string', 'Lower_content', NULL, NULL, NULL, '<h4>Workplace Health and Safety</h4>\r\n<p>Gloucester Pre-School is strongly committed to maintaining a safe and healthy environment and thereby protecting all those involved in the Pre-School from any potentially adverse health and safety effects.<br /> In the interests of your safety and the safety of others, could you please abide by the following procedures when at Pre School.</p>\r\n<ul>\r\n<li>No smoking at or near the Pre-School.</li>\r\n<li>If a whistle blows evacuate the building to the large cubby.</li>\r\n<li>If you see anything that could pose a hazard or risk to others, notify a staff member immediately.</li>\r\n<li>Please stay out of all storerooms.</li>\r\n<li>Please act in a way that ensures your own safety and the safety of others.</li>\r\n</ul>\r\n<p>For more information about our WH&amp;S policy and procedures ask a staff member.</p>', NULL, '2022-08-22 10:05:48'),
