(51, 'string', 'design_id', NULL, NULL, NULL, '10', NULL, '2024-01-30 14:42:26'),
(51, 'string', 'searchable', NULL, NULL, NULL, '1', NULL, '2024-01-30 14:42:26'),
(51, 'string', 'content_en', NULL, NULL, NULL, '<h2>Mobile Supported Playgroup is organised and facilitated by staff from Gloucester Pre School.</h2>\r\n<h4>Playgroups are held fortnightly at Booral and Gloucester CWA Hall.</h4>\r\n<p>Trained and experienced staff from Gloucester Pre School organize fun play sessions in the local community halls.</p>\r\n<p>Parents and carers have the opportunity to meet and interact with other families while supervising and playing with their children.</p>', NULL, '2024-01-30 14:42:26'),
(51, 'string', 'extra1', NULL, NULL, NULL, '', NULL, '2024-01-30 14:42:26'),
