(58, 'string', 'Second_content', NULL, NULL, NULL, '<h3>Food</h3>\r\n<p><strong>Long Day Bookings: </strong>Children will be supplied with morning tea, lunch and afternoon tea cooked daily on the premises in our commercial kitchen.</p>\r\n<p><strong>Pre School Bookings: </strong>Children will be supplied with morning tea and lunch provided for a fee of $5 per session.</p>\r\n<p>&nbsp;</p>', NULL, '2022-08-19 11:55:57'),
