(59, 'string', 'design_id', NULL, NULL, NULL, '10', NULL, '2022-08-22 10:05:05'),
(59, 'string', 'searchable', NULL, NULL, NULL, '1', NULL, '2022-08-22 10:05:05'),
(59, 'string', 'content_en', NULL, NULL, NULL, '<h3>What children learn from the daily program.</h3>\r\n<p>The daily program supports our goals for the children. We want your child to feel secure and independent, to move from one activity to another as easily and confidently as possible.</p>\r\n<p>We also want to provide a variety of learning experiences for a well-rounded education. So we plan a daily program that takes all of these goals into account.</p>\r\n<p>We follow the same routine day after day so children know what will be happening next. The day is a mix of free play, where the children can choose from the activities provided, and formal times where the children sit together and do all the same activities under staff instruction e.g. music, language groups and transition times.</p>', NULL, '2022-08-22 10:05:05'),
