INSERT INTO `cms_content_props` (`content_id`, `type`, `prop_name`, `param1`, `param2`, `param3`, `content`, `create_date`, `modified_date`) VALUES
(65, 'string', 'content_en', NULL, NULL, NULL, '<h2>From the moment you step outside into our unique outdoor learning environment, you will be transformed into a space that connects children to nature.</h2>\r\n<p>These areas were recognised for its natural design that support children&rsquo;s development through play, exploration and risk management skills when it won the Kidsafe National Playspace Design Awards in 2018.</p>\r\n<p>The outdoor environment consists of two areas, one designed for children under three years of age and the other for preschool age children. It is aesthetically pleasing with large natural grassed areas and a range of suitable spaces including garden beds, trees, vegetable gardens, composting, music &amp;amp; art pergolas, shade structures, paths, boat, mud kitchen, water pumping station, creek bed, bike track and much more.</p>\r\n<p>Loose Parts Play is an integral part of our nature based curriculum. While it occurs in all areas of the program it is most prominent outside in the bark soft fall areas where the large timber poles can be seen. The poles provide the skeleton for supporting a creative way for children to play and learn. They provide an open ended landscape for engineering creativity.</p>\r\n<p>The poles areas allow for positive adult-supported risk-taking play or challenging play and provides opportunities for self-assessment of risk. Research shows that children that engage in supported risky play can become better problem-solvers and in adulthood are more likely to take better, healthier appropriate risks.</p>\r\n<p>Risky play&nbsp;helps to develop important life skill learnings, such as:</p>\r\n<ul>\r\n<li>Building resilience and persistence.</li>\r\n<li>Creative thinking</li>\r\n<li>Balance and coordination.</li>\r\n<li>Awareness of the capabilities and limits of their own bodies.</li>\r\n<li>The ability to assess and make judgement about risk.</li>\r\n<li>Handling tools safely and with purpose.</li>\r\n<li>Understanding consequence to action</li>\r\n</ul>\r\n<p>All areas are nature-inspired spaces and are designed to provide children with open-end play possibilities, connecting them with our local flora and fauna.</p>\r\n<p>Our service has a community sustainability practices ethos and this is embedded through all our programs. We have worm farms, compost stations, rainwater tanks supplying water to our children&rsquo;s hand pumps, we upcycle and recycle materials and we frequently create and explore with natural materials.</p>\r\n<p><strong>In fact, we see the environment as the &lsquo;third teacher&rsquo;, alongside our highly trained, experienced early education professionals.</strong></p>', NULL, '2022-08-18 18:42:35'),
(65, 'string', 'extra1', NULL, NULL, NULL, '', NULL, '2022-08-18 18:42:35'),
(65, 'string', 'extra2', NULL, NULL, NULL, '', NULL, '2022-08-18 18:42:35'),
(65, 'string', 'extra3', NULL, NULL, NULL, '', NULL, '2022-08-18 18:42:35'),
(65, 'string', 'pagedata', NULL, NULL, NULL, '', NULL, '2022-08-18 18:42:35'),
