(35, 'string', 'content_en', NULL, NULL, NULL, '<p>The service has strong connections with local services &amp; organisations that support families and young children.&nbsp;</p>\r\n<p><strong>Connected with local schools</strong></p>\r\n<ul>\r\n<li><a title=\"Gloucester Public School\" href=\"https://gloucester-p.schools.nsw.gov.au/\" target=\"_blank\" rel=\"noopener\">Gloucester Public School</a></li>\r\n<li><a title=\"St Joseph&rsquo;s Primary School\" href=\"https://www.gloucester.catholic.edu.au/\" target=\"_blank\" rel=\"noopener\">St Joseph&rsquo;s Primary School</a></li>\r\n<li><a title=\"Barrington Public School\" href=\"https://barrington-p.schools.nsw.gov.au/\" target=\"_blank\" rel=\"noopener\">Barrington Public School</a></li>\r\n<li><a title=\"Stratford Public School\" href=\"https://stratford-p.schools.nsw.gov.au/\" target=\"_blank\" rel=\"noopener\">Stratford Public School</a></li>\r\n</ul>\r\n<p><strong>Allied Health Services</strong></p>\r\n<ul>\r\n<li><a title=\"Hunter New England Health\" href=\"https://www.hnehealth.nsw.gov.au/\" target=\"_blank\" rel=\"noopener\">Hunter New England Health</a> - Before School Screening, OT, Speech</li>\r\n<li><a title=\"NDIS\" href=\"https://www.ndis.gov.au/\" target=\"_blank\" rel=\"noopener\">NDIS</a></li>\r\n<li><a title=\"Catholic Care\" href=\"https://www.catholiccare.org/\" target=\"_blank\" rel=\"noopener\">Catholic Care</a></li>\r\n<li><a title=\"MSS\" href=\"https://mssinc.org.au/\" target=\"_blank\" rel=\"noopener\">MSS</a></li>\r\n</ul>\r\n<p><strong>Community Organisations</strong></p>\r\n<ul>\r\n<li><a title=\"Bucketts Way Neighbourhood Centre\" href=\"https://bwng.org.au/\" target=\"_blank\" rel=\"noopener\">Bucketts Way Neighbourhood Centre</a></li>\r\n<li>AEGC</li>\r\n</ul>\r\n<p>&nbsp;</p>', NULL, '2022-08-03 12:58:55'),
