(61, 'string', 'content_en', NULL, NULL, NULL, '<p>Pre School is funded by the NSW State Government.</p>\r\n<p>Operating hour 8.15am - 3.45pm (school term only)</p>\r\n<p>It is available for children ages 3 to 5 years of age.</p>', NULL, '2022-08-10 13:58:38'),
