(68, 'string', 'content_en', NULL, NULL, NULL, '<h2>Long Day Care is open 8am to 5.15pm and operates 50 weeks per year.</h2>\r\n<p>Enrolments are open to children 0 to 5 years of age.</p>\r\n<p>Families will need to apply for the Child Care Subsidy (CCS) through your MyGov account</p>\r\n<p>All children are provided with nutritious meals prepared on the premises in our commercial kitchen each day.</p>\r\n<p>&nbsp;</p>', NULL, '2022-09-06 12:35:30'),
