(25, 'topnav', '[[strip]]\r\n[[capture assign=\'root\']][[uploads_url]][[/capture]]\r\n\r\n[[assign \'theme\' \'#ffffff\' scope=global]]\r\n[[assign \'primary\' \'#FF7F00\' scope=global]]\r\n[[assign \'secondary\' \'#676767\' scope=global]]\r\n[[assign \'grey\' \'rgb(120,120,120)\' scope=global]]\r\n[[assign \'lightgrey\' \'#ebebeb\' scope=global]]\r\n[[assign \'darkgrey\' \'#515151\' scope=global]]\r\n[[assign \'red\' \'#C9252C\' scope=global]]\r\n[[assign \'highlight\' \'#C9252C\' scope=global]]\r\n\r\n[[assign \'white\' \'#ffffff\' scope=global]]\r\n[[assign \'black\' \'#000000\' scope=global]]\r\n[[assign \'orange\' \'#FF7F00\' scope=global]]\r\n[[assign \'darkblue\' \'#005CB9\' scope=global]]\r\n\r\n\r\n[[* /* assign the images path to a variable */ *]]\r\n\r\n[[capture assign=\'path\']][[uploads_url]]/simplex/images[[/capture]]\r\n\r\n[[capture assign=\'font\']][[uploads_url]]/simplex/fonts[[/capture]]\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n.navwrapper {\r\n\r\npadding: 0;}\r\n\r\n	\r\n\r\n\r\n\r\n[[* /* ------ NAVIGATION ------ */ *]]\r\n\r\n[[* /* --- FIRST LEVEL --- */ *]]\r\n\r\n.main-menu > li {display: block;border-bottom: none;position: relative;}\r\n\r\n.main-menu > li:last-child {}\r\n\r\n.main-menu > li > a,\r\n\r\n.main-menu > li.sectionheader > span {\r\n\r\nfont-family: \'Montserrat\', sans-serif;\r\ncolor: #ffffff;\r\ntext-decoration: none;\r\n\r\n[[* /* 20px */ *]]\r\n\r\nfont-weight: 400;\r\ncursor: pointer;\r\ndisplay: block;\r\nposition: relative;}\r\n\r\n.main-menu > li.current > a,\r\n\r\n.main-menu > li.current.sectionheader > span,\r\n\r\n.main-menu > li:hover > a,\r\n\r\n.main-menu > li.sectionheader:hover > span {\r\n\r\ncolor: [[$black]];\r\n\r\nbackground-color: [[$white]];\r\n\r\n}\r\n\r\n\r\n\r\n[[* /* --- SECOND LEVEL --- */ *]]\r\n\r\n.main-menu > li > ul,\r\n\r\n.main-menu > li > ul > li > ul [[* /* third level */ *]] {\r\n\r\nposition: absolute;\r\n\r\nleft: -999em;\r\n\r\nlist-style:none;}\r\n\r\n\r\n\r\n.main-menu > li:hover > ul,\r\n\r\n.main-menu > li.active > ul,\r\n\r\n.main-menu > li > ul > li:hover > ul, [[* /* third level */ *]]\r\n\r\n.main-menu > li > ul > li.active > ul {\r\n\r\nposition: relative;\r\n\r\nleft: 0;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li > ul > li > a,\r\n\r\n.main-menu > li > ul > li.sectionheader > span,\r\n\r\n.main-menu > li > ul > li > ul > li > a, [[* /* third level */ *]]\r\n\r\n.main-menu > li > ul > li > ul > li.sectionheader > span {\r\n\r\ntext-decoration: none;\r\n\r\ncolor: [[$white]];\r\n\r\ntext-transform: uppercase;\r\n\r\ndisplay: block;\r\n\r\npadding: 5px 0;\r\n\r\ntext-align: right;\r\n\r\n}\r\n\r\n.main-menu > li > ul > li:hover > a,\r\n\r\n.main-menu > li > ul > li.sectionheader:hover > span,\r\n\r\n.main-menu > li > ul > li > ul > li:hover > a,\r\n\r\n.main-menu > li > ul > li > ul > li.sectionheader:hover > span {\r\n\r\ncolor: #ffffff;\r\n\r\n}\r\n\r\n[[* /* --- THIRD LEVEL --- */ *]]\r\n\r\n.main-menu > li > ul > li > ul > li > a,\r\n\r\n.main-menu > li > ul > li > ul > li.sectionheader > span {\r\n\r\npadding-left: 15px;\r\n\r\nfont-size: .875em;\r\n\r\ntext-transform: uppercase;\r\n\r\n}\r\n\r\n\r\n\r\n[[* /* =====================================\r\n\r\n SCREENS BIGGER THAN 768px\r\n\r\n ===================================== */ *]]\r\n\r\n\r\n\r\n.main-navigation {\r\n\r\nz-index: 990;\r\n\r\nmargin: 0;\r\ntext-transform:uppercase;\r\n}\r\n\r\n.main-menu {float: right;margin: 0;}\r\n\r\n.main-navigation ul {margin: 0;}\r\n\r\n\r\n\r\n[[* /* --- FIRST LEVEL --- */ *]]\r\n\r\n\r\nul.main-menu {\r\n\r\n    font-family: inherit;\r\n    list-style-position: inside;\r\n}\r\n\r\n.main-menu > li {\r\n\r\ndisplay: inline-block;\r\n\r\npadding: 0;\r\n\r\nmargin: 0 1px 0 0;\r\n\r\nborder: none;\r\n\r\nposition: relative;\r\n\r\nleft: 0;}\r\n\r\n\r\n\r\n.main-menu > li:first-child, .main-menu > li.first {margin-left: 0;}\r\n\r\n.main-menu > li:last-child, .main-menu > li.last {margin-right: 0;}\r\n\r\n\r\n\r\n.main-menu > li > a, \r\n.main-menu > li.sectionheader span {\r\npadding: 0 1rem;\r\nline-height: 40px;\r\nfont-size: 1rem;\r\ntext-transform:uppercase;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li.parent:hover > a, \r\n\r\n.main-menu > li.sectionheader.parent:hover > span,\r\n\r\n.main-menu > li.parent.active > a, \r\n\r\n.main-menu > li.parent.active > span {\r\n\r\ncolor: [[$black]];\r\n\r\nbackground-color: [[$white]];\r\n\r\nborder-bottom: none;\r\n\r\n}\r\n\r\n\r\n\r\n[[* /* --- SECOND LEVEL --- */ *]]\r\n\r\n.main-menu > li > ul,\r\n\r\n.main-menu > li > ul > li > ul [[* /* third level */ *]] {\r\n\r\ndisplay: block;\r\n\r\nwidth: 220px;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li:hover > ul,\r\n\r\n.main-menu > li.active > ul,\r\n\r\n.main-menu > li > ul > li:hover > ul,\r\n\r\n.main-menu > li > ul > li.active > ul {\r\n\r\nheight: auto;\r\n\r\nposition: absolute;\r\n\r\nz-index: 9999;\r\n\r\ntop: 43px;\r\n\r\nright: 0;\r\n\r\nleft: auto;\r\n\r\ndisplay: block;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li:first-child:hover > ul,\r\n\r\n.main-menu > li:first-child.active > ul {\r\n\r\nright: auto;\r\n\r\nleft: 0;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li > ul > li {\r\n\r\nposition: relative;\r\n\r\nline-height: 1;\r\n\r\nmargin: 0;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li:first-child > ul > li {\r\n\r\npadding-right: 10px;\r\n\r\npadding-left: 0;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li > ul > li > a,\r\n\r\n.main-menu > li > ul > li.sectionheader > span,\r\n\r\n.main-menu > li > ul > li > ul > li > a,\r\n\r\n.main-menu > li > ul > li > ul > li.sectionheader > span {\r\n\r\ncolor: [[$white]];\r\n\r\ndisplay: block;\r\n\r\ntext-transform: uppercase;\r\n\r\nline-height: 2.5rem;\r\nfont-size: 1rem;\r\n\r\nbackground-color: rgba(0,0,0,1.0);\r\n\r\npadding:0 0.75rem;\r\n\r\ntext-decoration: none;\r\n\r\nmargin: -0.2rem 0 0 auto;\r\n\r\nfont-family: \'Montserrat\', sans-serif;\r\n\r\nfont-weight: 300;\r\n\r\nborder:1px solid #666666;}\r\n\r\n\r\n\r\n.main-menu > li > ul > li > a:hover {\r\n\r\ncolor: #000000;\r\n\r\nbackground-color: [[$white]];\r\n\r\nborder:1px solid #000000;\r\n}\r\n\r\n\r\n\r\n\r\n\r\n.main-menu > li > ul > li.current > a, \r\n\r\n.main-menu > li > ul > li.current.sectionheader > span,\r\n\r\n.main-menu > li > ul > li > ul > li.current > a, \r\n\r\n.main-menu > li > ul > ul > li > li.current.sectionheader > span {\r\n\r\ncolor:  [[$white]];\r\n\r\nbackground-color: #666666;}\r\n\r\n\r\n\r\n[[* /* THIRD LEVEL */ *]]\r\n\r\n.main-menu > li > ul > li:hover > ul,\r\n\r\n.main-menu > li > ul > li.active > ul {\r\n\r\nwidth: 250px;\r\n\r\nheight: auto;\r\n\r\ntop: 0;\r\n\r\nright: auto;\r\n\r\nleft: -250px;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li:first-child > ul > li:hover > ul,\r\n\r\n.main-menu > li:first-child > ul > li.active > ul {\r\n\r\nleft: auto;\r\n\r\nright: -250px;\r\n\r\n}\r\n\r\n\r\n\r\n.lt-ie9 .main-menu > li > ul > li:hover > ul,\r\n\r\n.lt-ie9 .main-menu > li > ul > li.active > ul {\r\n\r\nleft: -247px;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li > ul > li:hover > ul:after,\r\n\r\n.main-menu > li > ul > li.active > ul:after {\r\n\r\ncontent: \' \';\r\n\r\nwidth: 0px;\r\n\r\nheight: 0px;\r\n\r\nborder-style: solid;\r\n\r\nborder-width: 7px 0 7px 6px;\r\n\r\nborder-color: transparent transparent transparent [[$dark_grey]];\r\n\r\nborder-color: transparent transparent transparent rgba(85, 85, 85, .95);\r\n\r\nposition: absolute;\r\n\r\nright: -6px;\r\n\r\ntop: 12px;\r\n\r\n}\r\n\r\n\r\n\r\n.lt-ie9 .main-menu > li:first-child > ul > li:hover > ul,\r\n\r\n.lt-ie9 .main-menu > li:first-child > ul > li.active > ul {\r\n\r\nleft: auto;\r\n\r\nright: -247px;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu > li:first-child > ul > li:hover > ul:after,\r\n\r\n.main-menu > li:first-child > ul > li.active > ul:after {\r\n\r\nleft: -10px;\r\n\r\nright: auto;\r\n\r\n}\r\n\r\n\r\n\r\n.main-menu li ul li a:hover {color:[[$black]];background: [[$white]];}\r\n.main-menu li ul li a.cf:hover {color:[[$black]];background: [[$white]];}\r\n\r\n.main-menu li ul li span.sectionheader:hover {}\r\n\r\n\r\n\r\n.main-menu > ul > li:last-child > a,\r\n\r\n.main-menu > ul > li.sectionheader:last-child > span,\r\n\r\n.main-menu > ul > li > ul > li:last-child > a,\r\n\r\n.main-menu > ul > li > ul > li.sectionheader:last-child > span {\r\n\r\nborder-bottom: none;\r\n\r\n}\r\n\r\n\r\n\r\n\r\n\r\n\r\n.main-menu > li.hide {\r\n\r\n    display: none;\r\n\r\n}\r\n\r\n.hide {\r\n\r\n    display: none;\r\n\r\n}\r\n\r\n\r\n\r\n\r\n\r\n[[/strip]]', '', '', '', 1647993402, 1647993420),
(26, 'lightbox', '.lb-loader,.lightbox{text-align:center;line-height:0;position:absolute;left:0}body.lb-disable-scrolling{overflow:hidden}.lightboxOverlay{position:absolute;top:0;left:0;z-index:9999;background-color:#000;filter:alpha(Opacity=80);opacity:.8;display:none}.lightbox{width:100%;z-index:10000;font-weight:400;outline:0}.lightbox .lb-image{display:block;height:auto;max-width:inherit;max-height:none;border-radius:3px;border:4px solid #fff}.lightbox a img{border:none}.lb-outerContainer{position:relative;width:250px;height:250px;margin:0 auto;border-radius:4px;background-color:#fff}.lb-outerContainer:after{content:\"\";display:table;clear:both}.lb-loader{top:43%;height:25%;width:100%}.lb-cancel{display:block;width:32px;height:32px;margin:0 auto;background:url(../images/loading.gif) no-repeat}.lb-nav{position:absolute;top:0;left:0;height:100%;width:100%;z-index:10}.lb-container>.nav{left:0}.lb-nav a{outline:0;background-image:url(data:image/gif;base64,R0lGODlhAQABAPAAAP///wAAACH5BAEAAAAALAAAAAABAAEAAAICRAEAOw==)}.lb-next,.lb-prev{height:100%;cursor:pointer;display:block}.lb-nav a.lb-prev{width:34%;left:0;float:left;background:url(../images/prev.png) left 48% no-repeat;filter:alpha(Opacity=0);opacity:0;-webkit-transition:opacity .6s;-moz-transition:opacity .6s;-o-transition:opacity .6s;transition:opacity .6s}.lb-nav a.lb-prev:hover{filter:alpha(Opacity=100);opacity:1}.lb-nav a.lb-next{width:64%;right:0;float:right;background:url(../images/next.png) right 48% no-repeat;filter:alpha(Opacity=0);opacity:0;-webkit-transition:opacity .6s;-moz-transition:opacity .6s;-o-transition:opacity .6s;transition:opacity .6s}.lb-nav a.lb-next:hover{filter:alpha(Opacity=100);opacity:1}.lb-dataContainer{margin:0 auto;padding-top:5px;width:100%;border-bottom-left-radius:4px;border-bottom-right-radius:4px}.lb-dataContainer:after{content:\"\";display:table;clear:both}.lb-data{padding:0 4px;color:#ccc}.lb-data .lb-details{width:85%;float:left;text-align:left;line-height:1.1em}.lb-data .lb-caption{font-size:13px;font-weight:700;line-height:1em}.lb-data .lb-caption a{color:#4ae}.lb-data .lb-number{display:block;clear:left;padding-bottom:1em;font-size:12px;color:#999}.lb-data .lb-close{display:block;float:right;width:30px;height:30px;background:url(../images/close.png) top right no-repeat;text-align:right;outline:0;filter:alpha(Opacity=70);opacity:.7;-webkit-transition:opacity .2s;-moz-transition:opacity .2s;-o-transition:opacity .2s;transition:opacity .2s}.lb-data .lb-close:hover{cursor:pointer;filter:alpha(Opacity=100);opacity:1}', '', '', '', 1648015706, 1648015713);
INSERT INTO `cms_layout_stylesheets` (`id`, `name`, `content`, `description`, `media_type`, `media_query`, `created`, `modified`) VALUES
(22, 'gpc_app', '[[strip]]\r\n[[capture assign=\'root\']][[uploads_url]][[/capture]]\r\n\r\n[[assign \'theme\' \'#FF7F00\' scope=global]]\r\n[[assign \'primary\' \'#FF7F00\' scope=global]]\r\n[[assign \'secondary\' \'#676767\' scope=global]]\r\n[[assign \'grey\' \'#787878\' scope=global]]\r\n[[assign \'lightgrey\' \'#ebebeb\' scope=global]]\r\n[[assign \'midgrey\' \'#515151\' scope=global]]\r\n[[assign \'darkgrey\' \'#333333\' scope=global]]\r\n[[assign \'red\' \'#C9252C\' scope=global]]\r\n[[assign \'highlight\' \'#C9252C\' scope=global]]\r\n\r\n[[assign \'white\' \'#ffffff\' scope=global]]\r\n[[assign \'black\' \'#000000\' scope=global]]\r\n[[assign \'orange\' \'#FF7F00\' scope=global]]\r\n[[assign \'darkblue\' \'#005CB9\' scope=global]]\r\n\r\n\r\n\r\nbody {font-family: \'Lato\', sans-serif;font-weight: 400;}\r\n\r\n\r\n#header {\r\n    width: 100%;\r\n    position: fixed;\r\n    padding: 0;\r\n    background-color:[[$black]];\r\n    top: 0;\r\n	left:0;\r\n	right:0;\r\n    z-index: 100;\r\n	height:40px;\r\n}\r\n\r\n/*Page (Features)\r\n\r\n------------------------------------*/\r\na {color: #4e4e4e;}\r\na:focus, a:hover {\r\n    color: [[$black]];\r\n    text-decoration: none;\r\n    line-height: inherit;}\r\n\r\n/*Thumbnail*/\r\n\r\n.thumbnail-kenburn img {\r\n   -webkit-transition: all 0.6s ease-in-out;\r\n   -moz-transition: all 0.6s ease-in-out;\r\n   -o-transition: all 0.6s ease-in-out;\r\n   -ms-transition: all 0.6s ease-in-out;\r\n   transition: all 0.6s ease-in-out;\r\n}\r\n\r\n.thumbnail-kenburn:hover img {\r\n     -webkit-transform: rotate(-90deg);\r\n	    -moz-transform: rotate(-90deg);\r\n	    -ms-transform: rotate(-90deg);\r\n	    -o-transform: rotate(-90deg);\r\n	    transform: rotate(-90deg)\r\n}\r\n.thumbnail-kenburn a {border:none;}\r\n.thumbnail-kenburn a:hover {border:none;}\r\n\r\n.black-box {\r\n    color: [[$black]];\r\n    padding: 3rem .5rem;\r\n    margin-top: 41px;\r\n}\r\n.black-box p {\r\n	font-weight: 400;;\r\n	margin: 0;\r\n	font-size: 180%;\r\n}\r\n.caption-text h1{\r\nfont-family: \'Montserrat\', sans-serif;\r\ncolor: [[$black]];\r\nfont-size: calc(1rem + 2rem * ((100vw - 320px) / 680));\r\nline-height: 100px;\r\nfont-weight: 400;\r\ntext-transform: uppercase;\r\nletter-spacing: 0.1em;\r\nmargin:0;\r\n	}\r\n\r\n.caption-text h1 {font-size: 32px;}\r\n@media screen and (min-width: 768px) {\r\n.caption-text h1 {\r\nfont-size: calc(32px + 12 * ((100vw - 768px) / 1600));}\r\n}\r\n@media screen and (min-width: 1600px) {\r\n		.caption-text h1 {\r\n		  font-size: 44px;\r\n		}\r\n	  }\r\n\r\n.caption-text p{\r\nfont-family: \'Montserrat\', sans-serif;font-weight: 400;}\r\n\r\n@media only screen and (max-width: 767px) {\r\n\r\n.caption-text h1{\r\nfont-size: 2rem;\r\nline-height: 2rem;\r\n}\r\n}	\r\n\r\n.caption-text a {\r\n	color: [[$black]];\r\n	border-bottom: 2px dotted [[$black]];\r\n	padding-bottom: 3px;\r\n	padding-top: 3px;\r\n	}\r\n\r\n.caption-text a:hover {\r\n	color: [[$black]];\r\n	background-color: [[$lightgrey]];\r\n	border-bottom-width: 2px;\r\n	border-bottom-style: dotted;\r\n	border-bottom-color: #FF7F00;\r\n	text-decoration: none;\r\n	-webkit-transition: all 0.6s ease-in-out;\r\n   -moz-transition: all 0.6s ease-in-out;\r\n   -o-transition: all 0.6s ease-in-out;\r\n   -ms-transition: all 0.6s ease-in-out;\r\n   transition: all 0.6s ease-in-out;\r\n	}\r\n\r\n\r\n\r\n.block_holder {}\r\n\r\n.hover_block {\r\n    position: relative;\r\n    overflow: hidden;\r\n}\r\n\r\n.hover_info {\r\n    width: 100%;\r\n    height: 100%;\r\n    position: absolute;\r\n    top: 0;\r\n    left: 0;\r\n}\r\n\r\n\r\n.hover_info h1 { font-size: 1.5em; padding: 10px 20px; background: rgba(207, 138, 5, 0.7); color: #E7E7E7; position: absolute; top: 25px; left: -100%; transition: left 200ms linear; -webkit-transition: left 200ms linear; -moz-transition: left 200ms linear; }\r\n\r\n.hover_info p { font-size: 0.9em; line-height: 1.2; color: [[$white]];position: absolute; top: 10%; left: 5%; width: 90%; text-align: left; opacity: 0; transition: opacity 200ms linear; -webkit-transition: opacity 200ms linear; -moz-transition: opacity 200ms linear; }\r\n\r\n.hover_info a {\r\n	font-size: 1.1em;\r\n	padding: 10px 20px;\r\n	 background: [[$white]];\r\n	position: absolute;\r\n	bottom: 10%;\r\n	right: -100%;\r\n	font-family: inherit;\r\n	color: [[$black]];\r\n	line-height: 30px;\r\n	font-weight: 400;\r\n	text-transform: uppercase;\r\n	letter-spacing: 1px;\r\n}\r\n\r\n.hover_info:hover h1 { left: 0; transition-delay: 250ms; -webkit-transition-delay: 250ms; -moz-transition-delay: 250ms; }\r\n\r\n.hover_info:hover p { opacity: 1; transition-delay: 600ms; -webkit-transition-delay: 600ms; -moz-transition-delay: 600ms; }\r\n\r\n.hover_info:hover a { right: 0; transition: right 200ms linear 200ms, color, background 200ms linear; -webkit-transition: right 200ms linear 200ms, color, background 200ms linear; -moz-transition: right 200ms linear 200ms, color, background 200ms linear; }\r\n\r\n.hover_info a:hover {\r\n	background-color: [[$black]];\r\n	color: [[$white]];\r\n}\r\n\r\n\r\n\r\n\r\n\r\n.block_17 .blind {\r\n\r\n    width: 100%;\r\n\r\n    height: 100%;\r\n\r\n    background-color: black;\r\n\r\n        background-color: rgba(0, 0, 0, 0.4);\r\n\r\n    position: absolute;\r\n\r\n    top: 0;\r\n\r\n    left: 0;\r\n\r\n    transition: all 300ms linear; \r\n\r\n    -webkit-transition: all 300ms linear;  \r\n\r\n    -moz-transition: all 300ms linear;\r\n\r\n    transform: scale(0,0);\r\n\r\n    -webkit-transform: scale(0,0);\r\n\r\n}\r\n\r\n\r\n\r\n.block_17:hover .blind { transform: scale(1, 1); -webkit-transform: scale(1, 1); }\r\n\r\n.hover_block img, .block_17 img {margin: 0 auto;align-items: center;text-align:center;}\r\n\r\n.casestudyimage {margin:0 auto 1rem auto;}\r\n\r\n.casestudysidebarlist p {text-transform:capitalize;\r\nfont-size: 1.1rem;\r\nline-height: 1.1;\r\nmargin-bottom: 0.25rem;padding:0.5rem 0 0 0;}\r\n\r\n.detaillist {margin-bottom:0.5rem;\r\nbox-shadow: 0 2px 8px [[$white]];\r\n    -webkit-transition: box-shadow 0.2s ease-in-out;\r\n    -moz-transition: box-shadow 0.2s ease-in-out;\r\n    -o-transition: box-shadow 0.2s ease-in-out;\r\n    transition: box-shadow 0.2s ease-in-out;\r\n    border: 1px solid [[$white]];}\r\n\r\n.detaillist:hover {box-shadow: 0 2px 8px #CFCFCF;\r\n    -webkit-transition: box-shadow 0.2s ease-in-out;\r\n    -moz-transition: box-shadow 0.2s ease-in-out;\r\n    -o-transition: box-shadow 0.2s ease-in-out;\r\n    transition: box-shadow 0.2s ease-in-out;\r\n    border: 1px solid [[$lightgrey]];}\r\n\r\n\r\n.casepad {padding:0 0 0 0.5rem;}\r\n\r\n.casepad p {\r\n    text-transform: capitalize;\r\n    font-size: 1.1rem;\r\n    line-height: 1.1rem;\r\n    margin: 0;\r\n    padding: 0.4rem 0;\r\n}\r\n.casepad p a {color:[[$darkgrey]];border-bottom:1px solid transparent;padding: 0.25rem 0.5rem;}\r\n.casepad p a:hover {color:[[$black]];border-bottom:1px dotted [[$primary]];background-color:[[$white]];}\r\n/* type\r\n\r\n------------------------------------*/\r\n\r\nh1{\r\n\r\n	font-family: \'Montserrat\', sans-serif;\r\n\r\n	color: [[$white]];\r\n\r\n	font-size: 36px;\r\n\r\n	line-height: 40px;\r\n\r\n	font-weight: 400;\r\n\r\n	text-transform: uppercase;\r\n\r\n	letter-spacing: 0.3em; }\r\n\r\n h2{\r\n\r\n	font-family: \'Montserrat\', sans-serif;\r\n\r\n	color: [[$white]];\r\n\r\n	font-size: 36px;\r\n\r\n	line-height: 40px;\r\n\r\n	font-weight: 400;\r\n\r\n	text-transform: uppercase;\r\n\r\n	letter-spacing: 3px;\r\n\r\n}\r\nh3.h4.h5,h6 {font-family: \'Montserrat\', sans-serif;}\r\n\r\np {\r\n    margin-bottom: 1rem;\r\n    font-size: 1rem;\r\n    line-height: 1.6;\r\n    text-rendering: optimizeLegibility;\r\n}\r\n\r\nul, ol, dl {\r\n	font-size: 1.2em;\r\n	line-height: 1.6;\r\n	margin-bottom: 1.25rem;\r\n	font-family: inherit;\r\n	list-style-position: inside;\r\n}\r\n\r\n\r\n\r\n.feature {}  \r\n\r\nbutton.round, .button.round {\r\n\r\nborder-radius: 6px;\r\n	padding-top: 1em;\r\n	padding-right: 2em;\r\n	padding-left: 2em;\r\n	padding-bottom: 4em;\r\n	border-style: solid;\r\n	border-width: 1px;\r\n	border-color: [[$lightgrey]];\r\n	background-color: [[$white]];\r\n	color: #666666;\r\n	}\r\n\r\n	\r\n\r\n    button.round:hover, button.round:focus, .button.round:hover, .button.round:focus {\r\n      background-color: [[$white]];\r\n	   color: [[$black]];\r\n	 box-shadow: 0 0 8px #ddd; \r\n    -webkit-transition: box-shadow 0.2s ease-in-out;\r\n    -moz-transition: box-shadow 0.2s ease-in-out;\r\n\r\n    -o-transition: box-shadow 0.2s ease-in-out;\r\n\r\n    transition: box-shadow 0.2s ease-in-out;\r\n\r\n	-webkit-border-radius: 3px;\r\n\r\n	border-radius: 6px;\r\n\r\n	border: 1px solid [[$lightgrey]];\r\n\r\n	   }	\r\n\r\n .largetext{\r\n	font-family: inherit;\r\n	font-size: 30px;\r\n	line-height: 40px;\r\n	font-weight: 400;\r\n	text-transform: uppercase;\r\n	letter-spacing: 3px;\r\n}\r\n\r\n\r\n\r\n.smalltext{\r\n	font-family: inherit;\r\n	font-size: 18px;\r\n	line-height: 24px;\r\n	font-weight: 400;\r\n	letter-spacing: 1px;	\r\n}\r\n\r\n\r\n\r\n\r\n\r\n@media only screen and (max-width: 1100px) {\r\n\r\n	\r\n\r\n .largetext{\r\n\r\n	font-family: inherit;\r\n\r\n	font-size: 24px;\r\n\r\n	line-height: 40px;\r\n\r\n	font-weight: 400;\r\n\r\n	text-transform: uppercase;\r\n\r\n	letter-spacing: 3px;\r\n\r\n	\r\n\r\n}\r\n\r\n.smalltext{\r\n\r\n	font-family: inherit;\r\n\r\n	font-size: 14px;\r\n\r\n	line-height: 24px;\r\n\r\n	font-weight: 400;\r\n\r\n	letter-spacing: 1px;	\r\n\r\n}\r\n\r\n\r\n\r\n}\r\n\r\n@media only screen and (max-width: 768px) {\r\n\r\n .largetext{\r\n\r\n	font-family: inherit;\r\n\r\n	font-size: 24px;\r\n\r\n	line-height: 40px;\r\n\r\n	font-weight: 400;\r\n\r\n	text-transform: uppercase;\r\n\r\n	letter-spacing: 3px;\r\n\r\n}\r\n\r\n.smalltext{\r\n\r\n	font-family: inherit;\r\n\r\n	font-size: 14px;\r\n\r\n	line-height: 24px;\r\n\r\n	font-weight: 400;\r\n\r\n	letter-spacing: 1px;	\r\n}\r\n\r\n\r\n}\r\n\r\n.clientthree {padding: 2rem 8rem 2rem 0rem;}\r\n\r\n.clientthree:nth-child(3n+2) {padding: 2rem 4rem 2rem 4rem;}\r\n\r\n.clientthree:nth-child(3n+3) {padding: 2rem 0rem 2rem 8rem;}\r\n\r\n\r\n\r\n@media only screen and (max-width: 1100px) {	\r\n\r\n.clientthree {padding: 1rem 2rem 1rem 0rem;}\r\n\r\n.clientthree:nth-child(3n+2) {padding: 1rem;}\r\n\r\n.clientthree:nth-child(3n+3) {padding: 1rem 0rem 1rem 2rem;}}\r\n\r\n@media only screen and (max-width: 767px) {	\r\n\r\n.clientthree {padding: 0.5rem;}\r\n\r\n.clientthree:nth-child(3n+2) {padding: 0.5rem;}\r\n\r\n.clientthree:nth-child(3n+3) {padding: 0.5rem;}}\r\n\r\n\r\n\r\n\r\n\r\n/* Sections \r\n\r\n------------------------------------*/\r\n\r\n.hero {\r\n    padding: 41px 0;\r\n}\r\n\r\n\r\n\r\n.hero_black {\r\n    margin: 40px auto 0 auto;\r\n	padding: 2.5rem 0;\r\n	background-color: [[$white]];\r\n    border-bottom: 0.8rem solid [[$black]];\r\n	width: 100%;\r\n} \r\n\r\n\r\n@media only screen and (max-width: 767px) {\r\n.hero_black {\r\nmargin:40px auto 0 auto;padding: 1.8rem 0;}}\r\n\r\n.hero_white {\r\n\r\n	padding: 40px 0;\r\n\r\n	background-color: [[$white]];\r\n\r\n	border-top: 1px solid [[$white]];\r\n\r\n	min-height: 210px;\r\n\r\n} \r\n\r\n.about-box{\r\n\r\n	color: [[$white]];\r\n\r\n	padding-top: 1em;\r\n\r\n	margin-top: 50px;\r\n\r\n	padding-bottom: 1em;\r\n\r\n	padding-right: 1em;\r\n\r\n	padding-left: 1em;\r\n\r\n}\r\n\r\n\r\n\r\n\r\n.secondary.small.button{background-color:transparent;color:[[$white]];border:2px [[$white]] solid;border-radius:5px;padding:15px 50px 15px 50px;margin:0;}.secondary.small.button:hover{background-color:rgba(255,255,255,0.5);}.row \r\n\r\n.main-wrapper{color:[[$white]];}\r\n\r\n\r\n\r\n\r\n\r\n.black {\r\n	background-color: [[$black]];\r\n	padding: 0;}\r\n\r\n.white {\r\n\r\n	background-color: [[$white]];\r\n\r\n	padding-top: 1em;\r\n\r\n	padding-bottom: 0.5em;}\r\n\r\n.grey {\r\n\r\n	background-color: #696969;\r\n\r\n	padding-top: 1em;\r\n\r\n	padding-bottom: 0.5em;}	\r\n\r\n.orange {\r\n\r\n	background-color: #FF7F00;\r\n\r