mary]];min-height:3rem;}\r\n.NewsroomSummarysidebar:hover {padding:0 0 0 0.5rem;margin:0 0 0 0.5rem;border-left:0.3rem solid [[$black]];min-height:3rem;}\r\n\r\n.NewsroomSummarysidebar h2 {\r\n	font-family: \'Montserrat\', sans-serif;\r\n    color:[[$white]];\r\n    font-size: 1rem;\r\n    line-height: 1;\r\n    font-weight: 400;\r\n    text-transform: none;\r\n    letter-spacing: 1px;\r\n	margin:0;\r\n	padding:0;\r\n}\r\n.NewsroomSummarysidebar p {\r\n	font-size: 0.8rem;\r\n	margin:0;\r\n	padding:0;\r\n}\r\n\r\n.casestudycontentwrapper {padding: 0 0 1.5rem;}\r\n.casestudycontent {}\r\n\r\n\r\n[[/strip]]', '', '', '', 1647993328, 1647993328);
