(23, 'menu_vert', '[[strip]]\r\n[[capture assign=\'root\']][[uploads_url]][[/capture]]\r\n\r\n[[assign \'theme\' \'#ffffff\' scope=global]]\r\n\r\n[[assign \'secondary\' \'#676767\' scope=global]]\r\n[[assign \'grey\' \'rgb(120,120,120)\' scope=global]]\r\n[[assign \'lightgrey\' \'#ebebeb\' scope=global]]\r\n[[assign \'darkgrey\' \'#515151\' scope=global]]\r\n[[assign \'highlight\' \'#C9252C\' scope=global]]\r\n\r\n[[assign \'white\' \'#ffffff\' scope=global]]\r\n[[assign \'black\' \'#000000\' scope=global]]\r\n[[assign \'mattblack\' \'#191C20\' scope=global]]\r\n[[assign \'red\' \'#C9252C\' scope=global]]\r\n[[assign \'orange\' \'#FF7F00\' scope=global]]\r\n[[assign \'darkblue\' \'#005CB9\' scope=global]]\r\n\r\n/******************** MENU *********************/\r\n#menu_vert {\r\n	margin-bottom: 0;\r\npadding:0;\r\n	background-color: [[$white]];\r\n\r\n}\r\n\r\nul.off-canvas-list, ul.second, ul.menusocial {\r\n    list-style-type: none;\r\n    margin: 0;\r\n    padding: 0;\r\n    font-family: \'Montserrat\', sans-serif;\r\n}\r\n\r\nul.off-canvas-list li.sectionheader  {color: [[$grey]];background:[[$black]];padding: 0; border-bottom: 1px solid [[$lightgrey]];}\r\n\r\n.off-canvas-list li a:focus, .off-canvas-list li a:hover, .off-canvas-list li a:active {\r\n    display: block;\r\n    padding: 0.4rem 0.66667rem;\r\n    color: [[$black]];\r\n    border-bottom: 1px solid #262626;\r\n    background: [[$white]];\r\n    transition: background 300ms ease;\r\n}\r\n.off-canvas-list li.menuactive a.menuactive {\r\n    display: block;\r\n    padding: 0.4rem 0.66667rem;\r\n    color: [[$black]];\r\n    border-bottom: 1px solid #262626;\r\n    background: [[$white]];\r\n    transition: background 300ms ease;\r\n  \r\n}\r\n\r\n.off-canvas-list ul.second li.menuactive a.menuactive {\r\n    color: [[$black]];\r\n    background: [[$white]];\r\n    padding: 0.35rem 0 0.35rem 1rem;\r\n}\r\n.off-canvas-list ul.second li.menuparent.menuactive a.menuparent.menuactive {\r\n    color: [[$white]];\r\n    background: [[$darkgrey]];\r\n    padding: 0.35rem 0 0.35rem 1rem;\r\n}\r\n.off-canvas-list ul.second li.menuparent.menuactive a.menuparent.menuactive:hover {\r\n    color: [[$black]];\r\n    background: [[$white]];\r\n    padding: 0.35rem 0 0.35rem 1rem;\r\n}\r\n.left-small a {background-color: #333333;}\r\nul.off-canvas-list li ul, ul li ol {margin: 0;}\r\nul.off-canvas-list li a {\r\n    border-bottom: 1px solid [[$lightgrey]];\r\n    color: [[$white]];\r\n    display: block;\r\n    padding: 0.4rem 0.66667rem;\r\n    transition: background 300ms ease;\r\n	background:[[$mattblack]];\r\n    font-family: \'Montserrat\', sans-serif;\r\n}\r\nul.off-canvas-list li a:hover, ul.off-canvas-list li a:focus {color: [[$black]];background:[[$white]];font-weight: normal;}\r\nul.off-canvas-list li li a {color: [[$white]];background:[[$grey]];padding: 0.35rem 0 0.35rem 1rem;font-size:1rem;}\r\nul.off-canvas-list li li a.menuparent {color: [[$white]];background:[[$darkgrey]];padding: 0.35rem 0 0.35rem 1rem;font-size:1rem;}\r\n\r\n\r\nul.off-canvas-list li li a:hover, ul.off-canvas-list li li a:focus {color: [[$mattblack]];background:[[$lightgrey]];padding: 0.35rem 0 0.35rem 1rem;font-size:1rem;}\r\n\r\n[[/strip]]', '', '', '', 1647993367, 1647993409),
(24, 'slick', '[[strip]]\r\n[[capture assign=\'root\']][[uploads_url]][[/capture]]\r\n\r\n[[assign \'theme\' \'#ffffff\' scope=global]]\r\n\r\n[[assign \'secondary\' \'#676767\' scope=global]]\r\n\r\n[[assign \'lightgrey\' \'#ebebeb\' scope=global]]\r\n[[assign \'darkgrey\' \'#A9A9A9\' scope=global]]\r\n[[assign \'red\' \'#C9252C\' scope=global]]\r\n[[assign \'highlight\' \'#C9252C\' scope=global]]\r\n\r\n[[assign \'white\' \'#ffffff\' scope=global]]\r\n[[assign \'black\' \'#000000\' scope=global]]\r\n\r\n.homesliderbanner {\r\n\r\nwidth: 200px;\r\nheight: 150px;\r\n	margin: 0 auto 1rem auto;\r\n	display: block;\r\n	font-size: 0px;\r\n	text-decoration: none;\r\n\r\n	  -webkit-filter: grayscale(100%);\r\n\r\n   -moz-filter: grayscale(100%);\r\n\r\n   filter: grayscale(100%);\r\n\r\n	 opacity: 0.3;\r\n\r\n	transition: all 0.5s ease;}\r\n\r\n\r\n\r\n.homesliderbanner a {\r\n\r\n\r\n	margin: 0 auto 1rem auto;\r\n	text-decoration: none;\r\n\r\n }\r\n\r\n\r\n\r\n.homesliderbanner:hover {\r\n\r\n	text-decoration: none;\r\n\r\n	-webkit-filter: grayscale(0%);\r\n\r\n   -moz-filter: grayscale(0%);\r\n\r\n	filter: grayscale(0%);\r\n\r\n   opacity: 1;}\r\n\r\n\r\n.slick-center .homesliderbanner {\r\n\r\n	text-decoration: none;\r\n\r\n	-webkit-filter: grayscale(0%);\r\n\r\n   -moz-filter: grayscale(0%);\r\n\r\n	filter: grayscale(0%);\r\n\r\n   opacity: 1;}\r\n\r\n\r\n[[/strip]]', '', '', '', 1647993384, 1647993415);
INSERT INTO `cms_layout_stylesheets` (`id`, `name`, `content`, `description`, `media_type`, `media_query`, `created`, `modified`) VALUES
(21, 'gpc_font-awesome', '[[strip]]\r\n\r\n[[capture assign=\'root\']][[uploads_url]][[/capture]]\r\n\r\n\r\n\r\n/*!\r\n\r\n *  Font Awesome 4.7.0 by @davegandy - http://fontawesome.io - @fontawesome\r\n\r\n *  License - http://fontawesome.io/license (Font: SIL OFL 1.1, CSS: MIT License)\r\n\r\n */\r\n\r\n/* FONT PATH\r\n\r\n * -------------------------- */\r\n\r\n@font-face {\r\n\r\n  font-family: \'FontAwesome\';\r\n\r\n  src: url(\'[[$root]]/accesspr/fonts/fontawesome-webfont.eot?v=4.7.0\');\r\n\r\n  src: url(\'[[$root]]/accesspr/fonts/fontawesome-webfont.eot?#iefix&v=4.7.0\') format(\'embedded-opentype\'), url(\'[[$root]]/accesspr/fonts/fontawesome-webfont.woff2?v=4.7.0\') format(\'woff2\'), url(\'[[$root]]/accesspr/fonts/fontawesome-webfont.woff?v=4.7.0\') format(\'woff\'), url(\'[[$root]]/accesspr/fonts/fontawesome-webfont.ttf?v=4.7.0\') format(\'truetype\'), url(\'[[$root]]/accesspr/fonts/fontawesome-webfont.svg?v=4.7.0#fontawesomeregular\') format(\'svg\');\r\n\r\n  font-weight: normal;\r\n\r\n  font-style: normal;\r\n\r\n}\r\n\r\n.fa {\r\n\r\n  display: inline-block;\r\n\r\n  font: normal normal normal 14px/1 FontAwesome;\r\n\r\n  font-size: inherit;\r\n\r\n  text-rendering: auto;\r\n\r\n  -webkit-font-smoothing: antialiased;\r\n\r\n  -moz-osx-font-smoothing: grayscale;\r\n\r\n}\r\n\r\n/* makes the font 33% larger relative to the icon container */\r\n\r\n.fa-lg {\r\n\r\n  font-size: 1.33333333em;\r\n\r\n  line-height: 0.75em;\r\n\r\n  vertical-align: -15%;\r\n\r\n}\r\n\r\n.fa-2x {\r\n\r\n  font-size: 2em;\r\n\r\n}\r\n\r\n.fa-3x {\r\n\r\n  font-size: 3em;\r\n\r\n}\r\n\r\n.fa-4x {\r\n\r\n  font-size: 4em;\r\n\r\n}\r\n\r\n.fa-5x {\r\n\r\n  font-size: 5em;\r\n\r\n}\r\n\r\n.fa-fw {\r\n\r\n  width: 1.28571429em;\r\n\r\n  text-align: center;\r\n\r\n}\r\n\r\n.fa-ul {\r\n\r\n  padding-left: 0;\r\n\r\n  margin-left: 2.14285714em;\r\n\r\n  list-style-type: none;\r\n\r\n}\r\n\r\n.fa-ul > li {\r\n\r\n  position: relative;\r\n\r\n}\r\n\r\n.fa-li {\r\n\r\n  position: absolute;\r\n\r\n  left: -2.14285714em;\r\n\r\n  width: 2.14285714em;\r\n\r\n  top: 0.14285714em;\r\n\r\n  text-align: center;\r\n\r\n}\r\n\r\n.fa-li.fa-lg {\r\n\r\n  left: -1.85714286em;\r\n\r\n}\r\n\r\n.fa-border {\r\n\r\n  padding: .2em .25em .15em;\r\n\r\n  border: solid 0.08em #eeeeee;\r\n\r\n  border-radius: .1em;\r\n\r\n}\r\n\r\n.fa-pull-left {\r\n\r\n  float: left;\r\n\r\n}\r\n\r\n.fa-pull-right {\r\n\r\n  float: right;\r\n\r\n}\r\n\r\n.fa.fa-pull-left {\r\n\r\n  margin-right: .3em;\r\n\r\n}\r\n\r\n.fa.fa-pull-right {\r\n\r\n  margin-left: .3em;\r\n\r\n}\r\n\r\n/* Deprecated as of 4.4.0 */\r\n\r\n.pull-right {\r\n\r\n  float: right;\r\n\r\n}\r\n\r\n.pull-left {\r\n\r\n  float: left;\r\n\r\n}\r\n\r\n.fa.pull-left {\r\n\r\n  margin-right: .3em;\r\n\r\n}\r\n\r\n.fa.pull-right {\r\n\r\n  margin-left: .3em;\r\n\r\n}\r\n\r\n.fa-spin {\r\n\r\n  -webkit-animation: fa-spin 2s infinite linear;\r\n\r\n  animation: fa-spin 2s infinite linear;\r\n\r\n}\r\n\r\n.fa-pulse {\r\n\r\n  -webkit-animation: fa-spin 1s infinite steps(8);\r\n\r\n  animation: fa-spin 1s infinite steps(8);\r\n\r\n}\r\n\r\n@-webkit-keyframes fa-spin {\r\n\r\n  0% {\r\n\r\n    -webkit-transform: rotate(0deg);\r\n\r\n    transform: rotate(0deg);\r\n\r\n  }\r\n\r\n  100% {\r\n\r\n    -webkit-transform: rotate(359deg);\r\n\r\n    transform: rotate(359deg);\r\n\r\n  }\r\n\r\n}\r\n\r\n@keyframes fa-spin {\r\n\r\n  0% {\r\n\r\n    -webkit-transform: rotate(0deg);\r\n\r\n    transform: rotate(0deg);\r\n\r\n  }\r\n\r\n  100% {\r\n\r\n    -webkit-transform: rotate(359deg);\r\n\r\n    transform: rotate(359deg);\r\n\r\n  }\r\n\r\n}\r\n\r\n.fa-rotate-90 {\r\n\r\n  -ms-filter: \"progid:DXImageTransform.Microsoft.BasicImage(rotation=1)\";\r\n\r\n  -webkit-transform: rotate(90deg);\r\n\r\n  -ms-transform: rotate(90deg);\r\n\r\n  transform: rotate(90deg);\r\n\r\n}\r\n\r\n.fa-rotate-180 {\r\n\r\n  -ms-filter: \"progid:DXImageTransform.Microsoft.BasicImage(rotation=2)\";\r\n\r\n  -webkit-transform: rotate(180deg);\r\n\r\n  -ms-transform: rotate(180deg);\r\n\r\n  transform: rotate(180deg);\r\n\r\n}\r\n\r\n.fa-rotate-270 {\r\n\r\n  -ms-filter: \"progid:DXImageTransform.Microsoft.BasicImage(rotation=3)\";\r\n\r\n  -webkit-transform: rotate(270deg);\r\n\r\n  -ms-transform: rotate(270deg);\r\n\r\n  transform: rotate(270deg);\r\n\r\n}\r\n\r\n.fa-flip-horizontal {\r\n\r\n  -ms-filter: \"progid:DXImageTransform.Microsoft.BasicImage(rotation=0, mirror=1)\";\r\n\r\n  -webkit-transform: scale(-1, 1);\r\n\r\n  -ms-transform: scale(-1, 1);\r\n\r\n  transform: scale(-1, 1);\r\n\r\n}\r\n\r\n.fa-flip-vertical {\r\n\r\n  -ms-filter: \"progid:DXImageTransform.Microsoft.BasicImage(rotation=2, mirror=1)\";\r\n\r\n  -webkit-transform: scale(1, -1);\r\n\r\n  -ms-transform: scale(1, -1);\r\n\r\n  transform: scale(1, -1);\r\n\r\n}\r\n\r\n:root .fa-rotate-90,\r\n\r\n:root .fa-rotate-180,\r\n\r\n:root .fa-rotate-270,\r\n\r\n:root .fa-flip-horizontal,\r\n\r\n:root .fa-flip-vertical {\r\n\r\n  filter: none;\r\n\r\n}\r\n\r\n.fa-stack {\r\n\r\n  position: relative;\r\n\r\n  display: inline-block;\r\n\r\n  width: 2em;\r\n\r\n  height: 2em;\r\n\r\n  line-height: 2em;\r\n\r\n  vertical-align: middle;\r\n\r\n}\r\n\r\n.fa-stack-1x,\r\n\r\n.fa-stack-2x {\r\n\r\n  position: absolute;\r\n\r\n  left: 0;\r\n\r\n  width: 100%;\r\n\r\n  text-align: center;\r\n\r\n}\r\n\r\n.fa-stack-1x {\r\n\r\n  line-height: inherit;\r\n\r\n}\r\n\r\n.fa-stack-2x {\r\n\r\n  font-size: 2em;\r\n\r\n}\r\n\r\n.fa-inverse {\r\n\r\n  color: #ffffff;\r\n\r\n}\r\n\r\n/* Font Awesome uses the Unicode Private Use Area (PUA) to ensure screen\r\n\r\n   readers do not read off random characters that represent icons */\r\n\r\n.fa-glass:before {\r\n\r\n  content: \"\\f000\";\r\n\r\n}\r\n\r\n.fa-music:before {\r\n\r\n  content: \"\\f001\";\r\n\r\n}\r\n\r\n.fa-search:before {\r\n\r\n  content: \"\\f002\";\r\n\r\n}\r\n\r\n.fa-envelope-o:before {\r\n\r\n  content: \"\\f003\";\r\n\r\n}\r\n\r\n.fa-heart:before {\r\n\r\n  content: \"\\f004\";\r\n\r\n}\r\n\r\n.fa-st