INSERT INTO `cms_layout_templates` (`id`, `name`, `content`, `description`, `type_id`, `type_dflt`, `category_id`, `owner_id`, `listable`, `created`, `modified`) VALUES
(2, 'Minimal', '{process_pagedata}\n<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\"\n\"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\n\n<html xmlns=\"http://www.w3.org/1999/xhtml\" xml:lang=\"en\" lang=\"en\">\n{* Change lang=\"en\" to the language of your site *}\n\n<head>\n\n<title>{sitename} - {title}</title>\n{* The sitename is changed in Site Admin/Global settings. {title} is the name of each page *}\n\n{metadata}\n{* Don\\\'t remove this! Metadata is entered in Site Admin/Global settings. *}\n\n{cms_stylesheet}\n{* This is how all the stylesheets attached to this template are linked to *}\n\n</head>\n\n<body>\n\n      {* Start Navigation *}\n      <div style=\"float: left; width: 25%;\">\n         {Navigator loadprops=0 template=\'minimal_menu\'}\n      </div>\n      {* End Navigation *}\n\n      {* Start Content *}\n      <div>\n         <h2>{title}</h2>\n         {content} \n      </div>\n      {* End Content *}\n\n</body>\n</html>', 'A Simple, minimal page template', 1, NULL, NULL, 1, 1, 1642391015, 1642391015),
(46, 'MAMS lost username form', '{* lost username confirm template form *}\n<h4>{$mod->Lang(\'title_lostusername\')}</h4>\n<div class=\"alert alert-info\">{$mod->Lang(\'info_lostusername\')}</div>\n{if isset($message)}<div class=\"alert alert-danger\">{$message}</div>{/if}\n{if count($controls)}\n  {$startform}\n    <input type=\"hidden\" name=\"{$actionid}mams__data\" value=\"\"/>{* simple honeypot captcha *}\n    {foreach from=$controls item=\'entry\'}\n       <div class=\"row\">\n          <div class=\"col-sm-4 text-right\">{$entry->prompt}</div>\n          <div class=\"col-sm-8\">\n	    {if $entry->type == \'_password\'}\n	      <input type=\"password\" name=\"{$entry->fldname}\" value=\"{$entry->val}\" size=\"{$entry->length}\" maxlength=\"{$entry->maxlength}\"/>\n	      <br/>{$mod->Lang(\'info_lostun_pwfield\')}\n	    {else if $entry->type == 0}\n	      {* text *}\n	      <input type=\"text\" name=\"{$entry->fldname}\" value=\"{$entry->val}\" size=\"{$entry->length}\" maxlength=\"{$entry->maxlength}\"/>\n	      <br/>{$mod->Lang(\'info_lostun_textfield\')}\n	    {elseif $entry->type == 1}\n	      {* checkbox *}\n	      <input type=\"checkbox\" name=\"{$entry->fldname}\" value=\"1\" {if $entry->val}checked{/if}/>\n	    {elseif $entry->type == 2}\n	      {* email *}\n	      <input type=\"email\" name=\"{$entry->fldname}\" value=\"{$entry->val}\" size=\"{$entry->length}\" maxlength=\"{$entry->maxlength}\"/>\n	    {elseif $entry->type == 3}\n	      {* textarea *}\n	      <textarea name=\"{$entry->fldname}\" rows=\"3\" cols=\"50\">{$entry->val}</textarea>\n	      <br/>{$mod->Lang(\'info_lostun_textarea\')}\n	    {elseif $entry->type == 4}\n	      {* dropdown *}\n	      <select name=\"{$entry->fldname}\">\n	        <option value=\"\">{$mod->Lang(\'donotknow\')}</option>\n		{html_options options=$entry->options selected=$entry->val}\n	      </select>\n	    {elseif $entry->type == 5}\n	      {* multiselect *}\n	      <select name=\"{$entry->fldname}[]\" multiple size=\"{$entry->length}\">\n		{html_options options=$entry->options selected=$entry->val}\n	      </select>\n	    {elseif $entry->type == 7}\n	      {* radiobtns *}\n	      {foreach $entry->options as $key => $val}\n	        <label><input type=\"radio\" name=\"{$entry->fldname}\" value=\"{$key}\" {if $key == $entry->val}checked{/if}/> {$val}</label>\n	        {if !$val@last}<br/>{/if}\n	      {/foreach}\n	    {elseif $entry->type == 8}\n	      {* date *}\n	      {html_select_date prefix=$entry->fldname start_year=$entry->start_year end_year=$entry->end_year time=$entry->val all_empty=\'--\'}\n	    {/if}\n	  </div>\n       </div>\n    {/foreach}\n    {if isset($captcha)}\n      <div class=\"row\">\n        <p class=\"col-sm-4 text-right\">{$captcha_title}</p>\n        <div class=\"col-sm-8\">{$captcha}\n          {if $need_captcha_input}\n          <div class=\"row col-sm-12\">\n            <input type=\"text\" name=\"{$actionid}mams_input_captcha\" size=\"10\"/>\n          </div>\n          {/if}\n	</div>\n      </div>\n    {/if}\n    <div class=\"row\">\n      <div class=\"col-sm-4 text-right\"></div>\n      <div class=\"col-sm-8\">\n        <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n        <input type=\"submit\" name=\"{$actionid}mams_cancel\" value=\"{$mod->Lang(\'cancel\')}\"/>\n      </div>\n    </div>\n  {$endform}\n{/if}', NULL, 24, 1, NULL, 1, 1, 1648091132, 1648091132),
(47, 'MAMS lost username confirm', '{* lost username confirm template form *}\n<h3>{$premsg}</h3>\n<p>{$prompt_yourusernameis}: <strong>{$username}</strong>.</p>\n<p>{$postmsg}</p>', NULL, 25, 1, NULL, 1, 1, 1648091132, 1648091132),
(48, 'MAMS view user', '{* view user template *}\n<p>{$mod->Lang(\'id\')}:&nbsp;{$userinfo.id}</p>\n<p>{$mod->Lang(\'username\')}:&nbsp;{$userinfo.username}</p>\n<p>{$mod->Lang(\'email\')}:&nbsp;<a href=\"mailto:{$email_address}\">{$email_address}</p>\n<p>{$mod->Lang(\'expires\')}:&nbsp;{$userinfo.expires}</p>\n{foreach from=$user_properties item=\'entry\'}\n{if $entry.type != 0}\n<p>{$entry.prompt}:&nbsp;{$entry.data}</p>\n{/if}\n{/foreach}', NULL, 26, 1, NULL, 1, 1, 1648091132, 1648091132),
(49, 'MAMS reset session', '{* reset session template *}\n{* NOTE: this template requires jquery be available in any page that it is used on *}\n\n<p><a href=\"javascript:;\" name=\"mams_manual_reset\">Click Here To Confirm Login Status</a></p>{* safe to remove this *}\n\n{* style information for the modal window and the mask... these can be removed and placed in a CMSMS stylesheet *}\n{literal}\n<style type=\"text/css\">\nmams_modal {\n  background-color: #fff;\n  border: 1px solid #00f;\n  padding: 2px;\n  margin:  2px;\n}\n#mams_mask {\n  background-color: #000;\n}\n#mams_modal .title {\n  background-color: #00f;\n  color:  #fff;\n  padding: 0px;\n}\n</style>\n{/literal}\n\n{capture assign=\'mams_theform\'}{strip}\n{* the reset-session form, a simple form to display a message with a title to the user with two options... okay, and cancel... the name of these buttons is important, as well the strip tag is important *}\n<form action=\"javascript:;\">\n<p class=\"title\">{$mod->Lang(\'title_reset_session\')}</p>\n<p class=\"row\">{$mod->Lang(\'msg_reset_session\')}</p>\n<p class=\"row\">\n  <input type=\"submit\" name=\"mams_ok\" value=\"{$mod->Lang(\'ok\')}\"/>\n  <input type=\"submit\" name=\"mams_cancel\" value=\"{$mod->Lang(\'cancel\')}\"/>\n</p>\n</form>\n{/strip}{/capture}\n\n{literal}\n<script type=\"text/javascript\">\n//<![CDATA[\n// the timer interval (how often you want to display the dialog to your users\nvar timer_interval = {/literal}{$session_timeout}{literal} - 30;\n\n// a function to hide the modal dialog -- you can modify this function\nfunction mams_close_modal()\n{\n   jQuery(\'#mams_modal\').fadeOut(2000);\n   jQuery(\'#mams_mask\').fadeOut(1000);\n}\n\n// a function to display the modal dialog... you can modify this function\nfunction mams_open_modal()\n{\n  var maskHeight = jQuery(document).height();\n  var maskWidth = jQuery(document).width();\n\n  // set the mask size to fill up the whole screen\n  jQuery(\'#mams_mask\').css({\'width\':maskWidth,\'height\':maskHeight});\n\n  // transition effect\n  jQuery(\'#mams_mask\').fadeIn(1000);\n  jQuery(\'#mams_mask\').fadeTo(\"slow\",0.8);\n\n  // get the top left corner of the popup\n  var winHeight = jQuery(window).height();\n  var winWidth = jQuery(window).width();\n\n  var popupHeight = jQuery(\'#mams_modal\').height();\n  var popupWidth  = jQuery(\'#mams_modal\').width();\n\n  var top = winHeight/2 - popupHeight/2;\n  var left = winWidth/2 - popupWidth/2;\n  // set the popup window to center\n  jQuery(\'#mams_modal\').css({\'top\':top,\'left\':left});\n\n  // transition effect\n  jQuery(\'#mams_modal\').fadeIn(2000);\n}\n\nfunction mams_user_cancelled()\n{\n  // a callback function that may be customized to allow displaying a message to the user\n  // to indicate that they may be logged out at any time.\n  alert(\'You have chosen to disregard the session warning, you may continue to browse this site however some functionality may be unavailable to you until you login again\');\n}\n\n// *\n// * do not modify below here unless you are an experienced jquery programmer *\n// *\n\nif( timer_interval <= 0 )\n  {\n     timer_interval = 0;\n  }\nvar dialogcontents = \'{/literal}{$mams_theform}{literal}\';\n\n\n// we have jQuery\njQuery(document).ready(function(){\n  // create a new id for our stuff\n  jQuery(\'body\').append(\'<div id=\"mams_body\"></div>\');\n  \n  // create the mask and append it to the dom\n  jQuery(\'#mams_body\').append(\'<div id=\"mams_mask\"></div>\');\n\n  // create the modal dialog and append it to the DOM\n  jQuery(\'#mams_body\').append(\'<div id=\"mams_modal\">\'+dialogcontents+\'</div>\');\n  \n  // and a junk div\n  jQuery(\'#mams_body\').append(\'<div id=\"mams_junk\" style=\"display: none;\"></div>\');\n\n  // handle click events\n  jQuery(\'#mams_modal input[name=mams_ok]\').click(function(e){\n    e.preventDefault();\n\n    // do the ajax request\n    var url = \'{/literal}{$reset_url}{literal}\';\n    var url = url.replace(/amp;/g,\'\');\n    jQuery(\'#mams_junk\').load(url);\n\n    // and done.\n    #mams_close_modal();\n   });\n  jQuery(\'#mams_modal input[name=mams_cancel]\').click(function(e){\n    e.preventDefault();\n    #mams_close_modal();\n    #mams_user_cancelled();\n  });\n  jQuery(\'a[name=mams_manual_reset]\').click(function(e){\n    e.preventDefault();\n    mams_open_modal();\n  });\n\n  // create our timer\n  if( timer_interval > 0 )\n     {\n        setTimeout(mams_open_modal,timer_interval * 1000);\n     }\n\n});\n//]]>\n</script>\n{/literal}\n\n{* required css *}\n{literal}\n<style type=\"text/css\">\n#mams_modal {\n  position: absolute;\n  z-index: 9999;\n  display: none;\n}\n#mams_mask {\n  top: 0;\n  left: 0;\n  position: absolute;\n  z-index: 9000;\n  display: none;\n}\n</style>\n{/literal}', NULL, 27, 1, NULL, 1, 1, 1648091132, 1648091132),
(50, 'MAMS verify_form', '{* original verification form *}\n<div class=\"alert alert-info\">{$mod->Lang(\'info_verify_identity2\')}</div>\n{form_start uid=$uid}{xt_form_csrf}\n  <div class=\"row\">\n    <label>{$mod->Lang(\'code\')}: <input type=\"text\" class=\"form_control\" name=\"{$actionid}code\" value=\"{$code}\" required/></label>\n  </div>\n  <div class=\"row\">\n    <button type=\"submit\" name=\"{$actionid}mams_submit\" class=\"btn btn_active\">{$mod->Lang(\'verify\')}</button>\n  </div>\n</div>\n{form_end}', NULL, 28, 1, NULL, 1, 1, 1648091132, 1648091132),
(51, 'mams-gps-login', '{* login form template *}\r\n{* this is a sample template, feel free to customize it *}\r\n{if isset($alt_loginform)}\r\n  <div class=\"row\" id=\"altlogin\">{$alt_loginform}</div><br/>\r\n{/if}\r\n\r\n<fieldset id=\"loginform\">\r\n  <legend>{$MAMS->Lang(\'prompt_normallogin\')}:</legend>\r\n  {$startform}{xt_form_csrf}\r\n\r\n  {*\r\n   * a simple honeypot captcha....if this field has a value after submit an error will be thrown\r\n   * deleting this field will simply disable the honeypot.\r\n   * it is important that the field be hidden with CSS rather than using a hidden input field.\r\n   *}\r\n  <input type=\"text\" name=\"{$actionid}mams__data\" value=\"\" style=\"display: none;\"/>\r\n\r\n  {if $error}<div class=\"alert alert-danger\">{$error}</div>{/if}\r\n\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4 text-right\"><label for=\"mams_username\">*{$prompt_username}:</label></p>\r\n    <p class=\"col-md-8\">\r\n      <input type=\"{if $username_is_email}email{else}text{/if}\" id=\"mams_username\" name=\"{$fldname_username}\" value=\"{$username}\" size=\"{$username_size}\" maxlength=\"{$username_maxlength}\" {if !$username_is_email}autocorrect=\"off\" autocapitalize=\"off\"{/if} required/>\r\n    </p>\r\n  </div>\r\n\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4 text-right\"><label for=\"mams_password\">*{$prompt_password}:</label></p>\r\n    <p class=\"col-md-8\">\r\n      <input type=\"password\" id=\"mams_password\" name=\"{$fldname_password}\" value=\"{$password}\" size=\"{$password_size}\" maxlength=\"{$password_maxlength}\" required/>\r\n    </p>\r\n  </div>\r\n\r\n  {if isset($captcha)}\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4 text-right\">{$captcha_title}</p>\r\n    <div class=\"col-md-8\">{$captcha}\r\n      {if $need_captcha_input}\r\n      <div class=\"row\">\r\n        <input type=\"text\" name=\"{$actionid}mams_input_captcha\" size=\"10\"/>\r\n      </div>\r\n      {/if}\r\n    </div>\r\n  </div>\r\n  {/if}\r\n\r\n  {if isset($prompt_rememberme)}\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4\"></p>\r\n    <p class=\"col-md-8\">\r\n      <label><input type=\"checkbox\" name=\"{$actionid}mams_rememberme\" value=\"1\" {if $rememberme==1}checked{/if}/> {$prompt_rememberme}</label>\r\n    </p>\r\n  </div>\r\n  {/if}\r\n\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4\"></p>\r\n    <p class=\"col-md-8\">\r\n      <button class=\"btn btn-active\" name=\"{$actionid}mams_submit\">{$MAMS->Lang(\'login\')}</button>\r\n    </p>\r\n  </div>\r\n\r\n  {if isset($url_lostun) || isset($url_forgot)}\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4\"></p>\r\n    <p class=\"col-sm-8\">\r\n      {if isset($url_forgot)}\r\n        <a href=\"{$url_forgot}\" title=\"{$MAMS->Lang(\'info_forgotpw\')}\">{$MAMS->Lang(\'forgotpw\')}</a>\r\n      {/if}\r\n      {if isset($url_lostun)}\r\n        | <a href=\"{$url_lostun}\" title=\"{$MAMS->Lang(\'info_lostun\')}\">{$MAMS->Lang(\'lostusername\')}</a>\r\n      {/if}\r\n    </p>\r\n  </div>\r\n  {/if}\r\n  {$endform}\r\n</fieldset>', '', 17, 1, NULL, 1, 1, 1648093285, 1648093310),
(52, 'mams-gps-change-settings', '<!-- change settings template -->\r\n<div id=\"mams_changesettingsform\">\r\n<h4>{$mod->Lang(\'user_settings\')}</h4>\r\n\r\n{if isset($message) && $message != \'\'}\r\n  {if isset($error) && $error != \'\'}\r\n    <p class=\"alert alert-error\">{$message}</p>\r\n  {else}\r\n    <p class=\"alert alert-info\">{$message}</p>\r\n  {/if}\r\n{/if}\r\n\r\n{$startform}{xt_form_csrf}\r\n  {if $controlcount > 0}\r\n  {foreach $controls as $key=>$field}\r\n    <div class=\"row\">\r\n      <label for=\"{$field->input_id}\" class=\"col-sm-3 text-right\" style=\"color: {$field->color|default:\'inherit\'}\">{$field->marker|default:\'\'} {$field->prompt}:</label>\r\n      <div class=\"col-sm-9\">\r\n        {$field->hidden|default:\'\'}\r\n        {if isset($field->hidden)}{$field->hidden}{/if}\r\n\r\n	{* build the field itself *}\r\n	{if $field->type == \'0\'} {* text *}\r\n	  <input type=\"text\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == \'password\'} {* text *}\r\n	  <input type=\"password\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == 2} {* email *}\r\n	  <input type=\"email\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == 3} {* textarea *}\r\n          {xt_textarea id=$field->input_id wysiwyg=$field->wysiwyg name=$field->input_name content=$field->value class=\"form-control\"}\r\n	{elseif $field->type == 1} {* checkbox *}\r\n	  <input type=\"hidden\" name=\"{$field->input_name}\" value=\"0\"/>\r\n	  <input type=\"checkbox\" id=\"{$field->input_id}\" class=\"checkbox\" name=\"{$field->input_name}\" value=\"1\" {if $field->value}checked{/if}/>\r\n	{elseif $field->type == 4} {* dropdown *}\r\n	   <select id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" {if $field->readonly}readonly{/if}>\r\n	      {html_options options=$field->options selected=$field->value}\r\n	   </select>\r\n	{elseif $field->type == 5} {* multiselect *}\r\n	   <select id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}[]\" {if $field->readonly}readonly{/if} multiple>\r\n	      {html_options options=$field->options selected=$field->selected}\r\n	   </select>\r\n	{elseif $field->type == 7} {* radio group *}\r\n	   {foreach $field->options as $key => $val}\r\n	      <label><input type=\"radio\" class=\"form-control\" name=\"{$field->input_name}\" value=\"{$key}\" {if $key==$field->value}checked=\"checked\"{/if}> {$val}</label>\r\n	   {/foreach}\r\n	{elseif $field->type == 6} {* image *}\r\n	   {if isset($field->image_url) && $field->image_url}<img src=\"{$field->image_url}\" alt=\"{$field->image_url}\" width=\"100\" height=\"100\"/>{/if}\r\n	   {if isset($field->prompt2) && $field->prompt2}<label><input type=\"checkbox\" class=\"checkbox\" name=\"{$field->input_name2}\" value=\"clear\"/> {$field->prompt2}</label>{/if}\r\n	   <input type=\"hidden\" name=\"{$field->input_name}\" value=\"{$field->value}\"/>\r\n 	   <input type=\"file\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == 8} {* date *}\r\n	   {$sy=$field->startyear|default:\'-5\'}\r\n	   {$ey=$field->startyear|default:\'+10\'}\r\n	   {html_select_date prefix=$field->input_name start_year=$sy end_year=$ey time=$field->value}\r\n	{/if}\r\n        {$field->addtext|default:\'\'}\r\n      </div>\r\n    </div>\r\n  {/foreach}\r\n  {/if}\r\n\r\n  <div class=\"row\">\r\n    <div class=\"col-sm-3\"></div>\r\n    <div class=\"col-sm-9\">\r\n      <button type=\"submit\" class=\"btn btn_active\" name=\"{$actionid}submit\">{$mod->Lang(\'submit\')}</button>\r\n    </div>\r\n  </div>\r\n{$hidden|default:\'\'}{$endform}\r\n</div>\r\n<!-- change settings template -->', '', 19, 1, NULL, 1, 1, 1648162347, 1648162347),
(53, 'mams-gps-forgot-password', '{* forgot password template *}\r\n<h4>{$mod->Lang(\'title_forgotpw\')}</h4>\r\n{if !empty($message) }\r\n  {if !empty($error) }\r\n    <div class=\"alert alert-danger\">{$message}</div>\r\n  {else}\r\n    <div class=\"alert alert-info\">{$message}</div>\r\n  {/if}\r\n{else}\r\n  <div class=\"alert alert-info\">{$mod->Lang(\'lostpw_message\')}</div>\r\n{/if}\r\n\r\n{if !isset($forgotpwdone)}\r\n  {if isset($startform)}\r\n    {$startform}{xt_form_csrf}\r\n    <div class=\"row\">\r\n      <div class=\"col-sm-2 text-right\">\r\n        {if $username_is_email}\r\n          {$mod->Lang(\'prompt_email\')}:\r\n        {else}\r\n          {$mod->Lang(\'prompt_username\')}:\r\n        {/if}\r\n      </div>\r\n      <div class=\"col-sm-10\">\r\n        <input name=\"{$actionid}mams_username\" type=\"{if $username_is_email}email{else}text{/if}\" size=\"{$unfldlen}\" maxlength=\"{$max_unfldlen}\" value=\"{$username}\" required/> *\r\n      </div>\r\n    </div>\r\n    {if isset($captcha)}\r\n    <div class=\"row\">\r\n      <div class=\"col-sm-2 text-right\">{$captcha_title}:</div>\r\n      <div class=\"col-sm-10\">{$captcha}\r\n        {if isset($input_captcha)}<div class=\"row\">{$input_captcha}</p>{/if}\r\n      </div>\r\n    </div>\r\n    {/if}\r\n    <div class=\"row\">\r\n      <div class=\"col-sm-10 col-sm-offset-2\">\r\n        <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\r\n        <input id=\"mams_cancel\" type=\"submit\" name=\"{$actionid}mams_cancel\" value=\"{$mod->Lang(\'cancel\')}\" formnovalidate/>\r\n      </div>\r\n    </div>\r\n    {$endform}\r\n  {/if}\r\n{/if}', '', 20, 1, NULL, 1, 1, 1648188383, 1648188424),
(54, 'gps_sidebar', '{* simple navigation *}\r\n{* note, function can only be defined once *}\r\n{* \r\n  variables:\r\n  node: contains the current node.\r\n  aclass: is used to build a string containing class names given to the a tag if one is used\r\n  liclass: is used to build a string containing class names given to the li tag.\r\n*}\r\n\r\n{function name=Nav_menu depth=1}{strip}\r\n<ul>\r\n  {foreach $data as $node}\r\n    {* setup classes for the anchor and list item *}\r\n    {assign var=\'liclass\' value=\'menudepth\'|cat:$depth}\r\n    {assign var=\'aclass\' value=\'\'}\r\n\r\n    {* the first child gets a special class *}\r\n    {if $node@first && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' first_child\'}{/if}\r\n\r\n    {* the last child gets a special class *}\r\n    {if $node@last && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' last_child\'}{/if}\r\n\r\n    {if $node->current}\r\n      {* this is the current page *}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive\'}\r\n    {/if}\r\n\r\n    {if $node->parent}\r\n      {* this is a parent of the current page *}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive menuparent\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive menuparent\'}\r\n    {/if}\r\n\r\n    {if $node->children_exist}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' parent\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' parent\'}\r\n    {/if}\r\n\r\n    {* build the menu item node *}\r\n    {if $node->type == \'sectionheader\'}\r\n      <li class=\'sectionheader {$liclass}\'><span>{$node->menutext}</span>\r\n        {if isset($node->children)}\r\n          {Nav_menu data=$node->children depth=$depth+1}\r\n        {/if}\r\n      </li>\r\n    {else if $node->type == \'separator\'}\r\n      <li class=\'separator {$liclass}\'><hr class=\'separator\'/></li>\r\n    {else}\r\n      {* regular item *}\r\n      <li class=\"{$liclass}\">\r\n        <a class=\"{$aclass}\" href=\"{$node->url}\" title=\"{$node->menutext}\" {if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\r\n        {if isset($node->children)}\r\n          {Nav_menu data=$node->children depth=$depth+1}\r\n        {/if}\r\n      </li>\r\n    {/if}\r\n  {/foreach}\r\n</ul>\r\n{/strip}{/function}\r\n\r\n{if isset($nodes)}\r\n{Nav_menu data=$nodes depth=0}\r\n{/if}', '', 4, 0, NULL, 1, 1, 1648362504, 1648362534),
(55, 'gps_one_column', '{extends file=\'cms_template:gps_default\'}\r\n\r\n{block name=\'hero\'}\r\n{if $header_img}\r\n  <section class=\"hero\" style=\"background-image: url({$header_img});\" data-stellar-background-ratio=\"0.5\">{else}\r\n  <section class=\"hero\" style=\"background-image: url(https://ik.imagekit.io/webtactics/gloucester-pre-school/images/pages/header/generic-preschool-5.jpg);\" data-stellar-background-ratio=\"0.5\">{/if}\r\n  <div class=\"row\">\r\n  <div class=\"small-12 columns\">\r\n  <div class=\"caption-text\">\r\n  <h1><span>Gloucester Pre-School &</span><br/><span>Early Years Learning Centre</span></h1></div>\r\n  </div>\r\n  </div>\r\n  </section>\r\n  {/block}\r\n\r\n\r\n\r\n{block name=\'hero_black\'}\r\n<section class=\"hero\">\r\n<div class=\"row\">\r\n<div class=\"small-12 medium-9 medium-centered columns\">\r\n\r\n{$main_content|strip}\r\n\r\n</div>\r\n</section>\r\n{/block}\r\n{block name=\'content\'}\r\n    <section class=\"homecontent\">\r\n    <div class=\"row\">\r\n<div class=\"small-12 columns\">\r\n    {$main_content|strip}\r\n</div></div>\r\n    </section>\r\n{/block}\r\n', '', 1, 0, NULL, 1, 1, 1648609317, 1648609317),
(58, 'pag_menu', '{* simple navigation *}\r\n{* note, function can only be defined once *}\r\n{* \r\n  variables:\r\n  node: contains the current node.\r\n  aclass: is used to build a string containing class names given to the a tag if one is used\r\n  liclass: is used to build a string containing class names given to the li tag.\r\n*}\r\n\r\n{function name=Nav_menu depth=1}{strip}\r\n<ul>\r\n  {foreach $data as $node}\r\n    {* setup classes for the anchor and list item *}\r\n    {assign var=\'liclass\' value=\'menudepth\'|cat:$depth}\r\n    {assign var=\'aclass\' value=\'\'}\r\n\r\n    {* the first child gets a special class *}\r\n    {if $node@first && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' first_child\'}{/if}\r\n\r\n    {* the last child gets a special class *}\r\n    {if $node@last && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' last_child\'}{/if}\r\n\r\n    {if $node->current}\r\n      {* this is the current page *}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive\'}\r\n    {/if}\r\n\r\n    {if $node->parent}\r\n      {* this is a parent of the current page *}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive menuparent\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive menuparent\'}\r\n    {/if}\r\n\r\n    {if $node->children}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' parent\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' parent\'}\r\n    {/if}\r\n\r\n    {* build the menu item node *}\r\n    {if $node->type == \'sectionheader\'}\r\n      <li class=\'sectionheader {$liclass}\'><span>{$node->menutext}</span>\r\n        {if isset($node->children)}\r\n          {Nav_menu data=$node->children depth=$depth+1}\r\n        {/if}\r\n      </li>\r\n    {else if $node->type == \'separator\'}\r\n      <li class=\'separator {$liclass}\'><hr class=\'separator\'/></li>\r\n    {else}\r\n      {* regular item *}\r\n      <li class=\"{$liclass}\">\r\n        <a class=\"{$aclass}\" href=\"{$node->url}\"{if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\r\n        {if isset($node->children)}\r\n          {Nav_menu data=$node->children depth=$depth+1}\r\n        {/if}\r\n      </li>\r\n    {/if}\r\n  {/foreach}\r\n</ul>\r\n{/strip}{/function}\r\n\r\n{if isset($nodes)}\r\n{Nav_menu data=$nodes depth=0}\r\n{/if}', '', 4, 0, NULL, 1, 1, 1648630210, 1648630217),
(40, 'MAMS logout form', '{* logout form template *}\r\n{if isset($alt_logoutform)}{$alt_logoutform}{/if}\r\n{if isset($message)}<div class=\"alert alert-info\">{$message}</div>{/if}\r\n<p>{$prompt_loggedin}&nbsp;{$username}</p>\r\n<p><a href=\"{$url_changesettings}\" title=\"{$mod->Lang(\'info_changesettings\')}\">{$mod->Lang(\'prompt_changesettings\')}</a></p>\r\n{if isset($url_logout)}\r\n<p><a href=\"{$url_logout}\" title=\"{$mod->Lang(\'info_logout\')}\">{$mod->Lang(\'logout\')}</a></p>\r\n{/if}', '', 18, 0, NULL, 1, 1, 1648091132, 1648618950),
(41, 'MAMS chsettings form', '<!-- change settings template -->\r\n<div id=\"mams_changesettingsform\">\r\n<h4>{$mod->Lang(\'user_settings\')}</h4>\r\n\r\n{if isset($message) && $message != \'\'}\r\n  {if isset($error) && $error != \'\'}\r\n    <p class=\"alert alert-error\">{$message}</p>\r\n  {else}\r\n    <p class=\"alert alert-info\">{$message}</p>\r\n  {/if}\r\n{/if}\r\n\r\n{$startform}{xt_form_csrf}\r\n  {if $controlcount > 0}\r\n  {foreach $controls as $key=>$field}\r\n    <div class=\"row\">\r\n      <label for=\"{$field->input_id}\" class=\"col-sm-3 text-right\" style=\"color: {$field->color|default:\'inherit\'}\">{$field->marker|default:\'\'} {$field->prompt}:</label>\r\n      <div class=\"col-sm-9\">\r\n        {$field->hidden|default:\'\'}\r\n        {if isset($field->hidden)}{$field->hidden}{/if}\r\n\r\n	{* build the field itself *}\r\n	{if $field->type == \'0\'} {* text *}\r\n	  <input type=\"text\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == \'password\'} {* text *}\r\n	  <input type=\"password\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == 2} {* email *}\r\n	  <input type=\"email\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == 3} {* textarea *}\r\n          {xt_textarea id=$field->input_id wysiwyg=$field->wysiwyg name=$field->input_name content=$field->value class=\"form-control\"}\r\n	{elseif $field->type == 1} {* checkbox *}\r\n	  <input type=\"hidden\" name=\"{$field->input_name}\" value=\"0\"/>\r\n	  <input type=\"checkbox\" id=\"{$field->input_id}\" class=\"checkbox\" name=\"{$field->input_name}\" value=\"1\" {if $field->value}checked{/if}/>\r\n	{elseif $field->type == 4} {* dropdown *}\r\n	   <select id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" {if $field->readonly}readonly{/if}>\r\n	      {html_options options=$field->options selected=$field->value}\r\n	   </select>\r\n	{elseif $field->type == 5} {* multiselect *}\r\n	   <select id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}[]\" {if $field->readonly}readonly{/if} multiple>\r\n	      {html_options options=$field->options selected=$field->selected}\r\n	   </select>\r\n	{elseif $field->type == 7} {* radio group *}\r\n	   {foreach $field->options as $key => $val}\r\n	      <label><input type=\"radio\" class=\"form-control\" name=\"{$field->input_name}\" value=\"{$key}\" {if $key==$field->value}checked=\"checked\"{/if}> {$val}</label>\r\n	   {/foreach}\r\n	{elseif $field->type == 6} {* image *}\r\n	   {if isset($field->image_url) && $field->image_url}<img src=\"{$field->image_url}\" alt=\"{$field->image_url}\" width=\"100\" height=\"100\"/>{/if}\r\n	   {if isset($field->prompt2) && $field->prompt2}<label><input type=\"checkbox\" class=\"checkbox\" name=\"{$field->input_name2}\" value=\"clear\"/> {$field->prompt2}</label>{/if}\r\n	   <input type=\"hidden\" name=\"{$field->input_name}\" value=\"{$field->value}\"/>\r\n 	   <input type=\"file\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" {if $field->readonly}readonly{/if}/>\r\n	{elseif $field->type == 8} {* date *}\r\n	   {$sy=$field->startyear|default:\'-5\'}\r\n	   {$ey=$field->startyear|default:\'+10\'}\r\n	   {html_select_date prefix=$field->input_name start_year=$sy end_year=$ey time=$field->value}\r\n	{/if}\r\n        {$field->addtext|default:\'\'}\r\n      </div>\r\n    </div>\r\n  {/foreach}\r\n  {/if}\r\n\r\n  <div class=\"row\">\r\n    <div class=\"col-sm-3\"></div>\r\n    <div class=\"col-sm-9\">\r\n      <button type=\"submit\" class=\"btn btn_active\" name=\"{$actionid}submit\">{$mod->Lang(\'submit\')}</button>\r\n    </div>\r\n  </div>\r\n{$hidden|default:\'\'}{$endform}\r\n</div>\r\n<!-- change settings template -->', '', 19, 0, NULL, 1, 1, 1648091132, 1648162287),
(42, 'MAMS forgot password form', '{* forgot password template *}\r\n<h4>{$mod->Lang(\'title_forgotpw\')}</h4>\r\n{if !empty($message) }\r\n  {if !empty($error) }\r\n    <div class=\"alert alert-danger\">{$message}</div>\r\n  {else}\r\n    <div class=\"alert alert-info\">{$message}</div>\r\n  {/if}\r\n{else}\r\n  <div class=\"alert alert-info\">{$mod->Lang(\'lostpw_message\')}</div>\r\n{/if}\r\n\r\n{if !isset($forgotpwdone)}\r\n  {if isset($startform)}\r\n    {$startform}{xt_form_csrf}\r\n    <div class=\"row\">\r\n      <div class=\"col-sm-2 text-right\">\r\n        {if $username_is_email}\r\n          {$mod->Lang(\'prompt_email\')}:\r\n        {else}\r\n          {$mod->Lang(\'prompt_username\')}:\r\n        {/if}\r\n      </div>\r\n      <div class=\"col-sm-10\">\r\n        <input name=\"{$actionid}mams_username\" type=\"{if $username_is_email}email{else}text{/if}\" size=\"{$unfldlen}\" maxlength=\"{$max_unfldlen}\" value=\"{$username}\" required/> *\r\n      </div>\r\n    </div>\r\n    {if isset($captcha)}\r\n    <div class=\"row\">\r\n      <div class=\"col-sm-2 text-right\">{$captcha_title}:</div>\r\n      <div class=\"col-sm-10\">{$captcha}\r\n        {if isset($input_captcha)}<div class=\"row\">{$input_captcha}</p>{/if}\r\n      </div>\r\n    </div>\r\n    {/if}\r\n    <div class=\"row\">\r\n      <div class=\"col-sm-10 col-sm-offset-2\">\r\n        <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\r\n        <input id=\"mams_cancel\" type=\"submit\" name=\"{$actionid}mams_cancel\" value=\"{$mod->Lang(\'cancel\')}\" formnovalidate/>\r\n      </div>\r\n    </div>\r\n    {$endform}\r\n  {/if}\r\n{/if}', '', 20, 0, NULL, 1, 1, 1648091132, 1648188392),
(43, 'MAMS forgot password email', '{* verify email template -- formerly fogot password email template *}\n<h3>{$title}</h3>\n<div>{$message}</div>\n<h4>{$prompt_code}: {$data_code}</h4>\n<p>{$prompt_link}: <a href=\"{$data_url}\">{$data_url}</a></p>\n{/strip}', NULL, 21, 1, NULL, 1, 1, 1648091132, 1648091132),
(44, 'MAMS forgot password verify', '{* forgot password verification template *}\n<h4>{$mod->Lang(\'verify_identity\')}</h4>\n{if !empty($message)}\n  {if !empty($error) }\n    <div class=\"alert alert-danger\">{$message}</div>\n  {else}\n    <div class=\"alert alert-info\">{$message}</div>\n  {/if}\n{/if}\n\n{if isset($startform)}\n  {$startform}{xt_form_csrf}\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'prompt_username\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"{if $username_is_email}email{else}text{/if}\" name=\"{$actionid}mams_username\" size=\"{$unfldlen}\" maxlength=\"{$max_unfldlen}\" value=\"{$username}\" disabled=\"disabled\"/>\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'prompt_code\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"text\" name=\"{$actionid}mams_code\" value=\"{$code}\" size=\"40\" maxlength=\"40\" required /> *\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'prompt_password\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"password\" name=\"{$actionid}mams_password1\" value=\"{$password1}\" size=\"{$pwfldlen}\" maxlength=\"{$max_pwfldlen}\" required/> *\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'repeatpassword\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"password\" name=\"{$actionid}mams_password2\" value=\"{$password2}\" size=\"{$pwfldlen}\" maxlength=\"{$max_pwfldlen}\" required/> *\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">&nbsp;</div>\n    <div class=\"col-sm-9\">\n      <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n    </div>\n  </div>\n{$endform}\n{/if}', NULL, 22, 1, NULL, 1, 1, 1648091132, 1648091132),
(45, 'MAMS force new password', '{* system default force new password form template *}\n<div class=\"alert alert-info\">{$mod->Lang(\'msg_force_newpw\')}</div>\n\n{if isset($error)}\n<div class=\"alert alert-danger\">{$error}</div>\n{/if}\n\n{$formstart}\n<div class=\"row\">\n  <div class=\"col-xs-3 text-right\">* {$mod->Lang(\'password\')}:</div>\n  <div class=\"col-xs-9\">\n    <input type=\"password\" name=\"{$actionid}mams_password\" value=\"\" required/>\n  </div>\n</div>\n<div class=\"row\">\n  <div class=\"col-xs-3 text-right\">* {$mod->Lang(\'repeatpassword\')}:</div>\n  <div class=\"col-xs-9\">\n    <input type=\"password\" name=\"{$actionid}mams_repeatpassword\" value=\"\" required/>\n  </div>\n</div>\n<div class=\"row\">\n  <div class=\"col-xs-3\">&nbsp;</div>\n  <div class=\"col-xs-9\">\n    <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n  </div>\n</div>\n{$formend}', NULL, 23, 0, NULL, 1, 1, 1648091132, 1648091132),
(39, 'MAMS login form', '{* login form template *}\r\n{* this is a sample template, feel free to customize it *}\r\n{if isset($alt_loginform)}\r\n  <div class=\"row\" id=\"altlogin\">{$alt_loginform}</div><br/>\r\n{/if}\r\n\r\n<fieldset id=\"loginform\">\r\n  <legend>{$MAMS->Lang(\'prompt_normallogin\')}:</legend>\r\n  {$startform}{xt_form_csrf}\r\n\r\n  {*\r\n   * a simple honeypot captcha....if this field has a value after submit an error will be thrown\r\n   * deleting this field will simply disable the honeypot.\r\n   * it is important that the field be hidden with CSS rather than using a hidden input field.\r\n   *}\r\n  <input type=\"text\" name=\"{$actionid}mams__data\" value=\"\" style=\"display: none;\"/>\r\n\r\n  {if $error}<div class=\"alert alert-danger\">{$error}</div>{/if}\r\n\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4 text-right\"><label for=\"mams_username\">*{$prompt_username}:</label></p>\r\n    <p class=\"col-md-8\">\r\n      <input type=\"{if $username_is_email}email{else}text{/if}\" id=\"mams_username\" name=\"{$fldname_username}\" value=\"{$username}\" size=\"{$username_size}\" maxlength=\"{$username_maxlength}\" {if !$username_is_email}autocorrect=\"off\" autocapitalize=\"off\"{/if} required/>\r\n    </p>\r\n  </div>\r\n\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4 text-right\"><label for=\"mams_password\">*{$prompt_password}:</label></p>\r\n    <p class=\"col-md-8\">\r\n      <input type=\"password\" id=\"mams_password\" name=\"{$fldname_password}\" value=\"{$password}\" size=\"{$password_size}\" maxlength=\"{$password_maxlength}\" required/>\r\n    </p>\r\n  </div>\r\n\r\n  {if isset($captcha)}\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4 text-right\">{$captcha_title}</p>\r\n    <div class=\"col-md-8\">{$captcha}\r\n      {if $need_captcha_input}\r\n      <div class=\"row\">\r\n        <input type=\"text\" name=\"{$actionid}mams_input_captcha\" size=\"10\"/>\r\n      </div>\r\n      {/if}\r\n    </div>\r\n  </div>\r\n  {/if}\r\n\r\n  {if isset($prompt_rememberme)}\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4\"></p>\r\n    <p class=\"col-md-8\">\r\n      <label><input type=\"checkbox\" name=\"{$actionid}mams_rememberme\" value=\"1\" {if $rememberme==1}checked{/if}/> {$prompt_rememberme}</label>\r\n    </p>\r\n  </div>\r\n  {/if}\r\n\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4\"></p>\r\n    <p class=\"col-md-8\">\r\n      <button class=\"btn btn-active\" name=\"{$actionid}mams_submit\">{$MAMS->Lang(\'login\')}</button>\r\n    </p>\r\n  </div>\r\n\r\n  {if isset($url_lostun) || isset($url_forgot)}\r\n  <div class=\"row\">\r\n    <p class=\"col-md-4\"></p>\r\n    <p class=\"col-sm-8\">\r\n      {if isset($url_forgot)}\r\n        <a href=\"{$url_forgot}\" title=\"{$MAMS->Lang(\'info_forgotpw\')}\">{$MAMS->Lang(\'forgotpw\')}</a>\r\n      {/if}\r\n      {if isset($url_lostun)}\r\n        | <a href=\"{$url_lostun}\" title=\"{$MAMS->Lang(\'info_lostun\')}\">{$MAMS->Lang(\'lostusername\')}</a>\r\n      {/if}\r\n    </p>\r\n  </div>\r\n  {/if}\r\n  {$endform}\r\n</fieldset>', '', 17, 0, NULL, 1, 1, 1648091132, 1648093228),
(56, 'mams-logout-form', '{* logout form template *}\r\n{if isset($alt_logoutform)}{$alt_logoutform}{/if}\r\n{if isset($message)}<div class=\"alert alert-info\">{$message}</div>{/if}\r\n<p>{$prompt_loggedin}&nbsp;{$username}</p>\r\n<p><a href=\"{$url_changesettings}\" title=\"{$mod->Lang(\'info_changesettings\')}\">{$mod->Lang(\'prompt_changesettings\')}</a></p>\r\n{if isset($url_logout)}\r\n<p><a href=\"{$url_logout}\" title=\"{$mod->Lang(\'info_logout\')}\">{$mod->Lang(\'logout\')}</a></p>\r\n{/if}', '', 18, 1, NULL, 1, 1, 1648618998, 1648619014),
(57, 'gps_blog_summary', '{extends file=\'cms_template:gps_default\'}\r\n\r\n\r\n{block name=\'content\'}\r\n<section class=\"maincontent\">\r\n<div class=\"row\">\r\n<div class=\"small-12 columns\">\r\n{if $imageone}\r\n    <div class=\"page_img pad30\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-900,h-500,q-80/{$imageone}\" ></div>\r\n    {/if}\r\n  {$main_content|strip}  \r\n  {if $imagetwo}\r\n    <div class=\"page_img pad1rem two\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-800,h-600,q-80/{$imagetwo}\" ></div>\r\n    {/if}\r\n  \r\n  {if $second_content}\r\n  <div class=\"lowercontent\">{$second_content}</div>\r\n    {/if}\r\n    {if $imagethree}\r\n      <div class=\"page_img pad30 three\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-900,h-500,q-80/{$imagethree}\" ></div>\r\n      {/if}\r\n      {if $lower_content}\r\n        <div class=\"lowercontent\">{$lower_content}</div>\r\n          {/if}\r\n</div></div>\r\n</section>\r\n{/block}\r\n', '', 1, 0, NULL, 1, 1, 1648629668, 1648629668),
(14, 'Simple Navigation', '{* simple navigation *}\n{* note, function can only be defined once *}\n{* \n  variables:\n  node: contains the current node.\n  aclass: is used to build a string containing class names given to the a tag if one is used\n  liclass: is used to build a string containing class names given to the li tag.\n*}\n\n{function name=Nav_menu depth=1}{strip}\n<ul>\n  {foreach $data as $node}\n    {* setup classes for the anchor and list item *}\n    {assign var=\'liclass\' value=\'menudepth\'|cat:$depth}\n    {assign var=\'aclass\' value=\'\'}\n\n    {* the first child gets a special class *}\n    {if $node@first && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' first_child\'}{/if}\n\n    {* the last child gets a special class *}\n    {if $node@last && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' last_child\'}{/if}\n\n    {if $node->current}\n      {* this is the current page *}\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive\'}\n    {/if}\n\n    {if $node->parent}\n      {* this is a parent of the current page *}\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive menuparent\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive menuparent\'}\n    {/if}\n\n    {if $node->children}\n      {assign var=\'liclass\' value=$liclass|cat:\' parent\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' parent\'}\n    {/if}\n\n    {* build the menu item node *}\n    {if $node->type == \'sectionheader\'}\n      <li class=\'sectionheader {$liclass}\'><span>{$node->menutext}</span>\n        {if isset($node->children)}\n          {Nav_menu data=$node->children depth=$depth+1}\n        {/if}\n      </li>\n    {else if $node->type == \'separator\'}\n      <li class=\'separator {$liclass}\'><hr class=\'separator\'/></li>\n    {else}\n      {* regular item *}\n      <li class=\"{$liclass}\">\n        <a class=\"{$aclass}\" href=\"{$node->url}\"{if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\n        {if isset($node->children)}\n          {Nav_menu data=$node->children depth=$depth+1}\n        {/if}\n      </li>\n    {/if}\n  {/foreach}\n</ul>\n{/strip}{/function}\n\n{if isset($nodes)}\n{Nav_menu data=$nodes depth=0}\n{/if}', NULL, 4, 0, NULL, 1, 1, 1642391018, 1642391018),
(15, 'Breadcrumbs', '{* default breadcrumbs template *}\n{strip}\n<div class=\"breadcrumb\">\n  {if isset($starttext)}{$starttext}:&nbsp;{/if}\n  {foreach $nodelist as $node}\n    {$spanclass=\'breadcrumb\'}\n    {if $node->current}\n      {$spanclass=$spanclass|cat:\' current\'}\n    {/if}\n\n    <span class=\"{$spanclass}\">\n      {if $node@last}\n        {$node->menutext}\n      {elseif $node->type == \'sectionheader\'}\n        {$node->menutext}&nbsp;\n      {else}\n        <a href=\"{$node->url}\" title=\"{$node->menutext}\">{$node->menutext}</a>\n      {/if}\n    </span>\n\n    {if !$node@last}&raquo;&nbsp;{/if}\n  {/foreach}\n</div>\n{/strip}', NULL, 5, 1, NULL, 1, 1, 1642391018, 1642391018),
(16, 'cssmenu', '{* cssmenu *}\n{* this template uses recursion, but not a smarty function. *}\n{* \n  variables:\n  node: contains the current node.\n  aclass: is used to build a string containing class names given to the a tag if one is used\n  liclass: is used to build a string containing class names given to the li tag.\n*}\n{if !isset($depth)}{$depth=0}{/if}\n{strip}\n\n{if $depth == 0}\n<div id=\"menuwrapper\">\n<ul id=\"primary-nav\">\n{else}\n<ul class=\"unli\">\n{/if}\n\n{$depth=$depth+1}\n{foreach $nodes as $node}\n  {* setup classes for the anchor and list item *}\n  {$liclass=[]}\n  {$aclass=[]}\n\n  {* the first child gets a special class *}\n  {if $node@first && $node@total > 1}{$liclass[]=\'first_child\'}{/if}\n\n  {* the last child gets a special class *}\n  {if $node@last && $node@total > 1}{$liclass[]=\'last_child\'}{/if}\n\n  {if $node->current}\n    {* this is the current page *}\n    {$liclass[]=\'menuactive\'}\n    {$aclass[]=\'menuactive\'}\n  {/if}\n  {if $node->has_children}\n    {* this is a parent page *}\n    {$liclass[]=\'menuparent\'}\n    {$aclass[]=\'menuparent\'}\n  {/if}\n  {if $node->parent}\n    {* this is a parent of the current page *}\n    {$liclass[]=\'menuactive\'}\n    {$aclass[]=\'menuactive\'}\n  {/if}\n\n  {* build the menu item from the node *}\n  {if $node->type == \'sectionheader\'}\n    <li class=\'{implode(\' \',$liclass)}\'><a{if count($aclass) > 0} class=\"{implode(\' \',$aclass)}\"{/if}><span class=\"sectionheader\">{$node->menutext}</span></a>\n      {if isset($node->children)}\n        {include file=$smarty.template nodes=$node->children}\n      {/if}\n    </li>\n  {else if $node->type == \'separator\'}\n    <li style=\"list-style-type: none;\"><hr class=\"menu_separator\"/></li>\n  {else}\n    {* regular item *}\n    <li class=\"{implode(\' \',$liclass)}\">\n      <a{if count($aclass) > 0} class=\"{implode(\' \',$aclass)}\"{/if} href=\"{$node->url}\"{if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\n      {if isset($node->children)}\n        {include file=$smarty.template nodes=$node->children}\n      {/if}\n    </li>\n  {/if}\n{/foreach}\n{$depth=$depth-1}\n</ul>\n\n{if $depth == 0}\n<div class=\"clearb\"></div>\n</div>{* menuwrapper *}\n{/if}\n{/strip}', NULL, 4, 0, NULL, 1, 1, 1642391018, 1642391018),
(17, 'cssmenu_ulshadow', '{* cssmenu_ulshadow navigation *}\n{* note, function can only be defined once *}\n{* \n  variables:\n  node: contains the current node.\n  aclass: is used to build a string containing class names given to the a tag if one is used\n  liclass: is used to build a string containing class names given to the li tag.\n*}\n\n{function name=cssmenu_ulshadow depth=1}\n<ul{if $depth ==0} id=\"primary-nav\"{else} class=\"unli\"{/if}>\n  {foreach $data as $node}\n    {* setup classes for the anchor and list item *}\n    {assign var=\'liclass\' value=\'\'}\n    {*{assign var=\'liclass\' value=\' depth\'|cat:$depth}*}\n    {assign var=\'aclass\' value=\'\'}\n\n    {* the first child gets a special class \n    {if $node@first && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' first_child\'}{/if}\n    *}\n\n    {* the last child gets a special class \n    {if $node@last && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' last_child\'}{/if}\n    *}\n\n    {if $node->current}\n      {* this is the current page *}\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive\'}\n    {else if $node->parent}\n      {* this is a parent of the current page *}\n      {assign var=\'liclass\' value=$liclass|cat:\' parent\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' parent\'}\n    {/if}\n    {if isset($node->children)}\n      {assign var=\'liclass\' value=$liclass|cat:\' menuparent\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' menuparent\'}\n    {/if}\n\n    {* build the menu item node *}\n    {if $node->type == \'sectionheader\'}\n      <li class=\'sectionheader {$liclass}\'><span>{$node->menutext}</span>\n        {if isset($node->children)}\n          {cssmenu_ulshadow data=$node->children depth=$depth+1}\n        {/if}\n      </li>\n    {else if $node->type == \'separator\'}\n      <li class=\'separator {$liclass}\'><hr class=\'separator\'/></li>\n    {else}\n      {* regular item *}\n      <li class=\"{$liclass}\">\n        <a class=\"{$aclass}\" href=\"{$node->url}\"{if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\n        {if isset($node->children)}\n          {cssmenu_ulshadow data=$node->children depth=$depth+1}\n        {/if}\n      </li>\n    {/if}\n  {/foreach}\n  {if $depth > 0}\n    <li class=\"separator once\" style=\"list-style-type: none;\">&nbsp;</li>\n  {/if}\n</ul>\n{/function}\n\n{if isset($nodes)}\n<div id=\"menuwrapper\">\n  {cssmenu_ulshadow data=$nodes depth=0}\n  <div class=\"clearb\"></div>\n</div>\n{/if}', NULL, 4, 0, NULL, 1, 1, 1642391018, 1642391018);
INSERT INTO `cms_layout_templates` (`id`, `name`, `content`, `description`, `type_id`, `type_dflt`, `category_id`, `owner_id`, `listable`, `created`, `modified`) VALUES
(18, 'gps_mobile_menu', '{* cssmenu *}\r\n{* this template uses recursion, but not a smarty function. *}\r\n{* \r\n  variables:\r\n  node: contains the current node.\r\n  aclass: is used to build a string containing class names given to the a tag if one is used\r\n  liclass: is used to build a string containing class names given to the li tag.\r\n*}\r\n{if !isset($depth)}{$depth=0}{/if}\r\n  {strip}\r\n  \r\n  {if $depth == 0}\r\n  <ul class=\"off-canvas-list\">\r\n  {else}\r\n  <ul class=\"second\">\r\n  {/if}\r\n  \r\n  {$depth=$depth+1}\r\n  {foreach $nodes as $node}\r\n    {* setup classes for the anchor and list item *}\r\n    {$liclass=[]}\r\n    {$aclass=[]}\r\n  \r\n    {* the first child gets a special class *}\r\n    {if $node@first && $node@total > 1}{$liclass[]=\'first_child\'}{/if}\r\n  \r\n    {* the last child gets a special class *}\r\n    {if $node@last && $node@total > 1}{$liclass[]=\'last_child\'}{/if}\r\n  \r\n    {if $node->current}\r\n      {* this is the current page *}\r\n      {$liclass[]=\'menuactive\'}\r\n      {$aclass[]=\'menuactive\'}\r\n    {/if}\r\n    {if $node->has_children}\r\n      {* this is a parent page *}\r\n      {$liclass[]=\'menuparent\'}\r\n      {$aclass[]=\'menuparent\'}\r\n    {/if}\r\n    {if $node->parent}\r\n      {* this is a parent of the current page *}\r\n      {$liclass[]=\'menuactive\'}\r\n      {$aclass[]=\'menuactive\'}\r\n    {/if}\r\n    {if $node->alias == \'wild-fm\'}\r\n      {$liclass[]=\'hide\'}\r\n      {$aclass[]=\'hide\'}\r\n    {/if}\r\n    {* build the menu item from the node *}\r\n    {if $node->type == \'sectionheader\'}\r\n      <li class=\'{implode(\' \',$liclass)}\'><a{if count($aclass) > 0} class=\"{implode(\' \',$aclass)}\"{/if}><span class=\"sectionheader\">{$node->menutext}</span></a>\r\n        {if isset($node->children)}\r\n          {include file=$smarty.template nodes=$node->children}\r\n        {/if}\r\n      </li>\r\n    {else if $node->type == \'separator\'}\r\n      <li style=\"list-style-type: none;\"><hr class=\"menu_separator\"/></li>\r\n    {else}\r\n      {* regular item *}\r\n      <li class=\"{implode(\' \',$liclass)}\">\r\n        <a{if count($aclass) > 0} class=\"{implode(\' \',$aclass)}\"{/if} href=\"{$node->url}\"{if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\r\n        {if isset($node->children)}\r\n          {include file=$smarty.template nodes=$node->children}\r\n        {/if}\r\n      </li>\r\n    {/if}\r\n  \r\n  {/foreach}\r\n  {$depth=$depth-1}\r\n  </ul>\r\n  \r\n  {if $depth == 0}\r\n  <div class=\"clearb\"></div>\r\n  </div>{* menuwrapper *}\r\n  {/if}\r\n  {/strip}', '', 4, 0, NULL, 1, 1, 1642391018, 1648362574),
(37, 'gps_main_nav', '{strip}\r\n\r\n{$main_id = \' class=\\\'main-menu\\\'\'}\r\n{function do_class}\r\n    {if count($classes) > 0} class=\'{implode(\' \',$classes)}\'{/if}\r\n{/function}\r\n\r\n{function name=\'Simplex_menu\' depth=\'1\'}\r\n    <ul{$main_id}{if isset($ul_class) && $ul_class != \'\'} class=\"{$ul_class}\"{/if}>\r\n        {$main_id = \'\'}\r\n        {$ul_class = \'\'}\r\n        {foreach $data as $node}\r\n            {* setup classes for the anchor and list item *}\r\n            {$list_class = []}\r\n            {$href_class = [\'cf\']}\r\n            {$parent_indicator = \'\'}\r\n            {$aria_support = \'\'}\r\n    \r\n            {if $node->current || $node->parent}\r\n                {* this is the current page *}\r\n                {$list_class[] = \'current\'}\r\n                {$href_class[] = \'current\'}\r\n            {/if}\r\n    \r\n            {if $node->children_exist}\r\n                {$list_class[] = \'parent\'}\r\n                {$aria_support = \' aria-haspopup=\\\'true\\\'\'}\r\n                {$parent_indicator = \' <i class=\\\'icon-arrow-left\\\' aria-hidden=\\\'true\\\'></i>\'}\r\n            {/if}\r\n  \r\n            {* build the menu item node *}\r\n            {if $node->type == \'sectionheader\'}\r\n                {$list_class[] = \'sectionheader\'}\r\n                <li{do_class classes=$list_class}{$aria_support}><span>{$node->menutext}{$parent_indicator}</span>\r\n                {if isset($node->children)}\r\n                    {Simplex_menu data=$node->children depth=$depth+1}\r\n                {/if}\r\n                </li>\r\n            {else if $node->type == \'separator\'}\r\n                {$list_class[] = \'separator\'}\r\n                <li{do_class classes=$list_class}\'><hr class=\'separator\'/></li>\r\n              {elseif $node->alias == \'trade-customer-login\'}\r\n<li class=\"tradelogin\"><a href=\"{$node->url}\" title=\"{$node->menutext}\" target=\"_blank\" class=\"tradelogin\"><span>{$node->menutext}</span></a></li>\r\n{elseif $node->alias == \'home\'}\r\n<li class=\"hide\"><a class=\"hide\" href=\"{$node->url}\"><span>{$node->menutext}</span></a></li>\r\n{elseif $node->alias == \'facebook\'}\r\n<li><a class=\"social-icon\" title=\"Follow us on Facebook\" href=\"https://www.facebook.com/Gloucester-Preschool-and-Early-Years-Learning-Centre-111862070278368\" target=\"_blank\"><i class=\"fa fa-facebook\" title=\"Follow  {sitename} on Facebook\"></i></a></li>\r\n            {else}\r\n                {* regular item *}\r\n                <li{do_class classes=$list_class}{$aria_support}>\r\n                    <a{do_class classes=$href_class} title=\"{$node->menutext}\" href=\'{$node->url}\'{if $node->target != \'\'} target=\'{$node->target}\'{/if}>{$node->menutext}{$parent_indicator}</a>\r\n                    {if isset($node->children)}\r\n                        {Simplex_menu data=$node->children depth=$depth+1}\r\n                    {/if}\r\n                </li>\r\n            {/if}\r\n        {/foreach}\r\n\r\n    \r\n \r\n    </ul>\r\n{/function}\r\n\r\n{if isset($nodes)}\r\n    {Simplex_menu data=$nodes depth=\'0\' ul_class=\'cf\'}\r\n{/if}\r\n\r\n{/strip}', '', 4, 0, NULL, 1, 1, 1647992808, 1648108446),
(59, 'mams-force-password-change', '{* system default force new password form template *}\r\n<div class=\"alert alert-info\">{$mod->Lang(\'msg_force_newpw\')}</div>\r\n\r\n{if isset($error)}\r\n<div class=\"alert alert-danger\">{$error}</div>\r\n{/if}\r\n\r\n{$formstart}\r\n<div class=\"row\">\r\n  <div class=\"col-xs-3 text-right\">* {$mod->Lang(\'password\')}:</div>\r\n  <div class=\"col-xs-9\">\r\n    <input type=\"password\" name=\"{$actionid}mams_password\" value=\"\" required/>\r\n  </div>\r\n</div>\r\n<div class=\"row\">\r\n  <div class=\"col-xs-3 text-right\">* {$mod->Lang(\'repeatpassword\')}:</div>\r\n  <div class=\"col-xs-9\">\r\n    <input type=\"password\" name=\"{$actionid}mams_repeatpassword\" value=\"\" required/>\r\n  </div>\r\n</div>\r\n<div class=\"row\">\r\n  <div class=\"col-xs-3\">&nbsp;</div>\r\n  <div class=\"col-xs-9\">\r\n    <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\r\n  </div>\r\n</div>\r\n{$formend}', '', 23, 1, NULL, 1, 1, 1649229030, 1649229057),
(60, 'accordion-menu-mobile', '{function name=NavMobile depth=1}{strip}\r\n  <ul class=\"menu vertical accordion-menu\" data-accordion-menu data-parent-link=\'true\'>\r\n  {foreach $data as $node}\r\n    {* setup classes for the anchor and list item *}\r\n    {assign var=\'liclass\' value=\'menudepth\'|cat:$depth}\r\n    {assign var=\'aclass\' value=\'\'}\r\n\r\n    {* the first child gets a special class *}\r\n    {if $node@first && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' first_child\'}{/if}\r\n\r\n    {* the last child gets a special class *}\r\n    {if $node@last && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' last_child\'}{/if}\r\n\r\n    {if $node->current}\r\n      {* this is the current page *}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive\'}\r\n    {/if}\r\n\r\n    {if $node->parent}\r\n      {* this is a parent of the current page *}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive menuparent\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive menuparent\'}\r\n    {/if}\r\n\r\n    {if $node->children}\r\n      {assign var=\'liclass\' value=$liclass|cat:\' parent\'}\r\n      {assign var=\'aclass\' value=$aclass|cat:\' parent\'}\r\n    {/if}\r\n\r\n    {* build the menu item node *}\r\n    {if $node->type == \'sectionheader\'}\r\n      <li class=\'sectionheader {$liclass}\'><span>{$node->menutext}</span>\r\n        {if isset($node->children)}\r\n          {NavMobile data=$node->children depth=$depth+1}\r\n        {/if}\r\n      </li>\r\n    {else if $node->type == \'separator\'}\r\n      <li class=\'separator {$liclass}\'><hr class=\'separator\'/></li>\r\n    {else}\r\n      {* regular item *}\r\n      <li class=\"{$liclass}\">\r\n        <a class=\"{$aclass}\" href=\"{$node->url}\"{if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\r\n        {if isset($node->children)}\r\n          {NavMobile data=$node->children depth=$depth+1}\r\n        {/if}\r\n      </li>\r\n    {/if}\r\n  {/foreach}\r\n</ul>\r\n{/strip}{/function}\r\n\r\n{if isset($nodes)}\r\n{NavMobile data=$nodes depth=0}\r\n{/if}', '', 4, 0, NULL, 1, 1, 1651630244, 1651630244),
(61, 'Team', '<div>{LISETeam category=\'committee\' template_summary=\'committee\'}</div>\r\n<div>{LISETeam category=\'director\' template_summary=\'director\'}</div>\r\n<div>{LISETeam category=\'admin\' template_summary=\'admin\'}</div>\r\n<div>{LISETeam category=\'pre-school\' template_summary=\'pre-school\'}</div>\r\n<div>{LISETeam category=\'early-years\' template_summary=\'early-years\'}</div>\r\n<div>{LISETeam category=\'additional-educators\' template_summary=\'additional-educators\'}</div>\r\n<div>{LISETeam category=\'ancillary-staff\' template_summary=\'ancillary-staff\'}</div>\r\n<div>{LISETeam category=\'mobile-playgroup-educators\' template_summary=\'mobile-playgroup-educators\'}</div>', '', 2, NULL, NULL, 1, 1, 1651738177, 1659583418),
(62, 'Sitemap Pages', '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{function name=Nav_sitemap}\r\n{foreach $data as $node}\r\n{page_attr key=searchable page=$node->id assign=isSearchable}\r\n{if $node->type==\'content\' && !empty($isSearchable)}\r\n<url>\r\n  <loc>{$node->url}</loc>\r\n  <lastmod>{$node->modified|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=$node->modified equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>{$level=$node->hierarchy|substr_count:\'.\'}{if $node->url|substr:0:-1 == {root_url}}1{elseif $level == \'0\'}0.8{elseif $level == \'1\'}0.6{elseif $level == \'2\'}0.4{else}0.2{/if}</priority>\r\n</url>\r\n{/if}\r\n{if isset($node->children)}{Nav_sitemap data=$node->children}{/if}\r\n{/foreach}\r\n{/function}\r\n{if isset($nodes)}{Nav_sitemap data=$nodes}{/if}\r\n</urlset>', NULL, 30, 1, NULL, 1, 1, 1652252934, 1652252934),
(63, 'Sitemap News', '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->moreurl}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 31, 1, NULL, 1, 1, 1652252934, 1652252934),
(64, 'Sitemap CGBlog', '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->detail_url}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 32, 1, NULL, 1, 1, 1652252934, 1652252934),
(65, 'Sitemap CGCalendar', '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$events key=key item=event}\r\n<url>\r\n  <loc>{$event.url}</loc>\r\n  <lastmod>{$event.event_modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($event.event_modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 33, 1, NULL, 1, 1, 1652252934, 1652252934),
(66, 'Sitemap Company Directory', '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->detail_url}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 34, 1, NULL, 1, 1, 1652252934, 1652252934),
(67, 'Sitemap Products', '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->detail_url}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 35, 1, NULL, 1, 1, 1652252934, 1652252934),
(68, 'Sitemap PressRoom', '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach $articles as $article}\r\n<url>\r\n  <loc>{cms_action_url action=detail article=$article->id}</loc>\r\n  <lastmod>{$article->modified_date|default:$article->news_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=$article->modified_date|default:$article->news_date equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 36, 1, NULL, 1, 1, 1652252934, 1652252934),
(35, 'gps_home', '{extends file=\'cms_template:gpc_default\'}\r\n\r\n{block name=\'hero\'}\r\n{if $header_img}\r\n  <section class=\"hero\" style=\"background-image: url({$header_img});\" data-stellar-background-ratio=\"0.5\">{else}\r\n  <section class=\"hero\" style=\"background-image: url(https://ik.imagekit.io/webtactics/gloucester-pre-school/images/pages/header/generic-preschool-5.jpg);\" data-stellar-background-ratio=\"0.5\">{/if}\r\n  <div class=\"row\">\r\n  <div class=\"small-12 columns\">\r\n  <div class=\"caption-text\">\r\n  <h1><span>Gloucester Pre-School &</span><br/><span>Early Years Learning Centre</span></h1></div>\r\n  </div>\r\n  </div>\r\n  </section>\r\n  {/block}\r\n\r\n\r\n\r\n{block name=\'hero_black\'}\r\n<section class=\"hero\">\r\n<div class=\"row\">\r\n<div class=\"small-12 medium-9 medium-centered columns\">\r\n\r\n{$main_content|strip}\r\n\r\n</div>\r\n</section>\r\n{/block}\r\n{block name=\'content\'}\r\n    <section class=\"homecontent\">\r\n    <div class=\"row\">\r\n<div class=\"small-12 columns\">\r\n    {$main_content|strip}\r\n</div></div>\r\n    </section>\r\n{/block}\r\n', '', 1, 0, NULL, 1, 1, 1647991980, 1648078653),
(36, 'gps_default', '{strip}{process_pagedata}{block name=\'top\'}\r\n  {$canonical = \"{$content_obj->GetURL()|lower|default:\'\'}\" scope=global}\r\n  {$description = \"{description}\" scope=global}\r\n  {$main_content = \"{content}\" scope=global}\r\n  {my_set var=\'metadescription\' value=$main_content|strip_tags|trim}\r\n  {$header_img = \"{content_image block=\'Header Image\' label=\'Header Image\' dir=\'images/pages/header\' urlonly=\'1\'}\" scope=global}  \r\n  {$page_img = \"{content_image block=\'Page Image\' label=\'Page Image\' dir=\'images/pages\' urlonly=\'1\'}\" scope=global} \r\n  {content block=\'sidebar_content\' label=\'Sidebar_content\' assign=\'sidebar_content\' wysiwyg=\'false\'}\r\n  {cms_selflink dir=\'previous\' assign=\'prev_page\'}\r\n  {cms_selflink dir=\'next\' assign=\'next_page\'}\r\n  {* ensure that the smarty variables we created are copied to global scope for use elsewhere in the template *}\r\n  {share_data scope=parent vars=\'main_content,box_content,sidebar_content,prev_page,next_page\' scope=global}{/block}{/strip}\r\n<!doctype html>\r\n<html class=\"no-js\" lang=\"en\">\r\n<head>\r\n{metadata}\r\n</head>\r\n<body class=\"{$page_alias}\">\r\n<div class=\"off-canvas position-left\" id=\"offCanvasLeftOverlap\" data-off-canvas data-transition=\"overlap\">  \r\n{* Close button *}\r\n<button class=\"close-button\" aria-label=\"Close menu\" type=\"button\" data-close>\r\n<span aria-hidden=\"true\">&times;</span>\r\n</button>\r\n{* Mobile Menu *}\r\n<div id=\"menu_vert\">\r\n<h3>Menu</h3>\r\n<div class=\"mobilemenu\">\r\n{Navigator loadprops=\'0\' template=\'minimal_menu\' number_of_levels=\'3\'|strip}\r\n</div>\r\n<div class=\"mobilesearchsocialwrapper\">\r\n<ul class=\"menusocial\">\r\n<li><a class=\"social-icon\" title=\"Follow us on Facebook\" href=\"https://www.facebook.com/Gloucester-Preschool-and-Early-Years-Learning-Centre-111862070278368\" target=\"_blank\"><i class=\"fa fa-facebook\" title=\"Follow  {sitename} on Facebook\"></i></a></li>\r\n</ul>\r\n</div>\r\n</div>\r\n{* end menu *}\r\n</div>\r\n <div class=\"off-canvas-content\" data-off-canvas-content>\r\n {* Your page content starts here *}    \r\n<div id=\"header\" class=\"topbar\">\r\n<div class=\"row show-for-large\">\r\n<div class=\"small-12 columns\">\r\n{* main navigation on the right side *}\r\n<div class=\"navwrapper\">\r\n<nav class=\'main-navigation cf noprint\' id=\'nav\' role=\'navigation\'>\r\n{Navigator loadprops=\'0\' template=\'gpc_main_nav\'} {* A Navigator module, database Template *}\r\n</nav>\r\n</div>\r\n{* end main nav *}\r\n</div>\r\n</div>\r\n<div class=\"offcanvaswrapper\">\r\n<a class=\"menubar-icon\" data-toggle-menu class=\"overlay-nav-menu-toggle\" data-open=\"offCanvasLeftOverlap\" title=\"Click for Menu\"><i class=\"fa fa-bars\" aria-hidden=\"true\"></i><span class=\"mobilemenutitle\">Menu</span></a> \r\n</div>\r\n<div class=\"logowrapper\">\r\n<a href=\"/\" title=\"Return to the homepage | {sitename}\" id=\"logo\">\r\n<img src=\"{root_url}/uploads/images/assets/logo/Gloucester-Pre-School-logo-drop-shadow.png\" alt=\"{sitename}\" title=\"{sitename}\">\r\n</a>\r\n</div> \r\n</div>\r\n{* topbar above *}\r\n\r\n\r\n{block name=\'hero\'}\r\n  {if $header_img}\r\n<section class=\"hero\" style=\"background-image: url({$header_img});\" data-stellar-background-ratio=\"0.5\">{else}\r\n<section class=\"hero\" style=\"background-image: url({uploads_url}/images/pages/header/GPS-back-play.jpg);\" data-stellar-background-ratio=\"0.5\">{/if}\r\n<div class=\"row\">\r\n<div class=\"small-12 columns\">\r\n<div onclick  class=\"caption-text\">\r\n<h1><span>{if isset($alt_title)}{$alt_title}{elseif isset($blogtitle)}{$blogtitle}{else}{title}{/if}</span></h1></div>\r\n</div>\r\n</div>\r\n</section>\r\n{/block}\r\n{block name=\'content\'}\r\n<section class=\"maincontent\"> \r\n<div class=\"row toppad\">\r\n<div class=\"small-12 columns contentbox\">\r\n{$main_content|strip}  \r\n{if $page_img}\r\n<div class=\"page_img\"><img title=\"{title}\" alt=\"{title}\" src=\"{$page_img}\" ></div>\r\n{/if}\r\n</div>\r\n</div>\r\n</section>  \r\n{/block}\r\n{block name=\'slidersection\'}\r\n  <section class=\"slidersection\">      \r\n  <div class=\"row\">\r\n  <div class=\"small-12 columns\">\r\n  {LISEGalleryslide template_summary=summary_slick}\r\n  </div>\r\n  </div>\r\n  </section> \r\n  {/block} \r\n  {block name=\'mapsection\'}\r\n    <section class=\"mapsection\">      \r\n    <div class=\"expanded row\">\r\n    <div class=\"small-12 columns\">\r\n    <iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3383.216893543613!2d151.95881731744385!3d-32.00923799999998!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x6b74fbf45fdf620d%3A0x79ebb71df5faa997!2sGloucester%20Preschool!5e0!3m2!1sen!2sau!4v1648020485788!5m2!1sen!2sau\" width=\"100%\" height=\"250\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\"></iframe>\r\n    </div>\r\n    </div>\r\n    </section> \r\n    {/block} \r\n\r\n  \r\n\r\n\r\n{* start footer*}   \r\n<footer class=\"black\">\r\n<div class=\"row footer\">\r\n<div class=\"small-12 medium-7 large-9 columns footermenu\">\r\n<ul class=\"menu\">\r\n<li class=\"footlinkwhite\"><a href=\"{root_url}/about/who-we-are\">About</a></li>\r\n<li class=\"footlinkwhite\"><a href=\"{root_url}/admin\">Admin</a></li>\r\n<li class=\"footlinkwhite\"><a href=\"{root_url}/contact\">Contact</a></li>\r\n</ul>\r\n</div>\r\n<div class=\"small-12 medium-5 large-3 columns socialfooter\">\r\n<ul class=\"socialfootericons\">\r\n<li><a class=\"social-icon\" title=\"Follow us on Facebook\" href=\"https://www.facebook.com/Gloucester-Preschool-and-Early-Years-Learning-Centre-111862070278368\" target=\"_blank\"><i class=\"fa fa-facebook\" title=\"Follow  {sitename} on Facebook\"></i></a></li>\r\n</ul>  \r\n</div>\r\n</div>\r\n<a class=\"scrollToTop\" style=\"display: inline;\" href=\"#\">Scroll To Top</a>\r\n</footer>\r\n{* end footer *}\r\n{* end content *}\r\n</div>\r\n{* modals below *}\r\n{* end modals *}\r\n{block name=\'js\'}\r\n{jsmin}     \r\n<script src=\"{root_url}/js/lightbox-plus-jquery.min.js\"></script>\r\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/foundation/6.5.3/js/foundation.min.js\" integrity=\"sha256-/PFxCnsMh+nTuM0k3VJCRch1gwnCfKjaP8rJNq5SoBg=\" crossorigin=\"anonymous\"></script>\r\n<script src=\"{root_url}/js/slick.min.js\"></script>\r\n<script src=\"{root_url}/js/app.js\"></script>\r\n <script>\r\n      $(document).foundation();\r\n    </script> \r\n<script type=\"text/javascript\">\r\n  $(document).ready(function(){\r\n   // external links to new window\r\n    $(\'a[href^=\"http://\"], a[href^=\"https://\"]\').not(\'a[href*=\"gloucesterpreschool.behealthy.net.au\"]\').attr(\'target\',\'_blank\');\r\n    // force PDF Files to open in new window\r\n    $(\'a[href$=\".pdf\"]\').attr(\'target\', \'_blank\');\r\n  });\r\n </script>\r\n <script>\r\n$(function() {\r\n    var header = $(\".topbar\");\r\n  \r\n    $(window).scroll(function() {    \r\n        var scroll = $(window).scrollTop();\r\n        if (scroll >= 56) {\r\n            header.addClass(\"scrolled\");\r\n        } else {\r\n            header.removeClass(\"scrolled\");\r\n        }\r\n    });\r\n  \r\n});\r\n</script>\r\n<script>$( \".galleryimg\" ).last().addClass( \"end\" )</script>\r\n {/jsmin}\r\n{/block}\r\n{block name=\'clientjs\'}\r\n  <script>\r\n  $(document).ready(function(){\r\n      $(\'.client-class\').slick({\r\ncenterMode: true,\r\nautoplay: true,\r\nautoplaySpeed: 3000,\r\ncenterPadding: \'20px\',\r\nslidesToShow: 5,\r\nresponsive: [\r\n{\r\nbreakpoint: 800,\r\nsettings: {\r\n  arrows: false,\r\n  centerMode: true,\r\n  centerPadding: \'40px\',\r\n  slidesToShow: 3\r\n}\r\n},\r\n{\r\nbreakpoint: 480,\r\nsettings: {\r\n  arrows: false,\r\n  centerMode: true,\r\n  centerPadding: \'60px\',\r\n  slidesToShow: 1\r\n}\r\n}\r\n]\r\n      });\r\n  });\r\n</script>\r\n{/block}\r\n{block name=\'casejs\'}{/block}\r\n{block name=\'newsroomjs\'}{/block}\r\n</body>\r\n</html>', '', 1, 1, NULL, 1, 1, 1647992014, 1648078639),
(27, 'Search Form Sample', '{$startform}\n<label for=\"{$search_actionid}searchinput\">{$searchprompt}:&nbsp;</label><input type=\"text\" class=\"search-input\" id=\"{$search_actionid}searchinput\" name=\"{$search_actionid}searchinput\" size=\"20\" maxlength=\"50\" placeholder=\"{$searchtext}\"/>\n{*\n<br/>\n<input type=\"checkbox\" name=\"{$search_actionid}use_or\" value=\"1\"/>\n*}\n<input class=\"search-button\" name=\"submit\" value=\"{$submittext}\" type=\"submit\" />\n{if isset($hidden)}{$hidden}{/if}\n{$endform}', NULL, 10, 1, NULL, 1, 1, 1642391018, 1642391018),
(29, 'Search Results Sample', '<h3>{$searchresultsfor} &quot;{$phrase}&quot;</h3>\n{if $itemcount > 0}\n<ul>\n  {foreach from=$results item=entry}\n  <li>{$entry->title} - <a href=\"{$entry->url}\">{$entry->urltxt}</a> ({$entry->weight}%)</li>\n  {*\n     You can also instantiate custom behaviour on a module by module basis by looking at\n     the $entry->module and $entry->modulerecord fields in $entry\n      ie: {if $entry->module == \'News\'}{News action=\'detail\' article_id=$entry->modulerecord detailpage=\'News\'}\n\n     For content pages the module is \'content\' and modulerecord the page id. \n  *}\n  {/foreach}\n</ul>\n\n<p>{$timetaken}: {$timetook}</p>\n{else}\n  <p><strong>{$noresultsfound}</strong></p>\n{/if}', NULL, 11, 1, NULL, 1, 1, 1642391018, 1642391018);
INSERT INTO `cms_layout_templates` (`id`, `name`, `content`, `description`, `type_id`, `type_dflt`, `category_id`, `owner_id`, `listable`, `created`, `modified`) VALUES
