INSERT INTO `cms_layout_templates` (`id`, `name`, `content`, `description`, `type_id`, `type_dflt`, `category_id`, `owner_id`, `listable`, `created`, `modified`) VALUES
(71, 'gps_gallery', '{extends file=\'cms_template:gps_default\'}\r\n\r\n\r\n{block name=\'content\'}\r\n<section class=\"maincontent\">\r\n<div class=\"row\">\r\n<div class=\"small-12 columns\">\r\n{if $imageone}\r\n    <div class=\"page_img pad30\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-1200,h-700,q-80/{$imageone}\" ></div>\r\n    {/if}\r\n  {$main_content|strip}  \r\n  {if $imagetwo}\r\n    <div class=\"page_img pad1rem two\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-1200,h-600,q-80/{$imagetwo}\" ></div>\r\n    {/if}\r\n  \r\n  {if $second_content}\r\n  <div class=\"lowercontent\">{$second_content}</div>\r\n    {/if}\r\n    {if $imagethree}\r\n      <div class=\"page_img pad30 three\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-1200,h-500,q-80/{$imagethree}\" ></div>\r\n      {/if}\r\n      {if $lower_content}\r\n        <div class=\"lowercontent\">{$lower_content}</div>\r\n          {/if}\r\n</div></div>\r\n</section>\r\n{/block}\r\n', '', 1, 0, NULL, 1, 1, 1653012503, 1653012503),
(72, 'gps_team', '{extends file=\'cms_template:gps_default\'}\r\n\r\n\r\n{block name=\'content\'}\r\n<section class=\"maincontent\">\r\n<div class=\"row75em\">\r\n<div class=\"text-wrapper\">\r\n{$main_content|strip} \r\n</div>\r\n{if $page_alias == \"gallery\"}\r\n  {assign var=\'files\' value=\'uploads/images/Gallery/*.jpg\'|glob}\r\n  {if count($files)}\r\n  <div class=\"grid-200px-columns\">\r\n  {foreach from=$files item=\'file\'}\r\n  <div class=\"pagegallery\">\r\n  <div class=\"galleryimgwrapper\">\r\n  <a class=\"galleryimgwrapper-link\" href=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:h-1000,q-80,pr-true/{$file}\" data-lightbox=\"GPS-set\" data-title=\"{title}\" alt=\"{title}\" title=\"{title}\">\r\n  <img class=\"galleryimgwrapper-image\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/{$file}?tr=w-400,h-300,q-70,pr-true\" alt=\"{title}\" title=\"{title}\"/></a>\r\n  </div>\r\n  </div>\r\n  {/foreach}\r\n  </div>\r\n  {/if}\r\n{/if}\r\n{if $imageone}\r\n  <div class=\"page_img pad30\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-900,h-500,q-80/uploads/{$imageone}\" ></div>\r\n  {/if}\r\n  {if $second_content}\r\n    <div class=\"second_content\">{$second_content}</div>\r\n      {/if}\r\n{if $imagetwo}\r\n  <div class=\"page_img pad1rem two\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-800,h-600,q-80/uploads/{$imagetwo}\" ></div>\r\n  {/if}\r\n\r\n  {if $lower_content}\r\n    <div class=\"lower_content\">{$lower_content}</div>\r\n      {/if}\r\n  {if $imagethree}\r\n    <div class=\"page_img pad30 three\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-900,h-500,q-80/uploads/{$imagethree}\" ></div>\r\n    {/if}\r\n</div>\r\n</section>\r\n{/block}\r\n\r\n\r\n', '', 1, 0, NULL, 1, 1, 1659323102, 1659323102);
