(74, 'slick-slider', '{literal}<style>/*! slick-slider */.slick-slider { position: relative; display: block; box-sizing: border-box; -moz-box-sizing: border-box; -webkit-touch-callout: none; -webkit-user-select: none; -khtml-user-select: none; -moz-user-select: none; -ms-user-select: none; user-select: none; -ms-touch-action: pan-y; touch-action: pan-y; -webkit-tap-highlight-color: transparent; }\r\n\r\n.slick-list { position: relative; overflow: hidden; display: block; margin: 0; padding: 0; }\r\n.slick-list:focus { outline: none; }\r\n.slick-loading .slick-list { background: #fff url(\"./ajax-loader.gif\") center center no-repeat; }\r\n.slick-list.dragging { cursor: pointer; cursor: hand; }\r\n\r\n.slick-slider .slick-track { -webkit-transform: translate3d(0, 0, 0); -moz-transform: translate3d(0, 0, 0); -ms-transform: translate3d(0, 0, 0); -o-transform: translate3d(0, 0, 0); transform: translate3d(0, 0, 0); }\r\n\r\n.slick-track { position: relative; left: 0; top: 0; display: block; }\r\n.slick-track:before, .slick-track:after { content: \"\"; display: table; }\r\n.slick-track:after { clear: both; }\r\n.slick-loading .slick-track { visibility: hidden; }\r\n\r\n.slick-slide { float: left; height: 100%; min-height: 1px; display: none; }\r\n[dir=\"rtl\"] .slick-slide { float: right; }\r\n.slick-slide img { display: block; }\r\n.slick-slide.slick-loading img { display: none; }\r\n.slick-slide.dragging img { pointer-events: none; }\r\n.slick-initialized .slick-slide { display: block; }\r\n.slick-loading .slick-slide { visibility: hidden; }\r\n.slick-vertical .slick-slide { display: block; height: auto; border: 1px solid transparent; }\r\n\r\n/* Icons */\r\n@font-face { font-family: \"slick\"; src: url(\"./fonts/slick.eot\"); src: url(\"./fonts/slick.eot?#iefix\") format(\"embedded-opentype\"), url(\"./fonts/slick.woff\") format(\"woff\"), url(\"./fonts/slick.ttf\") format(\"truetype\"), url(\"./fonts/slick.svg#slick\") format(\"svg\"); font-weight: normal; font-style: normal; }\r\n/* Arrows */\r\n.slick-prev, .slick-next { position: absolute; display: block; height: 20px; width: 20px; line-height: 0; font-size: 0; cursor: pointer; background: transparent; color: transparent; top: 50%; margin-top: -10px; padding: 0; border: none; outline: none; }\r\n.slick-prev:hover, .slick-prev:focus, .slick-next:hover, .slick-next:focus { outline: none; background: transparent; color: transparent; }\r\n.slick-prev:hover:before, .slick-prev:focus:before, .slick-next:hover:before, .slick-next:focus:before { opacity: 1; }\r\n.slick-prev.slick-disabled:before, .slick-next.slick-disabled:before { opacity: 0.25; }\r\n\r\n.slick-prev:before, .slick-next:before { font-family: \"slick\"; font-size: 20px; line-height: 1; color: white; opacity: 0.75; -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }\r\n\r\n.slick-prev { left: -25px; }\r\n[dir=\"rtl\"] .slick-prev { left: auto; right: -25px; }\r\n.slick-prev:before { content: \"←\"; }\r\n[dir=\"rtl\"] .slick-prev:before { content: \"→\"; }\r\n\r\n.slick-next { right: -25px; }\r\n[dir=\"rtl\"] .slick-next { left: -25px; right: auto; }\r\n.slick-next:before { content: \"→\"; }\r\n[dir=\"rtl\"] .slick-next:before { content: \"←\"; }\r\n\r\n/* Dots */\r\n.slick-slider { margin-bottom: 30px; }\r\n\r\n.slick-dots { position: absolute; bottom: -45px; list-style: none; display: block; text-align: center; padding: 0; width: 100%; }\r\n.slick-dots li { position: relative; display: inline-block; height: 20px; width: 20px; margin: 0 5px; padding: 0; cursor: pointer; }\r\n.slick-dots li button { border: 0; background: transparent; display: block; height: 20px; width: 20px; outline: none; line-height: 0; font-size: 0; color: transparent; padding: 5px; cursor: pointer; }\r\n.slick-dots li button:hover, .slick-dots li button:focus { outline: none; }\r\n.slick-dots li button:hover:before, .slick-dots li button:focus:before { opacity: 1; }\r\n.slick-dots li button:before { position: absolute; top: 0; left: 0; content: \"•\"; width: 20px; height: 20px; font-family: \"slick\"; font-size: 6px; line-height: 20px; text-align: center; color: black; opacity: 0.25; -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }\r\n.slick-dots li.slick-active button:before { color: black; opacity: 0.75; }\r\n</style>{/literal}', '', 2, 0, NULL, 1, 1, 1659581919, 1659583410);
