INSERT INTO `cms_layout_templates` (`id`, `name`, `content`, `description`, `type_id`, `type_dflt`, `category_id`, `owner_id`, `listable`, `created`, `modified`) VALUES
(78, 'Simple Navigation Menu', '{* CSS classes used in this template:\r\n.activeparent - The top level parent when a child is the active/current page\r\nli.active0n h3 - n is the depth/level of the node. To style the active page for each level separately. The active page is not clickable.\r\n.clearfix - Used for the unclickable h3 to use the entire width of the li, just like the anchors. See the Tools stylesheet in the default CMSMS installation.\r\nli.sectionheader h3 - To style section header\r\nli.separator - To style the ruler for the separator *} \r\n\r\n{assign var=\'number_of_levels\' value=10000}\r\n{if isset($menuparams.number_of_levels)}\r\n  {assign var=\'number_of_levels\' value=$menuparams.number_of_levels}\r\n{/if}\r\n\r\n{if $count > 0}\r\n<ul>\r\n{foreach from=$nodelist item=node}\r\n{if $node->depth > $node->prevdepth}\r\n{repeat string=\"<ul>\" times=$node->depth-$node->prevdepth}\r\n{elseif $node->depth < $node->prevdepth}\r\n{repeat string=\"</li></ul>\" times=$node->prevdepth-$node->depth}\r\n</li>\r\n{elseif $node->index > 0}</li>\r\n{/if}\r\n\r\n{if $node->parent == true or $node->current == true}\r\n  {assign var=\'classes\' value=\'menuactive\'}\r\n  {if $node->parent == true}\r\n    {assign var=\'classes\' value=\'menuactive menuparent\'}\r\n  {/if}\r\n  {if $node->children_exist == true and $node->depth < $number_of_levels}\r\n    {assign var=\'classes\' value=$classes|cat:\' parent\'}\r\n  {/if}\r\n  <li class=\"{$classes}\"><a class=\"{$classes}\" href=\"{$node->url}\"><span>{$node->menutext}</span></a>\r\n\r\n{elseif $node->children_exist == true and $node->depth < $number_of_levels and $node->type != \'sectionheader\' and $node->type != \'separator\'}\r\n<li class=\"parent\"><a class=\"parent\" href=\"{$node->url}\"><span>{$node->menutext}</span></a>\r\n\r\n{elseif $node->current == true}\r\n<li class=\"currentpage\"><h3><span>{$node->menutext}</span></h3>\r\n\r\n{elseif $node->type == \'sectionheader\'}\r\n<li class=\"sectionheader\"><span>{$node->menutext}</span>\r\n\r\n{elseif $node->type == \'separator\'}\r\n<li class=\"separator\" style=\"list-style-type: none;\"> <hr />\r\n\r\n{else}\r\n<li><a href=\"{$node->url}\"><span>{$node->menutext}</span></a>\r\n\r\n{/if}\r\n\r\n{/foreach}\r\n{repeat string=\"</li></ul>\" times=$node->depth-1}</li>\r\n</ul>\r\n{/if}', NULL, 37, 1, NULL, 1, 1, 1687750545, 1687750545),
(79, 'News Summary Sample', '<!-- Start News Display Template -->\n{* This section shows a clickable list of your News categories. *}\n<ul class=\"list1\">\n{foreach from=$cats item=node}\n{if $node.depth > $node.prevdepth}\n{repeat string=\"<ul>\" times=$node.depth-$node.prevdepth}\n{elseif $node.depth < $node.prevdepth}\n{repeat string=\"</li></ul>\" times=$node.prevdepth-$node.depth}\n</li>\n{elseif $node.index > 0}</li>\n{/if}\n<li{if $node.index == 0} class=\"firstnewscat\"{/if}>\n{if $node.count > 0}\n	<a href=\"{$node.url}\">{$node.news_category_name}</a>{else}<span>{$node.news_category_name} </span>{/if}\n{/foreach}\n{repeat string=\"</li></ul>\" times=$node.depth-1}</li>\n</ul>\n\n{* this displays the category name if you\'re browsing by category *}\n{if $category_name}\n<h1>{$category_name}</h1>\n{/if}\n\n{* if you don\'t want category browsing on your summary page, remove this line and everything above it *}\n\n{if $pagecount > 1}\n  <p>\n{if $pagenumber > 1}\n{$firstpage}&nbsp;{$prevpage}&nbsp;\n{/if}\n{$pagetext}&nbsp;{$pagenumber}&nbsp;{$oftext}&nbsp;{$pagecount}\n{if $pagenumber < $pagecount}\n&nbsp;{$nextpage}&nbsp;{$lastpage}\n{/if}\n</p>\n{/if}\n{foreach from=$items item=entry}\n<div class=\"NewsSummary\">\n\n{if $entry->postdate}\n	<div class=\"NewsSummaryPostdate\">\n		{$entry->postdate|cms_date_format}\n	</div>\n{/if}\n\n<div class=\"NewsSummaryLink\">\n<a href=\"{$entry->moreurl}\" title=\"{$entry->title|cms_escape:htmlall}\">{$entry->title|cms_escape}</a>\n</div>\n\n<div class=\"NewsSummaryCategory\">\n	{$category_label} {$entry->category}\n</div>\n\n{if $entry->author}\n	<div class=\"NewsSummaryAuthor\">\n		{$author_label} {$entry->author}\n	</div>\n{/if}\n\n{if $entry->summary}\n        {* note, for security purposes, incase News articles can come from untrused sources, we do not pass the summary or content through smarty in the default templates *}\n	<div class=\"NewsSummarySummary\">\n		{$entry->summary}\n	</div>\n\n	<div class=\"NewsSummaryMorelink\">\n		[{$entry->morelink}]\n	</div>\n\n{else if $entry->content}\n        {* note, for security purposes, incase News articles can come from untrused sources, we do not pass the summary or content through smarty in the default templates *}\n	<div class=\"NewsSummaryContent\">\n		{$entry->content}\n	</div>\n{/if}\n\n{if isset($entry->extra)}\n    <div class=\"NewsSummaryExtra\">\n        {$entry->extra}\n	{* {cms_module module=\'Uploads\' mode=\'simpleurl\' upload_id=$entry->extravalue} *}\n    </div>\n{/if}\n{if isset($entry->fields)}\n  {foreach from=$entry->fields item=\'field\'}\n     <div class=\"NewsSummaryField\">\n        {if $field->type == \'file\'}\n          {if isset($field->value) && $field->value}\n            <img src=\"{$entry->file_location}/{$field->value}\"/>\n          {/if}\n        {elseif $field->type == \'linkedfile\'}\n          {* also assume it\'s an image... *}\n          {if !empty($field->value)}\n            <img src=\"{file_url file=$field->value}\" alt=\"{$field->value}\"/>\n          {/if}\n        {else}\n          {$field->name}:&nbsp;{$field->value}\n        {/if}\n     </div>\n  {/foreach}\n{/if}\n\n</div>\n{/foreach}\n<!-- End News Display Template -->', NULL, 38, 1, NULL, 1, 1, 1687750546, 1687750546),
(80, 'News Detail Sample', '{* set a canonical variable that can be used in the head section if process_whole_template is false in the config.php *}\n{if isset($entry->canonical)}\n  {* note this syntax ensures that the canonical variable is set into global scope *}\n  {assign var=\'canonical\' value=$entry->canonical scope=global}\n{/if}\n\n{if $entry->postdate}\n	<div id=\"NewsPostDetailDate\">\n		{$entry->postdate|cms_date_format}\n	</div>\n{/if}\n<h3 id=\"NewsPostDetailTitle\">{$entry->title|cms_escape:htmlall}</h3>\n\n<hr id=\"NewsPostDetailHorizRule\" />\n\n{if $entry->summary}\n	<div id=\"NewsPostDetailSummary\">\n		<strong>\n			{$entry->summary}\n		</strong>\n	</div>\n{/if}\n\n{if $entry->category}\n	<div id=\"NewsPostDetailCategory\">\n		{$category_label} {$entry->category}\n	</div>\n{/if}\n{if $entry->author}\n	<div id=\"NewsPostDetailAuthor\">\n		{$author_label} {$entry->author}\n	</div>\n{/if}\n\n<div id=\"NewsPostDetailContent\">\n        {* note, for security purposes we do not pass the content through smarty before displaying it.  This is incase your articles can come from untrusted sources. *}\n	{$entry->content}\n</div>\n\n{if $entry->extra}\n	<div id=\"NewsPostDetailExtra\">\n		{$extra_label} {$entry->extra}\n	</div>\n{/if}\n\n{if $return_url != \"\"}\n<div id=\"NewsPostDetailReturnLink\">{$return_url}{if $category_name != \'\'} - {$category_link}{/if}</div>\n{/if}\n\n{if isset($entry->fields)}\n  {foreach $entry->fields as $fieldname => $field}\n     <div class=\"NewsDetailField\">\n        {if $field->type == \'file\'}\n	  {* this template assumes that every file uploaded is an image of some sort, because News doesn\'t distinguish *}\n          {if isset($field->value) && $field->value}\n            <img src=\"{$entry->file_location}/{$field->value}\" alt=\"{$field->value}\"/>\n          {/if}\n        {elseif $field->type == \'linkedfile\'}\n          {* also assume it\'s an image... *}\n          {if !empty($field->value)}\n            <img src=\"{file_url file=$field->value}\" alt=\"{$field->value}\"/>\n          {/if}\n        {else}\n          {$field->name}:&nbsp;{$field->value}\n        {/if}\n     </div>\n  {/foreach}\n{/if}', NULL, 39, 1, NULL, 1, 1, 1687750546, 1687750546),
(81, 'News Fesubmit Form Sample', '{* original form template *}\n<h3>{$mod->Lang(\'title_fesubmit_form\')}</h3>\n\n{if isset($error)}\n  <div class=\"error>{$error}</div>\n{elseif isset($message)}\n  <div class=\"message>{$message}</div>\n{/if}\n\n{form_start category_id=$category_id}\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_title\">*{$mod->Lang(\'title\')}:</label></p>\n		<p class=\"col8\">\n			<input id=\"news_title\" type=\"text\" name=\"{$actionid}title\" value=\"{$title}\" size=\"30\" required/>\n                </p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_category\">{$mod->Lang(\'category\')}:</label></p>\n		<p class=\"col8\">\n			<select id=\"news_category\" name=\"{$actionid}input_category\">\n                        {html_options options=$categorylist selected=$category_id}\n			</select>\n                </p>\n	</div>\n\n{if !isset($hide_summary_field) or $hide_summary_field == 0}\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_summary\">{$mod->Lang(\'summary\')}:</label></p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'summary\'}\n			{cms_textarea enablewysiwyg=true id=news_summary name=$tmp value=$summary required=true}\n		</p>\n	</div>\n{/if}\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_content\">*{$mod->Lang(\'content\')}:</label></p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'content\'}\n			{cms_textarea enablewysiwyg=true id=news_content name=$tmp value=$content required=true}\n                </p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_extra\">{$mod->Lang(\'extra\')}:</label></p>\n		<p class=\"col8\">\n			<input id=\"news_extra\" type=\"text\" name=\"{$actionid}extra\" value=\"{$extra}\" size=\"30\"/>\n                </p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\">{$mod->Lang(\'startdate\')}:</p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'startdate_\'}\n			{html_select_date prefix=$tmp time=$startdate end_year=\"+15\"}\n			{html_select_time prefix=$tmp time=$startdate}\n		</p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\">{$mod->Lang(\'enddate\')}:</p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'enddate_\'}\n			{html_select_date prefix=$tmp time=$enddate end_year=\"+15\"}\n			{html_select_time prefix=$tmp time=$enddate}\n		</p>\n	</div>\n	{if isset($customfields)}\n	   {foreach from=$customfields item=\'field\'}\n	      <div class=\"row\">\n		<p class=\"col4\"><label for=\"news_fld_{$field->id}\">{$field->name}:</label></p>\n		<p class=\"col8\">\n		{if $field->type == \'file\'}\n			<input id=\"news_fld_{$field->id}\" type=\"file\" name=\"{$actionid}news_customfield_{$field->id}\"/>\n		{elseif $field->type == \'checkbox\'}\n			<input id=\"news_fld_{$field->id}\" type=\"checkbox\" name=\"{$actionid}news_customfield_{$field->id}\" value=\"1\"/>\n		{elseif $field->type == \'textarea\'}\n			{$tmp1=\'news_fld_\'|cat:$field->id}\n			{capture assign=\'tmp2\'}{$actionid}news_customfield_{$field->id}{/capture}\n			{cms_textarea id=$tmp1 name=$tmp2 enablewysiwyg=true}\n		{elseif $field->type == \'textbox\'}\n			<input id=\"news_fld_{$field->id}\" type=\"text\"\" name=\"{$actionid}news_customfield_{$field->id}\" maxlength=\"{$field->max_length}\"/>\n                {/if}\n		</p>\n	      </div>\n	   {/foreach}\n	{/if}\n	<div class=\"row\">\n		<p class=\"col4\">&nbsp;</p>\n		<p class=\"col8\">\n			<input type=\"submit\" name=\"{$actionid}submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n			<a href=\"{cms_selflink href=$page_alias}\">{$mod->Lang(\'prompt_redirecttocontent\')}</a>\n		</p>\n	</div>\n{form_end}', NULL, 40, 1, NULL, 1, 1, 1687750546, 1687750546),
(82, 'News Browse Category Sample', '{if $count > 0}\n<ul class=\"list1\">\n{foreach from=$cats item=node}\n{if $node.depth > $node.prevdepth}\n{repeat string=\"<ul>\" times=$node.depth-$node.prevdepth}\n{elseif $node.depth < $node.prevdepth}\n{repeat string=\"</li></ul>\" times=$node.prevdepth-$node.depth}\n</li>\n{elseif $node.index > 0}</li>\n{/if}\n<li class=\"newscategory\">\n{if $node.count > 0}\n	<a href=\"{$node.url}\">{$node.news_category_name}</a> ({$node.count}){else}<span>{$node.news_category_name} (0)</span>{/if}\n{/foreach}\n{repeat string=\"</li></ul>\" times=$node.depth-1}</li>\n</ul>\n{/if}', NULL, 41, 1, NULL, 1, 1, 1687750546, 1687750546),
(83, 'gps_qip_detail', '{extends file=\'cms_template:gps_default\'}\r\n\r\n\r\n{block name=\'content\'}\r\n<section class=\"maincontent\">\r\n<div class=\"row75em\">\r\n<div class=\"text-wrapper\">\r\n{$main_content|strip} \r\n{if $page_alias == \"gallery\"}\r\n{LISEGalleryslide}\r\n{/if}\r\n</div>\r\n{if $imageone}\r\n  <div class=\"page_img pad30\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-900,h-500,q-80/uploads/{$imageone}\" ></div>\r\n  {/if}\r\n  {if $second_content}\r\n    <div class=\"second_content\">{$second_content}</div>\r\n      {/if}\r\n{if $imagetwo}\r\n  <div class=\"page_img pad1rem two\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-800,h-600,q-80/uploads/{$imagetwo}\" ></div>\r\n  {/if}\r\n\r\n  {if $lower_content}\r\n    <div class=\"lower_content\">{$lower_content}</div>\r\n      {/if}\r\n  {if $imagethree}\r\n    <div class=\"page_img pad30 three\"><img title=\"{title}\" alt=\"{title}\" src=\"https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:w-900,h-500,q-80/uploads/{$imagethree}\" ></div>\r\n    {/if}\r\n</div>\r\n</section>\r\n{/block}\r\n\r\n\r\n', '', 1, 0, NULL, 1, 1, 1689831542, 1689831542);
INSERT INTO `cms_layout_tpl_addusers` (`tpl_id`, `user_id`) VALUES
(52, 1);
INSERT INTO `cms_layout_tpl_type` (`id`, `originator`, `name`, `has_dflt`, `dflt_contents`, `description`, `lang_cb`, `dflt_content_cb`, `requires_contentblocks`, `help_content_cb`, `one_only`, `owner`, `created`, `modified`) VALUES
(1, '__CORE__', 'page', 1, '{strip}\n	{process_pagedata}\n{/strip}<!doctype html>\n<html lang=\"{cms_get_language}\">\n\n<head>\n	<title>{title} - {sitename}</title>\n	{metadata}\n	{cms_stylesheet}\n</head>\n\n<body>\n	<header id=\"header\">\n		<h1>{sitename}</h1>\n	</header>\n\n	<nav id=\"menu\">\n		{Navigator}\n	</nav>\n\n	<section id=\"content\">\n		<h1>{title}</h1>\n		{content}\n	</section>\n</body>\n\n</html>', NULL, 's:44:\"CmsTemplateResource::page_type_lang_callback\";', 's:45:\"CmsTemplateResource::reset_page_type_defaults\";', 1, 's:43:\"CmsTemplateResource::template_help_callback\";', NULL, NULL, 1642391015, 1642391015),
(2, '__CORE__', 'generic', NULL, NULL, NULL, 's:47:\"CmsTemplateResource::generic_type_lang_callback\";', 'N;', 0, 's:43:\"CmsTemplateResource::template_help_callback\";', NULL, NULL, 1642391015, 1642391015),
(17, 'MAMS', 'login form', 1, '{* login form template *}\n{* this is a sample template, feel free to customize it *}\n{if isset($alt_loginform)}\n  <div class=\"row\" id=\"altlogin\">{$alt_loginform}</div><br/>\n{/if}\n\n<fieldset id=\"loginform\">\n  <legend>{$MAMS->Lang(\'prompt_normallogin\')}:</legend>\n  {$startform}{xt_form_csrf}\n\n  {*\n   * a simple honeypot captcha....if this field has a value after submit an error will be thrown\n   * deleting this field will simply disable the honeypot.\n   * it is important that the field be hidden with CSS rather than using a hidden input field.\n   *}\n  <input type=\"text\" name=\"{$actionid}mams__data\" value=\"\" style=\"display: none;\"/>\n\n  {if $error}<div class=\"alert alert-danger\">{$error}</div>{/if}\n\n  <div class=\"row\">\n    <p class=\"col-md-4 text-right\"><label for=\"mams_username\">*{$prompt_username}:</label></p>\n    <p class=\"col-md-8\">\n      <input type=\"{if $username_is_email}email{else}text{/if}\" id=\"mams_username\" name=\"{$fldname_username}\" value=\"{$username}\" size=\"{$username_size}\" maxlength=\"{$username_maxlength}\" {if !$username_is_email}autocorrect=\"off\" autocapitalize=\"off\"{/if} required/>\n    </p>\n  </div>\n\n  <div class=\"row\">\n    <p class=\"col-md-4 text-right\"><label for=\"mams_password\">*{$prompt_password}:</label></p>\n    <p class=\"col-md-8\">\n      <input type=\"password\" id=\"mams_password\" name=\"{$fldname_password}\" value=\"{$password}\" size=\"{$password_size}\" maxlength=\"{$password_maxlength}\" required/>\n    </p>\n  </div>\n\n  {if isset($captcha)}\n  <div class=\"row\">\n    <p class=\"col-md-4 text-right\">{$captcha_title}</p>\n    <div class=\"col-md-8\">{$captcha}\n      {if $need_captcha_input}\n      <div class=\"row\">\n        <input type=\"text\" name=\"{$actionid}mams_input_captcha\" size=\"10\"/>\n      </div>\n      {/if}\n    </div>\n  </div>\n  {/if}\n\n  {if isset($prompt_rememberme)}\n  <div class=\"row\">\n    <p class=\"col-md-4\"></p>\n    <p class=\"col-md-8\">\n      <label><input type=\"checkbox\" name=\"{$actionid}mams_rememberme\" value=\"1\" {if $rememberme==1}checked{/if}/> {$prompt_rememberme}</label>\n    </p>\n  </div>\n  {/if}\n\n  <div class=\"row\">\n    <p class=\"col-md-4\"></p>\n    <p class=\"col-md-8\">\n      <button class=\"btn btn-active\" name=\"{$actionid}mams_submit\">{$MAMS->Lang(\'login\')}</button>\n    </p>\n  </div>\n\n  {if isset($url_lostun) || isset($url_forgot)}\n  <div class=\"row\">\n    <p class=\"col-md-4\"></p>\n    <p class=\"col-sm-8\">\n      {if isset($url_forgot)}\n        <a href=\"{$url_forgot}\" title=\"{$MAMS->Lang(\'info_forgotpw\')}\">{$MAMS->Lang(\'forgotpw\')}</a>\n      {/if}\n      {if isset($url_lostun)}\n        | <a href=\"{$url_lostun}\" title=\"{$MAMS->Lang(\'info_lostun\')}\">{$MAMS->Lang(\'lostusername\')}</a>\n      {/if}\n    </p>\n  </div>\n  {/if}\n  {$endform}\n</fieldset>\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(4, 'Navigator', 'navigation', 1, '{* simple navigation *}\n{* note, function can only be defined once *}\n{* \n  variables:\n  node: contains the current node.\n  aclass: is used to build a string containing class names given to the a tag if one is used\n  liclass: is used to build a string containing class names given to the li tag.\n*}\n\n{function name=Nav_menu depth=1}{strip}\n<ul>\n  {foreach $data as $node}\n    {* setup classes for the anchor and list item *}\n    {assign var=\'liclass\' value=\'menudepth\'|cat:$depth}\n    {assign var=\'aclass\' value=\'\'}\n\n    {* the first child gets a special class *}\n    {if $node@first && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' first_child\'}{/if}\n\n    {* the last child gets a special class *}\n    {if $node@last && $node@total > 1}{assign var=\'liclass\' value=$liclass|cat:\' last_child\'}{/if}\n\n    {if $node->current}\n      {* this is the current page *}\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive\'}\n    {/if}\n\n    {if $node->parent}\n      {* this is a parent of the current page *}\n      {assign var=\'liclass\' value=$liclass|cat:\' menuactive menuparent\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' menuactive menuparent\'}\n    {/if}\n\n    {if $node->children}\n      {assign var=\'liclass\' value=$liclass|cat:\' parent\'}\n      {assign var=\'aclass\' value=$aclass|cat:\' parent\'}\n    {/if}\n\n    {* build the menu item node *}\n    {if $node->type == \'sectionheader\'}\n      <li class=\'sectionheader {$liclass}\'><span>{$node->menutext}</span>\n        {if isset($node->children)}\n          {Nav_menu data=$node->children depth=$depth+1}\n        {/if}\n      </li>\n    {else if $node->type == \'separator\'}\n      <li class=\'separator {$liclass}\'><hr class=\'separator\'/></li>\n    {else}\n      {* regular item *}\n      <li class=\"{$liclass}\">\n        <a class=\"{$aclass}\" href=\"{$node->url}\"{if $node->target ne \"\"} target=\"{$node->target}\"{/if}><span>{$node->menutext}</span></a>\n        {if isset($node->children)}\n          {Nav_menu data=$node->children depth=$depth+1}\n        {/if}\n      </li>\n    {/if}\n  {/foreach}\n</ul>\n{/strip}{/function}\n\n{if isset($nodes)}\n{Nav_menu data=$nodes depth=0}\n{/if}\n', NULL, 's:34:\"Navigator::page_type_lang_callback\";', 's:35:\"Navigator::reset_page_type_defaults\";', 0, 's:33:\"Navigator::template_help_callback\";', NULL, NULL, 1642391018, 1642391018),
(5, 'Navigator', 'breadcrumbs', 1, '{* default breadcrumbs template *}\n{strip}\n<div class=\"breadcrumb\">\n  {if isset($starttext)}{$starttext}:&nbsp;{/if}\n  {foreach $nodelist as $node}\n    {$spanclass=\'breadcrumb\'}\n    {if $node->current}\n      {$spanclass=$spanclass|cat:\' current\'}\n    {/if}\n\n    <span class=\"{$spanclass}\">\n      {if $node@last}\n        {$node->menutext}\n      {elseif $node->type == \'sectionheader\'}\n        {$node->menutext}&nbsp;\n      {else}\n        <a href=\"{$node->url}\" title=\"{$node->menutext}\">{$node->menutext}</a>\n      {/if}\n    </span>\n\n    {if !$node@last}&raquo;&nbsp;{/if}\n  {/foreach}\n</div>\n{/strip}', NULL, 's:34:\"Navigator::page_type_lang_callback\";', 's:35:\"Navigator::reset_page_type_defaults\";', 0, 's:33:\"Navigator::template_help_callback\";', NULL, NULL, 1642391018, 1642391018),
(29, 'SitemapMgr', 'sitemap_custom', 1, '', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(30, 'SitemapMgr', 'sitemap_pages', 1, '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{function name=Nav_sitemap}\r\n{foreach $data as $node}\r\n{page_attr key=searchable page=$node->id assign=isSearchable}\r\n{if $node->type==\'content\' && !empty($isSearchable)}\r\n<url>\r\n  <loc>{$node->url}</loc>\r\n  <lastmod>{$node->modified|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=$node->modified equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>{$level=$node->hierarchy|substr_count:\'.\'}{if $node->url|substr:0:-1 == {root_url}}1{elseif $level == \'0\'}0.8{elseif $level == \'1\'}0.6{elseif $level == \'2\'}0.4{else}0.2{/if}</priority>\r\n</url>\r\n{/if}\r\n{if isset($node->children)}{Nav_sitemap data=$node->children}{/if}\r\n{/foreach}\r\n{/function}\r\n{if isset($nodes)}{Nav_sitemap data=$nodes}{/if}\r\n</urlset>', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(31, 'SitemapMgr', 'sitemap_news', 1, '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->moreurl}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(32, 'SitemapMgr', 'sitemap_cgblog', 1, '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->detail_url}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(33, 'SitemapMgr', 'sitemap_cgcalendar', 1, '', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(34, 'SitemapMgr', 'sitemap_compdir', 1, '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->detail_url}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(35, 'SitemapMgr', 'sitemap_products', 1, '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach from=$items item=entry}\r\n<url>\r\n  <loc>{$entry->detail_url}</loc>\r\n  <lastmod>{$entry->modified_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=strtotime($entry->modified_date) equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(36, 'SitemapMgr', 'sitemap_pressroom', 1, '<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\r\n{foreach $articles as $article}\r\n<url>\r\n  <loc>{cms_action_url action=detail article=$article->id}</loc>\r\n  <lastmod>{$article->modified_date|default:$article->news_date|date_format:\'%Y-%m-%d\'}</lastmod>\r\n  <changefreq>{math now=$smarty.now modified=$article->modified_date|default:$article->news_date equation=\'(now-modified)/86400\' assign=\'days\'}{if $days < 2}hourly{elseif $days < 14}daily{elseif $days < 61}weekly{elseif $days < 365}monthly{else}yearly{/if}</changefreq>\r\n  <priority>0.6</priority>\r\n</url>\r\n{/foreach}\r\n</urlset>', NULL, 's:35:\"SitemapMgr::page_type_lang_callback\";', 's:36:\"SitemapMgr::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1652252934, 1652252934),
(10, 'Search', 'searchform', 1, '\n{$startform}\n<label for=\"{$search_actionid}searchinput\">{$searchprompt}:&nbsp;</label><input type=\"text\" class=\"search-input\" id=\"{$search_actionid}searchinput\" name=\"{$search_actionid}searchinput\" size=\"20\" maxlength=\"50\" placeholder=\"{$searchtext}\"/>\n{*\n<br/>\n<input type=\"checkbox\" name=\"{$search_actionid}use_or\" value=\"1\"/>\n*}\n<input class=\"search-button\" name=\"submit\" value=\"{$submittext}\" type=\"submit\" />\n{if isset($hidden)}{$hidden}{/if}\n{$endform}', NULL, 's:31:\"Search::page_type_lang_callback\";', 's:32:\"Search::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1642391018, 1642391018),
(11, 'Search', 'searchresults', 1, '<h3>{$searchresultsfor} &quot;{$phrase}&quot;</h3>\n{if $itemcount > 0}\n<ul>\n  {foreach from=$results item=entry}\n  <li>{$entry->title} - <a href=\"{$entry->url}\">{$entry->urltxt}</a> ({$entry->weight}%)</li>\n  {*\n     You can also instantiate custom behaviour on a module by module basis by looking at\n     the $entry->module and $entry->modulerecord fields in $entry\n      ie: {if $entry->module == \'News\'}{News action=\'detail\' article_id=$entry->modulerecord detailpage=\'News\'}\n\n     For content pages the module is \'content\' and modulerecord the page id. \n  *}\n  {/foreach}\n</ul>\n\n<p>{$timetaken}: {$timetook}</p>\n{else}\n  <p><strong>{$noresultsfound}</strong></p>\n{/if}', NULL, 's:31:\"Search::page_type_lang_callback\";', 's:32:\"Search::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1642391018, 1642391018),
(18, 'MAMS', 'logout form', 1, '{* logout form template *}\n{if isset($alt_logoutform)}{$alt_logoutform}{/if}\n{if isset($message)}<div class=\"alert alert-info\">{$message}</div>{/if}\n<p>{$prompt_loggedin}&nbsp;{$username}</p>\n<p><a href=\"{$url_changesettings}\" title=\"{$mod->Lang(\'info_changesettings\')}\">{$mod->Lang(\'prompt_changesettings\')}</a></p>\n{if isset($url_logout)}\n<p><a href=\"{$url_logout}\" title=\"{$mod->Lang(\'info_logout\')}\">{$mod->Lang(\'logout\')}</a></p>\n{/if}\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(19, 'MAMS', 'chsettings form', 1, '<!-- change settings template -->\n<div id=\"mams_changesettingsform\">\n<h4>{$mod->Lang(\'user_settings\')}</h4>\n\n{if isset($message) && $message != \'\'}\n  {if isset($error) && $error != \'\'}\n    <p class=\"alert alert-error\">{$message}</p>\n  {else}\n    <p class=\"alert alert-info\">{$message}</p>\n  {/if}\n{/if}\n\n{$startform}{xt_form_csrf}\n  {if $controlcount > 0}\n  {foreach $controls as $key=>$field}\n    <div class=\"row\">\n      <label for=\"{$field->input_id}\" class=\"col-sm-3 text-right\" style=\"color: {$field->color|default:\'inherit\'}\">{$field->marker|default:\'\'} {$field->prompt}:</label>\n      <div class=\"col-sm-9\">\n        {$field->hidden|default:\'\'}\n        {if isset($field->hidden)}{$field->hidden}{/if}\n\n	{* build the field itself *}\n	{if $field->type == \'0\'} {* text *}\n	  <input type=\"text\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\n	{elseif $field->type == \'password\'} {* text *}\n	  <input type=\"password\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\n	{elseif $field->type == 2} {* email *}\n	  <input type=\"email\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" size=\"{$field->length}\" maxlength=\"{$field->maxlength}\" value=\"{$field->value}\" {if $field->readonly}readonly{/if}/>\n	{elseif $field->type == 3} {* textarea *}\n          {xt_textarea id=$field->input_id wysiwyg=$field->wysiwyg name=$field->input_name content=$field->value class=\"form-control\"}\n	{elseif $field->type == 1} {* checkbox *}\n	  <input type=\"hidden\" name=\"{$field->input_name}\" value=\"0\"/>\n	  <input type=\"checkbox\" id=\"{$field->input_id}\" class=\"checkbox\" name=\"{$field->input_name}\" value=\"1\" {if $field->value}checked{/if}/>\n	{elseif $field->type == 4} {* dropdown *}\n	   <select id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" {if $field->readonly}readonly{/if}>\n	      {html_options options=$field->options selected=$field->value}\n	   </select>\n	{elseif $field->type == 5} {* multiselect *}\n	   <select id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}[]\" {if $field->readonly}readonly{/if} multiple>\n	      {html_options options=$field->options selected=$field->selected}\n	   </select>\n	{elseif $field->type == 7} {* radio group *}\n	   {foreach $field->options as $key => $val}\n	      <label><input type=\"radio\" class=\"form-control\" name=\"{$field->input_name}\" value=\"{$key}\" {if $key==$field->value}checked=\"checked\"{/if}> {$val}</label>\n	   {/foreach}\n	{elseif $field->type == 6} {* image *}\n	   {if isset($field->image_url) && $field->image_url}<img src=\"{$field->image_url}\" alt=\"{$field->image_url}\" width=\"100\" height=\"100\"/>{/if}\n	   {if isset($field->prompt2) && $field->prompt2}<label><input type=\"checkbox\" class=\"checkbox\" name=\"{$field->input_name2}\" value=\"clear\"/> {$field->prompt2}</label>{/if}\n	   <input type=\"hidden\" name=\"{$field->input_name}\" value=\"{$field->value}\"/>\n 	   <input type=\"file\" id=\"{$field->input_id}\" class=\"form-control\" name=\"{$field->input_name}\" {if $field->readonly}readonly{/if}/>\n	{elseif $field->type == 8} {* date *}\n	   {$sy=$field->startyear|default:\'-5\'}\n	   {$ey=$field->startyear|default:\'+10\'}\n	   {html_select_date prefix=$field->input_name start_year=$sy end_year=$ey time=$field->value}\n	{/if}\n        {$field->addtext|default:\'\'}\n      </div>\n    </div>\n  {/foreach}\n  {/if}\n\n  <div class=\"row\">\n    <div class=\"col-sm-3\"></div>\n    <div class=\"col-sm-9\">\n      <button type=\"submit\" class=\"btn btn_active\" name=\"{$actionid}submit\">{$mod->Lang(\'submit\')}</button>\n    </div>\n  </div>\n{$hidden|default:\'\'}{$endform}\n</div>\n<!-- change settings template -->\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(20, 'MAMS', 'forgot password form', 1, '{* forgot password template *}\n<h4>{$mod->Lang(\'title_forgotpw\')}</h4>\n{if !empty($message) }\n  {if !empty($error) }\n    <div class=\"alert alert-danger\">{$message}</div>\n  {else}\n    <div class=\"alert alert-info\">{$message}</div>\n  {/if}\n{else}\n  <div class=\"alert alert-info\">{$mod->Lang(\'lostpw_message\')}</div>\n{/if}\n\n{if !isset($forgotpwdone)}\n  {if isset($startform)}\n    {$startform}{xt_form_csrf}\n    <div class=\"row\">\n      <div class=\"col-sm-2 text-right\">\n        {if $username_is_email}\n          {$mod->Lang(\'prompt_email\')}:\n        {else}\n          {$mod->Lang(\'prompt_username\')}:\n        {/if}\n      </div>\n      <div class=\"col-sm-10\">\n        <input name=\"{$actionid}mams_username\" type=\"{if $username_is_email}email{else}text{/if}\" size=\"{$unfldlen}\" maxlength=\"{$max_unfldlen}\" value=\"{$username}\" required/> *\n      </div>\n    </div>\n    {if isset($captcha)}\n    <div class=\"row\">\n      <div class=\"col-sm-2 text-right\">{$captcha_title}:</div>\n      <div class=\"col-sm-10\">{$captcha}\n        {if isset($input_captcha)}<div class=\"row\">{$input_captcha}</p>{/if}\n      </div>\n    </div>\n    {/if}\n    <div class=\"row\">\n      <div class=\"col-sm-10 col-sm-offset-2\">\n        <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n        <input id=\"mams_cancel\" type=\"submit\" name=\"{$actionid}mams_cancel\" value=\"{$mod->Lang(\'cancel\')}\" formnovalidate/>\n      </div>\n    </div>\n    {$endform}\n  {/if}\n{/if}\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(21, 'MAMS', 'forgot password email', 1, '{* verify email template -- formerly fogot password email template *}\n<h3>{$title}</h3>\n<div>{$message}</div>\n<h4>{$prompt_code}: {$data_code}</h4>\n<p>{$prompt_link}: <a href=\"{$data_url}\">{$data_url}</a></p>\n{/strip}\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(22, 'MAMS', 'forgot password verify', 1, '{* forgot password verification template *}\n<h4>{$mod->Lang(\'verify_identity\')}</h4>\n{if !empty($message)}\n  {if !empty($error) }\n    <div class=\"alert alert-danger\">{$message}</div>\n  {else}\n    <div class=\"alert alert-info\">{$message}</div>\n  {/if}\n{/if}\n\n{if isset($startform)}\n  {$startform}{xt_form_csrf}\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'prompt_username\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"{if $username_is_email}email{else}text{/if}\" name=\"{$actionid}mams_username\" size=\"{$unfldlen}\" maxlength=\"{$max_unfldlen}\" value=\"{$username}\" disabled=\"disabled\"/>\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'prompt_code\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"text\" name=\"{$actionid}mams_code\" value=\"{$code}\" size=\"40\" maxlength=\"40\" required /> *\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'prompt_password\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"password\" name=\"{$actionid}mams_password1\" value=\"{$password1}\" size=\"{$pwfldlen}\" maxlength=\"{$max_pwfldlen}\" required/> *\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">{$mod->Lang(\'repeatpassword\')}:</div>\n    <div class=\"col-sm-9\">\n      <input type=\"password\" name=\"{$actionid}mams_password2\" value=\"{$password2}\" size=\"{$pwfldlen}\" maxlength=\"{$max_pwfldlen}\" required/> *\n    </div>\n  </div>\n  <div class=\"row\">\n    <div class=\"col-sm-3 text-right\">&nbsp;</div>\n    <div class=\"col-sm-9\">\n      <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n    </div>\n  </div>\n{$endform}\n{/if}\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(23, 'MAMS', 'force new password', 1, '{* system default force new password form template *}\n<div class=\"alert alert-info\">{$mod->Lang(\'msg_force_newpw\')}</div>\n\n{if isset($error)}\n<div class=\"alert alert-danger\">{$error}</div>\n{/if}\n\n{$formstart}\n<div class=\"row\">\n  <div class=\"col-xs-3 text-right\">* {$mod->Lang(\'password\')}:</div>\n  <div class=\"col-xs-9\">\n    <input type=\"password\" name=\"{$actionid}mams_password\" value=\"\" required/>\n  </div>\n</div>\n<div class=\"row\">\n  <div class=\"col-xs-3 text-right\">* {$mod->Lang(\'repeatpassword\')}:</div>\n  <div class=\"col-xs-9\">\n    <input type=\"password\" name=\"{$actionid}mams_repeatpassword\" value=\"\" required/>\n  </div>\n</div>\n<div class=\"row\">\n  <div class=\"col-xs-3\">&nbsp;</div>\n  <div class=\"col-xs-9\">\n    <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n  </div>\n</div>\n{$formend}', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(24, 'MAMS', 'lost username form', 1, '{* lost username confirm template form *}\n<h4>{$mod->Lang(\'title_lostusername\')}</h4>\n<div class=\"alert alert-info\">{$mod->Lang(\'info_lostusername\')}</div>\n{if isset($message)}<div class=\"alert alert-danger\">{$message}</div>{/if}\n{if count($controls)}\n  {$startform}\n    <input type=\"hidden\" name=\"{$actionid}mams__data\" value=\"\"/>{* simple honeypot captcha *}\n    {foreach from=$controls item=\'entry\'}\n       <div class=\"row\">\n          <div class=\"col-sm-4 text-right\">{$entry->prompt}</div>\n          <div class=\"col-sm-8\">\n	    {if $entry->type == \'_password\'}\n	      <input type=\"password\" name=\"{$entry->fldname}\" value=\"{$entry->val}\" size=\"{$entry->length}\" maxlength=\"{$entry->maxlength}\"/>\n	      <br/>{$mod->Lang(\'info_lostun_pwfield\')}\n	    {else if $entry->type == 0}\n	      {* text *}\n	      <input type=\"text\" name=\"{$entry->fldname}\" value=\"{$entry->val}\" size=\"{$entry->length}\" maxlength=\"{$entry->maxlength}\"/>\n	      <br/>{$mod->Lang(\'info_lostun_textfield\')}\n	    {elseif $entry->type == 1}\n	      {* checkbox *}\n	      <input type=\"checkbox\" name=\"{$entry->fldname}\" value=\"1\" {if $entry->val}checked{/if}/>\n	    {elseif $entry->type == 2}\n	      {* email *}\n	      <input type=\"email\" name=\"{$entry->fldname}\" value=\"{$entry->val}\" size=\"{$entry->length}\" maxlength=\"{$entry->maxlength}\"/>\n	    {elseif $entry->type == 3}\n	      {* textarea *}\n	      <textarea name=\"{$entry->fldname}\" rows=\"3\" cols=\"50\">{$entry->val}</textarea>\n	      <br/>{$mod->Lang(\'info_lostun_textarea\')}\n	    {elseif $entry->type == 4}\n	      {* dropdown *}\n	      <select name=\"{$entry->fldname}\">\n	        <option value=\"\">{$mod->Lang(\'donotknow\')}</option>\n		{html_options options=$entry->options selected=$entry->val}\n	      </select>\n	    {elseif $entry->type == 5}\n	      {* multiselect *}\n	      <select name=\"{$entry->fldname}[]\" multiple size=\"{$entry->length}\">\n		{html_options options=$entry->options selected=$entry->val}\n	      </select>\n	    {elseif $entry->type == 7}\n	      {* radiobtns *}\n	      {foreach $entry->options as $key => $val}\n	        <label><input type=\"radio\" name=\"{$entry->fldname}\" value=\"{$key}\" {if $key == $entry->val}checked{/if}/> {$val}</label>\n	        {if !$val@last}<br/>{/if}\n	      {/foreach}\n	    {elseif $entry->type == 8}\n	      {* date *}\n	      {html_select_date prefix=$entry->fldname start_year=$entry->start_year end_year=$entry->end_year time=$entry->val all_empty=\'--\'}\n	    {/if}\n	  </div>\n       </div>\n    {/foreach}\n    {if isset($captcha)}\n      <div class=\"row\">\n        <p class=\"col-sm-4 text-right\">{$captcha_title}</p>\n        <div class=\"col-sm-8\">{$captcha}\n          {if $need_captcha_input}\n          <div class=\"row col-sm-12\">\n            <input type=\"text\" name=\"{$actionid}mams_input_captcha\" size=\"10\"/>\n          </div>\n          {/if}\n	</div>\n      </div>\n    {/if}\n    <div class=\"row\">\n      <div class=\"col-sm-4 text-right\"></div>\n      <div class=\"col-sm-8\">\n        <input type=\"submit\" name=\"{$actionid}mams_submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n        <input type=\"submit\" name=\"{$actionid}mams_cancel\" value=\"{$mod->Lang(\'cancel\')}\"/>\n      </div>\n    </div>\n  {$endform}\n{/if}\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(25, 'MAMS', 'lost username confirm', 1, '{* lost username confirm template form *}\n<h3>{$premsg}</h3>\n<p>{$prompt_yourusernameis}: <strong>{$username}</strong>.</p>\n<p>{$postmsg}</p>', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(26, 'MAMS', 'view user', 1, '{* view user template *}\n<p>{$mod->Lang(\'id\')}:&nbsp;{$userinfo.id}</p>\n<p>{$mod->Lang(\'username\')}:&nbsp;{$userinfo.username}</p>\n<p>{$mod->Lang(\'email\')}:&nbsp;<a href=\"mailto:{$email_address}\">{$email_address}</p>\n<p>{$mod->Lang(\'expires\')}:&nbsp;{$userinfo.expires}</p>\n{foreach from=$user_properties item=\'entry\'}\n{if $entry.type != 0}\n<p>{$entry.prompt}:&nbsp;{$entry.data}</p>\n{/if}\n{/foreach}\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(27, 'MAMS', 'reset session', 1, '{* reset session template *}\n{* NOTE: this template requires jquery be available in any page that it is used on *}\n\n<p><a href=\"javascript:;\" name=\"mams_manual_reset\">Click Here To Confirm Login Status</a></p>{* safe to remove this *}\n\n{* style information for the modal window and the mask... these can be removed and placed in a CMSMS stylesheet *}\n{literal}\n<style type=\"text/css\">\nmams_modal {\n  background-color: #fff;\n  border: 1px solid #00f;\n  padding: 2px;\n  margin:  2px;\n}\n#mams_mask {\n  background-color: #000;\n}\n#mams_modal .title {\n  background-color: #00f;\n  color:  #fff;\n  padding: 0px;\n}\n</style>\n{/literal}\n\n{capture assign=\'mams_theform\'}{strip}\n{* the reset-session form, a simple form to display a message with a title to the user with two options... okay, and cancel... the name of these buttons is important, as well the strip tag is important *}\n<form action=\"javascript:;\">\n<p class=\"title\">{$mod->Lang(\'title_reset_session\')}</p>\n<p class=\"row\">{$mod->Lang(\'msg_reset_session\')}</p>\n<p class=\"row\">\n  <input type=\"submit\" name=\"mams_ok\" value=\"{$mod->Lang(\'ok\')}\"/>\n  <input type=\"submit\" name=\"mams_cancel\" value=\"{$mod->Lang(\'cancel\')}\"/>\n</p>\n</form>\n{/strip}{/capture}\n\n{literal}\n<script type=\"text/javascript\">\n//<![CDATA[\n// the timer interval (how often you want to display the dialog to your users\nvar timer_interval = {/literal}{$session_timeout}{literal} - 30;\n\n// a function to hide the modal dialog -- you can modify this function\nfunction mams_close_modal()\n{\n   jQuery(\'#mams_modal\').fadeOut(2000);\n   jQuery(\'#mams_mask\').fadeOut(1000);\n}\n\n// a function to display the modal dialog... you can modify this function\nfunction mams_open_modal()\n{\n  var maskHeight = jQuery(document).height();\n  var maskWidth = jQuery(document).width();\n\n  // set the mask size to fill up the whole screen\n  jQuery(\'#mams_mask\').css({\'width\':maskWidth,\'height\':maskHeight});\n\n  // transition effect\n  jQuery(\'#mams_mask\').fadeIn(1000);\n  jQuery(\'#mams_mask\').fadeTo(\"slow\",0.8);\n\n  // get the top left corner of the popup\n  var winHeight = jQuery(window).height();\n  var winWidth = jQuery(window).width();\n\n  var popupHeight = jQuery(\'#mams_modal\').height();\n  var popupWidth  = jQuery(\'#mams_modal\').width();\n\n  var top = winHeight/2 - popupHeight/2;\n  var left = winWidth/2 - popupWidth/2;\n  // set the popup window to center\n  jQuery(\'#mams_modal\').css({\'top\':top,\'left\':left});\n\n  // transition effect\n  jQuery(\'#mams_modal\').fadeIn(2000);\n}\n\nfunction mams_user_cancelled()\n{\n  // a callback function that may be customized to allow displaying a message to the user\n  // to indicate that they may be logged out at any time.\n  alert(\'You have chosen to disregard the session warning, you may continue to browse this site however some functionality may be unavailable to you until you login again\');\n}\n\n// *\n// * do not modify below here unless you are an experienced jquery programmer *\n// *\n\nif( timer_interval <= 0 )\n  {\n     timer_interval = 0;\n  }\nvar dialogcontents = \'{/literal}{$mams_theform}{literal}\';\n\n\n// we have jQuery\njQuery(document).ready(function(){\n  // create a new id for our stuff\n  jQuery(\'body\').append(\'<div id=\"mams_body\"></div>\');\n  \n  // create the mask and append it to the dom\n  jQuery(\'#mams_body\').append(\'<div id=\"mams_mask\"></div>\');\n\n  // create the modal dialog and append it to the DOM\n  jQuery(\'#mams_body\').append(\'<div id=\"mams_modal\">\'+dialogcontents+\'</div>\');\n  \n  // and a junk div\n  jQuery(\'#mams_body\').append(\'<div id=\"mams_junk\" style=\"display: none;\"></div>\');\n\n  // handle click events\n  jQuery(\'#mams_modal input[name=mams_ok]\').click(function(e){\n    e.preventDefault();\n\n    // do the ajax request\n    var url = \'{/literal}{$reset_url}{literal}\';\n    var url = url.replace(/amp;/g,\'\');\n    jQuery(\'#mams_junk\').load(url);\n\n    // and done.\n    #mams_close_modal();\n   });\n  jQuery(\'#mams_modal input[name=mams_cancel]\').click(function(e){\n    e.preventDefault();\n    #mams_close_modal();\n    #mams_user_cancelled();\n  });\n  jQuery(\'a[name=mams_manual_reset]\').click(function(e){\n    e.preventDefault();\n    mams_open_modal();\n  });\n\n  // create our timer\n  if( timer_interval > 0 )\n     {\n        setTimeout(mams_open_modal,timer_interval * 1000);\n     }\n\n});\n//]]>\n</script>\n{/literal}\n\n{* required css *}\n{literal}\n<style type=\"text/css\">\n#mams_modal {\n  position: absolute;\n  z-index: 9999;\n  display: none;\n}\n#mams_mask {\n  top: 0;\n  left: 0;\n  position: absolute;\n  z-index: 9000;\n  display: none;\n}\n</style>\n{/literal}', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(28, 'MAMS', 'verify_form', 1, '{* original verification form *}\n<div class=\"alert alert-info\">{$mod->Lang(\'info_verify_identity2\')}</div>\n{form_start uid=$uid}{xt_form_csrf}\n  <div class=\"row\">\n    <label>{$mod->Lang(\'code\')}: <input type=\"text\" class=\"form_control\" name=\"{$actionid}code\" value=\"{$code}\" required/></label>\n  </div>\n  <div class=\"row\">\n    <button type=\"submit\" name=\"{$actionid}mams_submit\" class=\"btn btn_active\">{$mod->Lang(\'verify\')}</button>\n  </div>\n</div>\n{form_end}\n', NULL, 's:29:\"MAMS::page_type_lang_callback\";', 's:30:\"MAMS::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1648091132, 1648091132),
(37, 'MenuManager', 'navigation', 1, '{* CSS classes used in this template:\r\n.activeparent - The top level parent when a child is the active/current page\r\nli.active0n h3 - n is the depth/level of the node. To style the active page for each level separately. The active page is not clickable.\r\n.clearfix - Used for the unclickable h3 to use the entire width of the li, just like the anchors. See the Tools stylesheet in the default CMSMS installation.\r\nli.sectionheader h3 - To style section header\r\nli.separator - To style the ruler for the separator *} \r\n\r\n{assign var=\'number_of_levels\' value=10000}\r\n{if isset($menuparams.number_of_levels)}\r\n  {assign var=\'number_of_levels\' value=$menuparams.number_of_levels}\r\n{/if}\r\n\r\n{if $count > 0}\r\n<ul>\r\n{foreach from=$nodelist item=node}\r\n{if $node->depth > $node->prevdepth}\r\n{repeat string=\"<ul>\" times=$node->depth-$node->prevdepth}\r\n{elseif $node->depth < $node->prevdepth}\r\n{repeat string=\"</li></ul>\" times=$node->prevdepth-$node->depth}\r\n</li>\r\n{elseif $node->index > 0}</li>\r\n{/if}\r\n\r\n{if $node->parent == true or $node->current == true}\r\n  {assign var=\'classes\' value=\'menuactive\'}\r\n  {if $node->parent == true}\r\n    {assign var=\'classes\' value=\'menuactive menuparent\'}\r\n  {/if}\r\n  {if $node->children_exist == true and $node->depth < $number_of_levels}\r\n    {assign var=\'classes\' value=$classes|cat:\' parent\'}\r\n  {/if}\r\n  <li class=\"{$classes}\"><a class=\"{$classes}\" href=\"{$node->url}\"><span>{$node->menutext}</span></a>\r\n\r\n{elseif $node->children_exist == true and $node->depth < $number_of_levels and $node->type != \'sectionheader\' and $node->type != \'separator\'}\r\n<li class=\"parent\"><a class=\"parent\" href=\"{$node->url}\"><span>{$node->menutext}</span></a>\r\n\r\n{elseif $node->current == true}\r\n<li class=\"currentpage\"><h3><span>{$node->menutext}</span></h3>\r\n\r\n{elseif $node->type == \'sectionheader\'}\r\n<li class=\"sectionheader\"><span>{$node->menutext}</span>\r\n\r\n{elseif $node->type == \'separator\'}\r\n<li class=\"separator\" style=\"list-style-type: none;\"> <hr />\r\n\r\n{else}\r\n<li><a href=\"{$node->url}\"><span>{$node->menutext}</span></a>\r\n\r\n{/if}\r\n\r\n{/foreach}\r\n{repeat string=\"</li></ul>\" times=$node->depth-1}</li>\r\n</ul>\r\n{/if}\r\n', NULL, 's:36:\"MenuManager::page_type_lang_callback\";', 's:37:\"MenuManager::reset_page_type_defaults\";', 0, 'N;', NULL, NULL, 1687750545, 1687750545),
(38, 'News', 'summary', 1, '<!-- Start News Display Template -->\n{* This section shows a clickable list of your News categories. *}\n<ul class=\"list1\">\n{foreach from=$cats item=node}\n{if $node.depth > $node.prevdepth}\n{repeat string=\"<ul>\" times=$node.depth-$node.prevdepth}\n{elseif $node.depth < $node.prevdepth}\n{repeat string=\"</li></ul>\" times=$node.prevdepth-$node.depth}\n</li>\n{elseif $node.index > 0}</li>\n{/if}\n<li{if $node.index == 0} class=\"firstnewscat\"{/if}>\n{if $node.count > 0}\n	<a href=\"{$node.url}\">{$node.news_category_name}</a>{else}<span>{$node.news_category_name} </span>{/if}\n{/foreach}\n{repeat string=\"</li></ul>\" times=$node.depth-1}</li>\n</ul>\n\n{* this displays the category name if you\'re browsing by category *}\n{if $category_name}\n<h1>{$category_name}</h1>\n{/if}\n\n{* if you don\'t want category browsing on your summary page, remove this line and everything above it *}\n\n{if $pagecount > 1}\n  <p>\n{if $pagenumber > 1}\n{$firstpage}&nbsp;{$prevpage}&nbsp;\n{/if}\n{$pagetext}&nbsp;{$pagenumber}&nbsp;{$oftext}&nbsp;{$pagecount}\n{if $pagenumber < $pagecount}\n&nbsp;{$nextpage}&nbsp;{$lastpage}\n{/if}\n</p>\n{/if}\n{foreach from=$items item=entry}\n<div class=\"NewsSummary\">\n\n{if $entry->postdate}\n	<div class=\"NewsSummaryPostdate\">\n		{$entry->postdate|cms_date_format}\n	</div>\n{/if}\n\n<div class=\"NewsSummaryLink\">\n<a href=\"{$entry->moreurl}\" title=\"{$entry->title|cms_escape:htmlall}\">{$entry->title|cms_escape}</a>\n</div>\n\n<div class=\"NewsSummaryCategory\">\n	{$category_label} {$entry->category}\n</div>\n\n{if $entry->author}\n	<div class=\"NewsSummaryAuthor\">\n		{$author_label} {$entry->author}\n	</div>\n{/if}\n\n{if $entry->summary}\n        {* note, for security purposes, incase News articles can come from untrused sources, we do not pass the summary or content through smarty in the default templates *}\n	<div class=\"NewsSummarySummary\">\n		{$entry->summary}\n	</div>\n\n	<div class=\"NewsSummaryMorelink\">\n		[{$entry->morelink}]\n	</div>\n\n{else if $entry->content}\n        {* note, for security purposes, incase News articles can come from untrused sources, we do not pass the summary or content through smarty in the default templates *}\n	<div class=\"NewsSummaryContent\">\n		{$entry->content}\n	</div>\n{/if}\n\n{if isset($entry->extra)}\n    <div class=\"NewsSummaryExtra\">\n        {$entry->extra}\n	{* {cms_module module=\'Uploads\' mode=\'simpleurl\' upload_id=$entry->extravalue} *}\n    </div>\n{/if}\n{if isset($entry->fields)}\n  {foreach from=$entry->fields item=\'field\'}\n     <div class=\"NewsSummaryField\">\n        {if $field->type == \'file\'}\n          {if isset($field->value) && $field->value}\n            <img src=\"{$entry->file_location}/{$field->value}\"/>\n          {/if}\n        {elseif $field->type == \'linkedfile\'}\n          {* also assume it\'s an image... *}\n          {if !empty($field->value)}\n            <img src=\"{file_url file=$field->value}\" alt=\"{$field->value}\"/>\n          {/if}\n        {else}\n          {$field->name}:&nbsp;{$field->value}\n        {/if}\n     </div>\n  {/foreach}\n{/if}\n\n</div>\n{/foreach}\n<!-- End News Display Template -->\n', NULL, 's:29:\"News::page_type_lang_callback\";', 's:30:\"News::reset_page_type_defaults\";', 0, 's:28:\"News::template_help_callback\";', NULL, NULL, 1687750546, 1687750546),
(39, 'News', 'detail', 1, '{* set a canonical variable that can be used in the head section if process_whole_template is false in the config.php *}\n{if isset($entry->canonical)}\n  {* note this syntax ensures that the canonical variable is set into global scope *}\n  {assign var=\'canonical\' value=$entry->canonical scope=global}\n{/if}\n\n{if $entry->postdate}\n	<div id=\"NewsPostDetailDate\">\n		{$entry->postdate|cms_date_format}\n	</div>\n{/if}\n<h3 id=\"NewsPostDetailTitle\">{$entry->title|cms_escape:htmlall}</h3>\n\n<hr id=\"NewsPostDetailHorizRule\" />\n\n{if $entry->summary}\n	<div id=\"NewsPostDetailSummary\">\n		<strong>\n			{$entry->summary}\n		</strong>\n	</div>\n{/if}\n\n{if $entry->category}\n	<div id=\"NewsPostDetailCategory\">\n		{$category_label} {$entry->category}\n	</div>\n{/if}\n{if $entry->author}\n	<div id=\"NewsPostDetailAuthor\">\n		{$author_label} {$entry->author}\n	</div>\n{/if}\n\n<div id=\"NewsPostDetailContent\">\n        {* note, for security purposes we do not pass the content through smarty before displaying it.  This is incase your articles can come from untrusted sources. *}\n	{$entry->content}\n</div>\n\n{if $entry->extra}\n	<div id=\"NewsPostDetailExtra\">\n		{$extra_label} {$entry->extra}\n	</div>\n{/if}\n\n{if $return_url != \"\"}\n<div id=\"NewsPostDetailReturnLink\">{$return_url}{if $category_name != \'\'} - {$category_link}{/if}</div>\n{/if}\n\n{if isset($entry->fields)}\n  {foreach $entry->fields as $fieldname => $field}\n     <div class=\"NewsDetailField\">\n        {if $field->type == \'file\'}\n	  {* this template assumes that every file uploaded is an image of some sort, because News doesn\'t distinguish *}\n          {if isset($field->value) && $field->value}\n            <img src=\"{$entry->file_location}/{$field->value}\" alt=\"{$field->value}\"/>\n          {/if}\n        {elseif $field->type == \'linkedfile\'}\n          {* also assume it\'s an image... *}\n          {if !empty($field->value)}\n            <img src=\"{file_url file=$field->value}\" alt=\"{$field->value}\"/>\n          {/if}\n        {else}\n          {$field->name}:&nbsp;{$field->value}\n        {/if}\n     </div>\n  {/foreach}\n{/if}\n', NULL, 's:29:\"News::page_type_lang_callback\";', 's:30:\"News::reset_page_type_defaults\";', 0, 's:28:\"News::template_help_callback\";', NULL, NULL, 1687750546, 1687750546),
(40, 'News', 'form', 1, '{* original form template *}\n<h3>{$mod->Lang(\'title_fesubmit_form\')}</h3>\n\n{if isset($error)}\n  <div class=\"error>{$error}</div>\n{elseif isset($message)}\n  <div class=\"message>{$message}</div>\n{/if}\n\n{form_start category_id=$category_id}\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_title\">*{$mod->Lang(\'title\')}:</label></p>\n		<p class=\"col8\">\n			<input id=\"news_title\" type=\"text\" name=\"{$actionid}title\" value=\"{$title}\" size=\"30\" required/>\n                </p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_category\">{$mod->Lang(\'category\')}:</label></p>\n		<p class=\"col8\">\n			<select id=\"news_category\" name=\"{$actionid}input_category\">\n                        {html_options options=$categorylist selected=$category_id}\n			</select>\n                </p>\n	</div>\n\n{if !isset($hide_summary_field) or $hide_summary_field == 0}\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_summary\">{$mod->Lang(\'summary\')}:</label></p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'summary\'}\n			{cms_textarea enablewysiwyg=true id=news_summary name=$tmp value=$summary required=true}\n		</p>\n	</div>\n{/if}\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_content\">*{$mod->Lang(\'content\')}:</label></p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'content\'}\n			{cms_textarea enablewysiwyg=true id=news_content name=$tmp value=$content required=true}\n                </p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\"><label for=\"news_extra\">{$mod->Lang(\'extra\')}:</label></p>\n		<p class=\"col8\">\n			<input id=\"news_extra\" type=\"text\" name=\"{$actionid}extra\" value=\"{$extra}\" size=\"30\"/>\n                </p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\">{$mod->Lang(\'startdate\')}:</p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'startdate_\'}\n			{html_select_date prefix=$tmp time=$startdate end_year=\"+15\"}\n			{html_select_time prefix=$tmp time=$startdate}\n		</p>\n	</div>\n	<div class=\"row\">\n		<p class=\"col4\">{$mod->Lang(\'enddate\')}:</p>\n		<p class=\"col8\">\n			{$tmp=$actionid|cat:\'enddate_\'}\n			{html_select_date prefix=$tmp time=$enddate end_year=\"+15\"}\n			{html_select_time prefix=$tmp time=$enddate}\n		</p>\n	</div>\n	{if isset($customfields)}\n	   {foreach from=$customfields item=\'field\'}\n	      <div class=\"row\">\n		<p class=\"col4\"><label for=\"news_fld_{$field->id}\">{$field->name}:</label></p>\n		<p class=\"col8\">\n		{if $field->type == \'file\'}\n			<input id=\"news_fld_{$field->id}\" type=\"file\" name=\"{$actionid}news_customfield_{$field->id}\"/>\n		{elseif $field->type == \'checkbox\'}\n			<input id=\"news_fld_{$field->id}\" type=\"checkbox\" name=\"{$actionid}news_customfield_{$field->id}\" value=\"1\"/>\n		{elseif $field->type == \'textarea\'}\n			{$tmp1=\'news_fld_\'|cat:$field->id}\n			{capture assign=\'tmp2\'}{$actionid}news_customfield_{$field->id}{/capture}\n			{cms_textarea id=$tmp1 name=$tmp2 enablewysiwyg=true}\n		{elseif $field->type == \'textbox\'}\n			<input id=\"news_fld_{$field->id}\" type=\"text\"\" name=\"{$actionid}news_customfield_{$field->id}\" maxlength=\"{$field->max_length}\"/>\n                {/if}\n		</p>\n	      </div>\n	   {/foreach}\n	{/if}\n	<div class=\"row\">\n		<p class=\"col4\">&nbsp;</p>\n		<p class=\"col8\">\n			<input type=\"submit\" name=\"{$actionid}submit\" value=\"{$mod->Lang(\'submit\')}\"/>\n			<a href=\"{cms_selflink href=$page_alias}\">{$mod->Lang(\'prompt_redirecttocontent\')}</a>\n		</p>\n	</div>\n{form_end}\n', NULL, 's:29:\"News::page_type_lang_callback\";', 's:30:\"News::reset_page_type_defaults\";', 0, 's:28:\"News::template_help_callback\";', NULL, NULL, 1687750546, 1687750546),
(41, 'News', 'browsecat', 1, '{if $count > 0}\n<ul class=\"list1\">\n{foreach from=$cats item=node}\n{if $node.depth > $node.prevdepth}\n{repeat string=\"<ul>\" times=$node.depth-$node.prevdepth}\n{elseif $node.depth < $node.prevdepth}\n{repeat string=\"</li></ul>\" times=$node.prevdepth-$node.depth}\n</li>\n{elseif $node.index > 0}</li>\n{/if}\n<li class=\"newscategory\">\n{if $node.count > 0}\n	<a href=\"{$node.url}\">{$node.news_category_name}</a> ({$node.count}){else}<span>{$node.news_category_name} (0)</span>{/if}\n{/foreach}\n{repeat string=\"</li></ul>\" times=$node.depth-1}</li>\n</ul>\n{/if}', NULL, 's:29:\"News::page_type_lang_callback\";', 's:30:\"News::reset_page_type_defaults\";', 0, 's:28:\"News::template_help_callback\";', NULL, NULL, 1687750546, 1687750546);
