INSERT INTO `cms_module_templates` (`module_name`, `template_name`, `content`, `create_date`, `modified_date`) VALUES
('LISEGalleryslide', 'summary_default', '{if $items|@count > 0}\n\n	{if $pagecount > 1}\n	<!-- pagination -->\n	<p>\n		{if $pagenumber > 1}\n			{$firstpage}&nbsp;{$prevpage}&nbsp;\n		{/if}\n			{foreach from=$pagelinks item=page}\n				{$page->link}\n			{/foreach}\n		{if $pagenumber < $pagecount}\n			&nbsp;{$nextpage}&nbsp;{$lastpage}\n		{/if}\n	</p>\n	<!-- pagination //-->\n	{/if}\n	\n	<!-- items -->\n	{foreach from=$items item=item}\n	<!-- item -->\n	<div class=\"item\">\n	\n		<h2 class=\"item-title\">{$item->title}</h2>\n	\n		{if !empty($item->fielddefs)}\n		<!-- field definitions -->\n		<div class=\"item-properties\">\n			{foreach from=$item->fielddefs item=fielddef}\n	\n			{*\n				Categories were moved to field definitions.\n				If you need Categories, create new Field definition with alias \"category\"\n				and Categories will be available again.\n			*}\n	\n			{if $fielddef.type == \'Categories\' && ($fielddef.value != \'\')}\n	\n			{* use LISELoader plugin if you need Category information in default module action templates *}\n			{LISELoader item=\'category\' force_array=1 value=$fielddef.value assign=\'cats\'}\n	\n			<!-- categories -->\n			<div class=\"item-category\">\n				Category: {implode(\',\', $cats)}\n			</div>\n			<!-- categories //-->\n			{/if}\n	\n			{if $fielddef.value && $fielddef.type != \'Categories\'}\n				{if $fielddef.type == \'SelectFile\' || $fielddef.type == \'FileUpload\'}\n					{$fielddef.name}: <a href=\"{$fielddef->GetImagePath(true)}/{$fielddef.value}\">{$fielddef.value}</a><br />\n				{elseif $fielddef.type == \'SelectDateTime\'}\n					{$fielddef.name}: {$fielddef.value|cms_date_format}<br />\n				{else}\n					{$fielddef.name}: {$fielddef.value}<br />\n				{/if}\n			{/if}\n	\n			{/foreach}\n		</div>\n		<!-- field definitions //-->\n		{/if}\n	\n		<a href=\"{$item->url}\">more</a>\n	</div>\n	<!-- item //-->\n	{/foreach}\n	<!-- items //-->\n\n{/if}', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'summary_searchresults', '{if $items|@count > 0}\n\n{if $pagecount > 1}\n<!-- pagination -->\n<p>\n{if $pagenumber > 1}\n    {$firstpage}&nbsp;{$prevpage}\n{/if}\n{foreach from=$pagelinks item=page}\n    {$page->link}\n{/foreach}\n{if $pagenumber < $pagecount}\n    &nbsp;{$nextpage}&nbsp;{$lastpage}\n{/if}\n</p>\n<!-- pagination //-->\n{/if}\n\n{if !empty($actionparams.search)}\n    <h2>{$mod->ModLang(\'searchresultsfor\')} &quot;{$actionparams.search}&quot;</h2>\n{/if}\n\n<ul>\n{foreach from=$items item=item}\n    <li class=\"item searchresult\">\n        <a href=\"{$item->url}\">{$item->title}</a>\n    </li>\n{/foreach}\n</ul>\n\n{/if}', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'detail_default', '<!-- item -->\n<div class=\"item\">\n	<h2 class=\"item-title\">{$item->title|cms_escape}</h2>\n\n	{if !empty($item->fielddefs)}\n\n	<div class=\"item-properties\">\n		{foreach from=$item->fielddefs item=fielddef}\n\n		{*\n			Categories were moved to field definitions.\n			If you need Categories, create new Field definition with alias \"category\"\n			and Categories will be available again.\n		*}\n\n		{if $fielddef.type == \'Categories\' && ($fielddef.value != \'\')}\n\n			{* use LISELoader plugin if you need Category information in default module action templates *}\n			{LISELoader item=\'category\' force_array=1 value=$fielddef.value assign=\'cats\'}\n	\n			<!-- categories -->\n			<div class=\"item-category\">\n				Category: {implode(\',\', $cats)}\n			</div>\n			<!-- categories //-->\n			\n		{/if}\n\n		{if $fielddef.value && $fielddef.type != \'Categories\'}\n			{if $fielddef.type == \'SelectFile\' || $fielddef.type == \'FileUpload\'}\n				{$fielddef.name}: <a href=\"{$fielddef->GetImagePath(true)}/{$fielddef.value}\">{$fielddef.value}</a><br />\n		{elseif $fielddef.type == \'SelectDateTime\'}\n					{$fielddef.name}: {$fielddef.value|cms_date_format}<br />\n		{else}\n			{$fielddef.name}: {$fielddef.value}<br />\n			{/if}\n		{/if}\n\n		{/foreach}\n	</div>\n\n	{/if}\n	\n	<a href=\"{$return_url}\" class=\"return-link\">return</a>\n	{* or use {$return_link} to create link tag *}\n	\n</div>\n<!-- item //-->', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'search_default', '<div id=\"{$modulealias}_search\">\n	{$formstart}\n		<label for=\"{$modulealias}searchinput\">{$mod->ModLang(\'searchfor\')}:</label>&nbsp;\n		<input type=\"text\" id=\"{$modulealias}searchinput\" name=\"{$actionid}search\" size=\"20\" maxlength=\"50\" value=\"\" />\n		<input class=\"search-button\" name=\"submit\" value=\"{$mod->ModLang(\'search\')}\" type=\"submit\" />\n	{$formend}\n</div>', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'search_filter', '<div id=\"{$modulealias}_filter\">\n\n	<h3>{$filterprompt}</h3>\n\n	{$formstart}\n\n		{foreach from=$fielddefs item=fielddef}\n		<div class=\"form-row\">\n			\n		{if $fielddef.type != \'Categories\'}\n			<label for=\"filter_{$fielddef->alias}\">{$fielddef->name}</label>\n			\n			{if $fielddef.type == \'Checkbox\'}\n				<input type=\"checkbox\" name=\"{$actionid}search_{$fielddef->alias}\" id=\"filter_{$fielddef->alias}\" value=\"{$fielddef->value}\" />\n			{else}\n			\n			<select name=\"{$actionid}search_{$fielddef->alias}\" id=\"filter_{$fielddef->alias}\">\n				<option value=\'\'>{$mod->ModLang(\'all\')}</option>\n				{foreach from=$fielddef->values item=value}\n				<option>{$value}</option>\n				{/foreach}\n			</select>\n			{/if}\n			\n		{/if}\n			\n		</div>\n		{/foreach}\n	\n		<input class=\"search-button\" name=\"submit\" value=\"{$mod->ModLang(\'search\')}\" type=\"submit\" />\n\n	{$formend}\n\n</div>', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'search_multiselect', '<div id=\"{$modulealias}_filter\">\n\n	<h3>{$filterprompt}</h3>\n\n	{$formstart}\n\n		{foreach from=$fielddefs item=fielddef}\n		<div class=\"filter form-row\">\n\n		{if $fielddef.type != \'Categories\'}\n		\n			<label>{$fielddef->name}</label><br />\n			{if $fielddef.type == \'Checkbox\'}\n				\n				<input type=\"checkbox\" name=\"{$actionid}search_{$fielddef->alias}\" id=\"filter_{$fielddef->alias}\" value=\"{$fielddef->value}\" />\n			{else}\n				\n				<select name=\"{$actionid}search_{$fielddef->alias}[]\" size=\"5\" multiple=\"multiple\">\n					{foreach from=$fielddef->values item=\'value\'}\n					<option value=\"{$value}\">{$value}</option>\n					{/foreach}\n				</select>\n			{/if}\n		{/if}\n		</div>\n		{/foreach}\n\n		<input class=\"search-button\" name=\"submit\" value=\"{$mod->ModLang(\'filter\')}\" type=\"submit\" />\n\n	{$formend}\n</div>', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'category_default', '<!-- categories -->\n<ul>\n{foreach from=$categories item=category}\n	<li class=\"category-{$category->alias}\">\n		<a class=\"category-name\" href=\"{$category->url}\">{$category->name} ({$category->items|count})</a>\n			{if !empty($category->description)}\n			<div class=\"category-description\">\n				{eval var=$category->description}\n			</div>\n			{/if}\n	</li>\n{/foreach}\n<ul>\n<!-- categories //-->', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'category_hierarchy', '<!-- categories hierarchy -->\n<ul class=\"categories\">\n{foreach from=$categories item=category}\n\n{if $category->depth > $category->prevdepth}\n	{repeat string=\"<ul>\" times=$category->depth-$category->prevdepth}\n{elseif $category->depth < $category->prevdepth}\n	{repeat string=\"</li></ul>\" times=$category->prevdepth-$category->depth}\n	</li>\n{elseif $category->index > 0}\n	</li>\n{/if}\n\n{if $category->current}\n<li class=\"category-{$category->alias} current{if $category->parent == true || $category->children|@count > 0} parent{/if}\">\n	<a href=\"{$category->url}\">{$category->menutext}</a>\n{else}\n<li class=\"category-{$category->alias}{if $category->parent == true || $category->children|@count > 0} parent{/if}\">\n	<a href=\"{$category->url}\">{$category->menutext}</a>\n{/if}\n\n{/foreach}\n\n	{repeat string=\"</li></ul>\" times=$category->depth-1}\n	</li>\n</ul>\n<!-- categories hierarchy //-->', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'archive_default', '{if $archives|@count > 0}\n\n    <!-- archives -->\n    <ul>\n        {foreach from=$archives item=\'archive\'}\n            <li><a href=\"{$archive->url}\">{$archive->month}/{$archive->year} ({$archive->count})</a> [{$archive->timestamp|cms_date_format:\'%B %Y\'}]</li>    \n        {/foreach}\n    </ul>\n    <!-- archives //-->\n    \n{/if}', '2022-03-23 16:27:44', '2022-03-23 16:27:44'),
('LISEGalleryslide', 'summary_summary_slick', '{include file=\'LISEGalleryslide_summary_slick.tpl\'}', '2022-05-20 11:31:01', '2022-05-20 11:31:01'),
('LISEGalleryslide', 'summary_summary_default', '{include file=\'LISEGalleryslide_summary_default.tpl\'}', '2022-03-24 16:27:37', '2022-03-24 16:27:37'),
('LISEGalleryslide', 'summary_summary_pageheader', '{include file=\'LISEGalleryslide_summary_pageheader.tpl\'}', '2022-03-26 16:36:55', '2022-03-26 16:36:55'),
('LISEGalleryslide', 'summary_summary_page_header', '{include file=\'LISEGalleryslide_summary_page_header.tpl\'}\r\n', '2022-03-26 16:06:22', '2022-03-26 16:06:22'),
('LISEGalleryslide', 'summary_summary_homepage_hero_slick', '{include file=\'LISEGalleryslide_summary_homepage_hero_slick.tpl\'}', '2022-05-18 15:08:56', '2022-05-18 15:08:56'),
('LISEGalleryslide', 'summary_summary_slick_5wide', '{include file=\'LISEGalleryslide_summary_slick_5wide.tpl\'}', '2022-03-26 16:35:40', '2022-03-26 16:35:40'),
('LISEPolicies', 'summary_searchresults', '{if $items|@count > 0}\n\n{if $pagecount > 1}\n<!-- pagination -->\n<p>\n{if $pagenumber > 1}\n    {$firstpage}&nbsp;{$prevpage}\n{/if}\n{foreach from=$pagelinks item=page}\n    {$page->link}\n{/foreach}\n{if $pagenumber < $pagecount}\n    &nbsp;{$nextpage}&nbsp;{$lastpage}\n{/if}\n</p>\n<!-- pagination //-->\n{/if}\n\n{if !empty($actionparams.search)}\n    <h2>{$mod->ModLang(\'searchresultsfor\')} &quot;{$actionparams.search}&quot;</h2>\n{/if}\n\n<ul>\n{foreach from=$items item=item}\n    <li class=\"item searchresult\">\n        <a href=\"{$item->url}\">{$item->title}</a>\n    </li>\n{/foreach}\n</ul>\n\n{/if}', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISEPolicies', 'detail_default', '<!-- item -->\n<div class=\"item\">\n	<h2 class=\"item-title\">{$item->title|cms_escape}</h2>\n\n	{if !empty($item->fielddefs)}\n\n	<div class=\"item-properties\">\n		{foreach from=$item->fielddefs item=fielddef}\n\n		{*\n			Categories were moved to field definitions.\n			If you need Categories, create new Field definition with alias \"category\"\n			and Categories will be available again.\n		*}\n\n		{if $fielddef.type == \'Categories\' && ($fielddef.value != \'\')}\n\n			{* use LISELoader plugin if you need Category information in default module action templates *}\n			{LISELoader item=\'category\' force_array=1 value=$fielddef.value assign=\'cats\'}\n	\n			<!-- categories -->\n			<div class=\"item-category\">\n				Category: {implode(\',\', $cats)}\n			</div>\n			<!-- categories //-->\n			\n		{/if}\n\n		{if $fielddef.value && $fielddef.type != \'Categories\'}\n			{if $fielddef.type == \'SelectFile\' || $fielddef.type == \'FileUpload\'}\n				{$fielddef.name}: <a href=\"{$fielddef->GetImagePath(true)}/{$fielddef.value}\">{$fielddef.value}</a><br />\n		{elseif $fielddef.type == \'SelectDateTime\'}\n					{$fielddef.name}: {$fielddef.value|cms_date_format}<br />\n		{else}\n			{$fielddef.name}: {$fielddef.value}<br />\n			{/if}\n		{/if}\n\n		{/foreach}\n	</div>\n\n	{/if}\n	\n	<a href=\"{$return_url}\" class=\"return-link\">return</a>\n	{* or use {$return_link} to create link tag *}\n	\n</div>\n<!-- item //-->', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISEPolicies', 'search_default', '<div id=\"{$modulealias}_search\">\n	{$formstart}\n		<label for=\"{$modulealias}searchinput\">{$mod->ModLang(\'searchfor\')}:</label>&nbsp;\n		<input type=\"text\" id=\"{$modulealias}searchinput\" name=\"{$actionid}search\" size=\"20\" maxlength=\"50\" value=\"\" />\n		<input class=\"search-button\" name=\"submit\" value=\"{$mod->ModLang(\'search\')}\" type=\"submit\" />\n	{$formend}\n</div>', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISEPolicies', 'search_filter', '<div id=\"{$modulealias}_filter\">\n\n	<h3>{$filterprompt}</h3>\n\n	{$formstart}\n\n		{foreach from=$fielddefs item=fielddef}\n		<div class=\"form-row\">\n			\n		{if $fielddef.type != \'Categories\'}\n			<label for=\"filter_{$fielddef->alias}\">{$fielddef->name}</label>\n			\n			{if $fielddef.type == \'Checkbox\'}\n				<input type=\"checkbox\" name=\"{$actionid}search_{$fielddef->alias}\" id=\"filter_{$fielddef->alias}\" value=\"{$fielddef->value}\" />\n			{else}\n			\n			<select name=\"{$actionid}search_{$fielddef->alias}\" id=\"filter_{$fielddef->alias}\">\n				<option value=\'\'>{$mod->ModLang(\'all\')}</option>\n				{foreach from=$fielddef->values item=value}\n				<option>{$value}</option>\n				{/foreach}\n			</select>\n			{/if}\n			\n		{/if}\n			\n		</div>\n		{/foreach}\n	\n		<input class=\"search-button\" name=\"submit\" value=\"{$mod->ModLang(\'search\')}\" type=\"submit\" />\n\n	{$formend}\n\n</div>', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISEPolicies', 'search_multiselect', '<div id=\"{$modulealias}_filter\">\n\n	<h3>{$filterprompt}</h3>\n\n	{$formstart}\n\n		{foreach from=$fielddefs item=fielddef}\n		<div class=\"filter form-row\">\n\n		{if $fielddef.type != \'Categories\'}\n		\n			<label>{$fielddef->name}</label><br />\n			{if $fielddef.type == \'Checkbox\'}\n				\n				<input type=\"checkbox\" name=\"{$actionid}search_{$fielddef->alias}\" id=\"filter_{$fielddef->alias}\" value=\"{$fielddef->value}\" />\n			{else}\n				\n				<select name=\"{$actionid}search_{$fielddef->alias}[]\" size=\"5\" multiple=\"multiple\">\n					{foreach from=$fielddef->values item=\'value\'}\n					<option value=\"{$value}\">{$value}</option>\n					{/foreach}\n				</select>\n			{/if}\n		{/if}\n		</div>\n		{/foreach}\n\n		<input class=\"search-button\" name=\"submit\" value=\"{$mod->ModLang(\'filter\')}\" type=\"submit\" />\n\n	{$formend}\n</div>', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISEPolicies', 'category_default', '<!-- categories -->\n<ul>\n{foreach from=$categories item=category}\n	<li class=\"category-{$category->alias}\">\n		<a class=\"category-name\" href=\"{$category->url}\">{$category->name} ({$category->items|count})</a>\n			{if !empty($category->description)}\n			<div class=\"category-description\">\n				{eval var=$category->description}\n			</div>\n			{/if}\n	</li>\n{/foreach}\n<ul>\n<!-- categories //-->', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISEPolicies', 'category_hierarchy', '<!-- categories hierarchy -->\n<ul class=\"categories\">\n{foreach from=$categories item=category}\n\n{if $category->depth > $category->prevdepth}\n	{repeat string=\"<ul>\" times=$category->depth-$category->prevdepth}\n{elseif $category->depth < $category->prevdepth}\n	{repeat string=\"</li></ul>\" times=$category->prevdepth-$category->depth}\n	</li>\n{elseif $category->index > 0}\n	</li>\n{/if}\n\n{if $category->current}\n<li class=\"category-{$category->alias} current{if $category->parent == true || $category->children|@count > 0} parent{/if}\">\n	<a href=\"{$category->url}\">{$category->menutext}</a>\n{else}\n<li class=\"category-{$category->alias}{if $category->parent == true || $category->children|@count > 0} parent{/if}\">\n	<a href=\"{$category->url}\">{$category->menutext}</a>\n{/if}\n\n{/foreach}\n\n	{repeat string=\"</li></ul>\" times=$category->depth-1}\n	</li>\n</ul>\n<!-- categories hierarchy //-->', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISEPolicies', 'archive_default', '{if $archives|@count > 0}\n\n    <!-- archives -->\n    <ul>\n        {foreach from=$archives item=\'archive\'}\n            <li><a href=\"{$archive->url}\">{$archive->month}/{$archive->year} ({$archive->count})</a> [{$archive->timestamp|cms_date_format:\'%B %Y\'}]</li>    \n        {/foreach}\n    </ul>\n    <!-- archives //-->\n    \n{/if}', '2022-08-02 14:16:11', '2022-08-02 14:16:11'),
('LISENewsletters', 'archive_default', '{if $archives|@count > 0}\n\n    <!-- archives -->\n    <ul>\n        {foreach from=$archives item=\'archive\'}\n            <li><a href=\"{$archive->url}\">{$archive->month}/{$archive->year} ({$archive->count})</a> [{$archive->timestamp|cms_date_format:\'%B %Y\'}]</li>    \n        {/foreach}\n    </ul>\n    <!-- archives //-->\n    \n{/if}', '2024-01-30 17:57:59', '2024-01-30 17:57:59'),
('LISENewsletters', 'category_default', '<!-- categories -->\n<ul>\n{foreach from=$categories item=category}\n	<li class=\"category-{$category->alias}\">\n		<a class=\"category-name\" href=\"{$category->url}\">{$category->name} ({$category->items|count})</a>\n			{if !empty($category->description)}\n			<div class=\"category-description\">\n				{eval var=$category->description}\n			</div>\n			{/if}\n	</li>\n{/foreach}\n<ul>\n<!-- categories //-->', '2024-01-30 17:57:59', '2024-01-30 17:57:59'),
