('metadata', '{strip}{my_get var=alt_title assign=alt_title}\r\n{my_get var=\'description\' assign=description}\r\n{my_get var=\'metadescription\' assign=metadescription}\r\n{my_get var=canonical assign=canonical}\r\n{my_get var=\'main_image\' assign=main_image}\r\n{my_get var=\'blog_image\' assign=blog_image}\r\n{my_get var=\'pageimage\' assign=pageimage}\r\n{my_set var=\'pageimage\' assign=pageimage}\r\n{my_get var=\'blog_url\' assign=blog_url}\r\n{my_get var=\'blog_description\' assign=blog_description}\r\n{my_get var=\'case_description\' assign=case_description}\r\n{my_get var=\'case_image\' assign=case_image}\r\n{my_get var=\'case_url\' assign=case_url}\r\n{/strip}<meta charset=\"utf-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n<title>{if isset($alt_title)}{$alt_title}{elseif isset($blogtitle)}{$blogtitle}{else}{title}{/if} - {sitename}</title>\r\n<link rel=\"apple-touch-icon\" sizes=\"180x180\" href=\"{root_url}/uploads/gps/images/apple-touch-icon.png\">\r\n<link rel=\"icon\" type=\"image/png\" sizes=\"32x32\" href=\"{root_url}/uploads/gps/images/favicon-32x32.png\">\r\n<link rel=\"icon\" type=\"image/png\" sizes=\"16x16\" href=\"{root_url}/uploads/gps/images/favicon-16x16.png\">\r\n<link rel=\"manifest\" href=\"{root_url}/uploads/gps/images/site.webmanifest\">\r\n<meta name=\'robots\' content=\'index, follow\'>\r\n<meta name=\"revised\" content=\"{modified_date format=\"%a, %d %b %Y %H:%M:%S\"}\" />\r\n<meta name=\"original-source\" content=\"{if isset($blog_url)}{root_url}/{$blog_url}{elseif isset($case_url)}{root_url}/{$case_url}{else}{if isset($canonical)}{$canonical}{elseif isset($content_obj)}{$content_obj->GetURL()}{/if}{/if}\"/>\r\n<link rel=\'canonical\' href=\'{if isset($blog_url)}{root_url}/{$blog_url}{elseif isset($case_url)}{root_url}/{$case_url}{else}{if isset($canonical)}{$canonical}{elseif isset($content_obj)}{$content_obj->GetURL()}{/if}{/if}\'/>\r\n<meta property=\"og:url\" content=\"{if isset($blog_url)}{root_url}/{$blog_url}{elseif isset($case_url)}{root_url}/{$case_url}{else}{if isset($canonical)}{$canonical}{elseif isset($content_obj)}{$content_obj->GetURL()}{/if}{/if}\"/>\r\n<meta property=\"og:image\" content=\'{if ! empty($blog_image)}{root_url}/uploads/{$blog_image}{elseif !empty($pageimage)}{root_url}/uploads/{$pageimage}{else}https://ik.imagekit.io/webtactics/gloucester-pre-school/tr:h-1000,q-80,pr-true/uploads/images/Gallery/GPS-front.jpg{/if}\'/>\r\n<meta property=\"og:title\" content=\"{if isset($alt_title)}{$alt_title}{else}{title}{/if}\">\r\n<meta property=\'og:site_name\' content=\'{sitename}\'>\r\n<meta name=\"description\" content=\"{if ! empty($blog_description)}{$blog_description|strip_tags|truncate:\'250\'|strip}{else}{$main_content|strip_tags|truncate:\'250\'|strip}{/if}\">\r\n{strip}{cms_selflink dir=\"start\" rellink=1}\r\n{cms_selflink dir=\"prev\" rellink=1}\r\n{cms_selflink dir=\"next\" rellink=1}{/strip}\r\n{cms_stylesheet}\r\n{if ! empty($blog_description)}\r\n<script type=\"application/ld+json\">{\r\n\"@context\": \"https://schema.org\", \r\n\"@type\": \"BlogPosting\",\r\n\"headline\": \"{if isset($alt_title)}{$alt_title}{else}{title}{/if}\",\r\n\"image\": \"{root_url}/uploads/{$blog_image}\",\r\n\"genre\": \"search engine optimization\", \r\n\"keywords\": \"{search action=\'keywords\' count=\'8\'}\", \r\n\"publisher\": \"{sitename}\",\r\n\"url\": \"{if isset($blog_url)}{root_url}/{$blog_url}{elseif isset($case_url)}{root_url}/{$case_url}{else}{if isset($canonical)}{$canonical}{elseif isset($content_obj)}{$content_obj->GetURL()}{/if}{/if}\",\r\n\"datePublished\": \"{created_date format=\"%A %d-%b-%y %T %Z\"}\",\r\n\"dateCreated\": \" {created_date format=\"%A %d-%b-%y %T %Z\"}\",\r\n\"dateModified\": \"{modified_date format=\"%a, %d %b %Y %H:%M:%S\"}\",\r\n\"description\": \"{if ! empty($blog_description)}{$blog_description|strip_tags|truncate:\'70\'|strip}{else}{$main_content|strip_tags|truncate:\'70\'|strip}{/if}\",\r\n\"articleBody\": \"{$blog_description|strip_tags|truncate:\'2000\'|strip}\",\r\n}</script>\r\n{else}<script type=\"application/ld+json\">{\r\n\"@context\": \"http://schema.org\",\r\n\"@type\": \"WebSite\",\r\n\"name\": \"{if isset($alt_title)}{$alt_title}{elseif isset($blogtitle)}{$blogtitle}{else}{title}{/if} - {sitename}\",\r\n\"url\": \"{if isset($blog_url)}{root_url}/{$blog_url}{elseif isset($case_url)}{root_url}/{$case_url}{else}{if isset($canonical)}{$canonical}{elseif isset($content_obj)}{$content_obj->GetURL()}{/if}{/if}\",\r\n}</script>\r\n{/if}', NULL, NULL),
