INSERT INTO `cms_userplugins` (`userplugin_id`, `userplugin_name`, `code`, `description`, `create_date`, `modified_date`) VALUES
(1, 'user_agent', '//Code to show the users user agent information.\necho $_SERVER[\'HTTP_USER_AGENT\'];', 'Code to show the user\'s user agent information', '2022-01-17 03:43:35', '2022-01-17 03:43:35'),
(2, 'custom_copyright', '//set start to date your site was published\n$startCopyRight=\'2004\';\n\n// check if start year is this year\nif(date(\'Y\') == $startCopyRight){\n// it was, just print this year\n    echo $startCopyRight;\n}else{\n// it wasnt, print startyear and this year delimited with a dash\n    echo $startCopyRight.\'-\'. date(\'Y\');\n}', 'Code to output copyright information', '2022-01-17 03:43:35', '2022-01-17 03:43:35'),
(3, 'my_get', '$var = trim($params[\'var\']);\r\n$assign = trim($params[\'assign\']);\r\nif( $var ) {\r\n    $val = \\cms_utils::get_app_data(\'my_\'.$var);\r\n    if( $assign ) {\r\n       $smarty->assign($assign,$val);\r\n    }  else {\r\n       return $val;\r\n    }\r\n}', '', '2022-03-23 10:50:56', '2022-05-26 18:46:38'),
(4, 'my_set', '$var = trim($params[\'var\']);\r\n$val = $params[\'value\'];\r\nif( $var )  \\cms_utils::set_app_data(\'my_\'.$var,$val);', '', '2022-03-23 10:51:14', '2022-05-26 18:46:31'),
(5, 'pageurl', 'echo $_SERVER[\'REQUEST_URI\'];', '', '2022-03-23 10:51:33', '2022-05-26 18:46:07'),
(6, 'content_type', '$type = isset($params[\'type\']) ? $params[\'type\'] : \'text/html\';\r\ncmsms()->variables[\'content-type\'] = $type;', '', '2022-05-26 18:47:04', '2022-05-26 18:47:04');
